import{_ as i,o as a,c as e,ae as r}from"./chunks/framework.D0ZdyYnl.js";const b=JSON.parse('{"title":"世界观设定","description":"","frontmatter":{},"headers":[],"relativePath":"创世纪_世界观设定.md","filePath":"创世纪_世界观设定.md"}'),o={name:"创世纪_世界观设定.md"};function h(t,l,n,u,d,s){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="世界观设定" tabindex="-1">世界观设定 <a class="header-anchor" href="#世界观设定" aria-label="Permalink to &quot;世界观设定&quot;">​</a></h1><h2 id="前言声明" tabindex="-1">前言声明: <a class="header-anchor" href="#前言声明" aria-label="Permalink to &quot;前言声明:&quot;">​</a></h2><ul><li><strong>文档性质</strong>: 本文档为世界观底层架构与核心逻辑基石。</li><li><strong>核心目的</strong>: 确立世界运转规律、能量守恒机制（信息熵）、主要矛盾与各方势力底层物理刚需。</li><li><strong>后续工作</strong>: 本文档非最终总世界观设定集，表层文化、具体人物列传、城邦风貌等详尽血肉，需由文案与策划团队基于此底层逻辑进行后续构建与扩充。</li></ul><h2 id="世界观简要介绍" tabindex="-1">世界观简要介绍: <a class="header-anchor" href="#世界观简要介绍" aria-label="Permalink to &quot;世界观简要介绍:&quot;">​</a></h2><h4 id="时代背景" tabindex="-1">时代背景: <a class="header-anchor" href="#时代背景" aria-label="Permalink to &quot;时代背景:&quot;">​</a></h4><ul><li>世界处于类似一战至二战间的间歇期，魔导工业经历百年狂飙，列强处于高速发展与矛盾激化的百年未有之大变局中。</li></ul><h4 id="核心危机" tabindex="-1">核心危机: <a class="header-anchor" href="#核心危机" aria-label="Permalink to &quot;核心危机:&quot;">​</a></h4><ul><li>维持世界运转的信息熵在魔导工业的粗暴做功下持续流失至虚境。世界面临不可逆的“枯竭”与“概念剥落”危机，末日倒计时已经开启。（环境危机和人的异化）</li></ul><h4 id="世界规律" tabindex="-1">世界规律: <a class="header-anchor" href="#世界规律" aria-label="Permalink to &quot;世界规律:&quot;">​</a></h4><ul><li>遵循绝对的“等价交换”。任何魔法与能量的获取均需支付代价，表现为对高维有序信息的破坏和对现实世界的污染排放。</li><li>世界处于几万次轮回之中，“命定之人”试图在当前轮回耗尽信息熵引发“大重置”，将世界坍缩为绝对稳定的“奇点”。</li></ul><h4 id="社会状态" tabindex="-1">社会状态: <a class="header-anchor" href="#社会状态" aria-label="Permalink to &quot;社会状态:&quot;">​</a></h4><ul><li>列强为争夺不可再生能源（深海原晶、遗迹技术）进行残酷博弈。</li><li>工业排污将一阶废热与二阶精神毒素排入荒野与底层平民区，导致底层劳工异化为“无面者”，形成特有的荒野奇观灾厄生态。</li></ul><h4 id="叙事主轴" tabindex="-1">叙事主轴: <a class="header-anchor" href="#叙事主轴" aria-label="Permalink to &quot;叙事主轴:&quot;">​</a></h4><ul><li>“旅人”（玩家）作为唯一能产出“可能性之花”的高维变数降临。</li><li>旅人穿梭于处于历史叠加态的“乱序区”中，在各方势力的夹缝中探寻自身记忆，其对既定历史的干涉将直接透支底层算力，改变世界走向奇点的既定剧本。</li></ul><h2 id="一、核心设定" tabindex="-1">一、核心设定: <a class="header-anchor" href="#一、核心设定" aria-label="Permalink to &quot;一、核心设定:&quot;">​</a></h2><ul><li><ol><li>美术基调： 在现实主义底色之上，以魔导动力与蒸汽朋克元素（微量）作为点缀。整体剧情气质参考《钢之炼金术师》（借用其等价交换的残酷世界运行法则与工业革命时期的社会阵痛）与《谭雅战记》（参考其残酷的战壕硝烟氛围与理性至上的国家利益博弈）。</li></ol></li><li>视觉包装：视觉表现上则偏向《明日方舟》式的现代工业风。</li><li><ol start="2"><li>世界核心法则： 等价交换，任何魔法行为都无法凭空创造，其代价以信息熵的形式体现。</li></ol></li></ul><h3 id="法律与社会共识底线" tabindex="-1">法律与社会共识底线 <a class="header-anchor" href="#法律与社会共识底线" aria-label="Permalink to &quot;法律与社会共识底线&quot;">​</a></h3><ul><li>普世人权公约：当前世界处于现代文明阶段，各国普遍签署并承认《基本人权公约》。底层劳工虽然工作环境恶劣，但并非奴隶。列强国家机器维持着基础的社会福利与医疗保障，国家并非要所有人都死的极端派，其核心执政基础之一就是保住本国人民的生存空间。</li><li>异化的非故意性：底层平民转化为无面者，被定性为长期从事高危劳动后不可避免的“慢性职业病”，而非国家或资本故意将其“往死里用”的物理消耗机制。国家层面试图通过技术手段延缓这一过程以维持劳动力池。</li><li>人形权利：基于《人权保障公约》，具备完整自我认知的中高阶自律人形在法理上拥有基本人权，不受无底线的强制劳役或随意报废。</li></ul><h3 id="当前世界状况" tabindex="-1">当前世界状况 <a class="header-anchor" href="#当前世界状况" aria-label="Permalink to &quot;当前世界状况&quot;">​</a></h3><ul><li>时代背景：故事发生在对应现实世界第一次世界大战与第二次世界大战之间的间歇期，魔导全面现代化和普世化经历了一个漫长的过程，时间跨度长达百年（类似现实世界的工业发展时间）。</li><li>社会状态：列强处于高速发展期，技术爆炸引发剧烈的社会动荡，是一个矛盾激化、变局丛生的大争之世。百年未有之大变局</li></ul><h3 id="核心矛盾与主要矛盾" tabindex="-1">核心矛盾与主要矛盾 <a class="header-anchor" href="#核心矛盾与主要矛盾" aria-label="Permalink to &quot;核心矛盾与主要矛盾&quot;">​</a></h3><h3 id="主要矛盾" tabindex="-1">主要矛盾 <a class="header-anchor" href="#主要矛盾" aria-label="Permalink to &quot;主要矛盾&quot;">​</a></h3><ul><li>发展与毁灭的矛盾（世界规律）：世界因信息熵持续流失而面临不可逆的枯竭危机（末日倒计时）。</li><li>明确区分当期能源收支与信息熵稳态收支：魔晶的总产出大于消耗仅代表现世能源未断供，社会表面繁荣；而信息熵的亏空指向的是有序信息的净流失（魔晶破壳后深层有序信息跌落虚境，无法回收），这构成了深层的枯竭危机。虚境作为一个高维空间，其初始状态在这一轮回被命定之人故意设定为“99%满载的高压状态”以加速奇点结局。虽然战后人口在增加，但魔导工业的消耗呈“指数级”飙升。长生种和神明在古代的魔法消耗是精确剥离信息，产生的废热相对平缓；而人类魔导工业对魔晶的物理碾碎，不仅产生无序废热，这种粗暴做功还产生了一种特殊的“低维高频物理震荡”。这种工业震荡波排入虚境后，搅动了虚境底层几万次轮回积攒的古老死寂废料，使其沸腾膨胀，瞬间顶破了现实世界的概念外壳。人口的“线性增长”已经远远无法填补工业狂飙带来的信息熵亏空。重置每次轮回的信息熵会越来越趋于稳态，集中在魔晶中，逐渐枯竭。而列强为了自救与争霸，肆意发展魔导工业与极端计划，反而加速了信息稳态的崩溃与世界的毁灭。掉熵的本质是现实世界的信息来到了虚境，现实发生的“概念剥落”灾难，体现的正是虚境和现实逐渐接轨的过程。信息熵遵循永恒循环模型，既不能被创造也不能被消灭，只能在现实-虚境-奇点之间循环。大重置是虚境信息熵满载引发的大爆炸，奇点结局是将其极度压缩的过程。</li><li>宿命与破局的矛盾（叙事主轴）：“命定之人”出于对历史代价的恐惧选择饮鸩止渴，试图通过“真实历史之花”维持世界逐渐走向永恒这个剧本的现状，而不是维持这个世界的现状。她的最终目的是在世界不断缩小，最终坍缩成一个极小但绝对稳定的“奇点”时，达成永恒。目前魔晶广泛分布以及列强的疯狂开采与消耗，本身就是她计划中预料的一部分，这一轮回即将走向枯竭和重启。新轮回魔晶的“单位能量密度”在极度飙升，这也是为什么最终会形成奇点的原因。而“玩家（旅人）”作为变数执意探寻“可能性之花”，试图在乱序区中微调历史，彻底逆转世界衰亡的既定结局。</li></ul><h3 id="具体-次要矛盾" tabindex="-1">具体/次要矛盾 <a class="header-anchor" href="#具体-次要矛盾" aria-label="Permalink to &quot;具体/次要矛盾&quot;">​</a></h3><ul><li>阶级矛盾：掌握着土地资源与古代魔法“高端知识垄断”的旧贵族，与掌握着工厂和魔晶资源、要求获得对应政治权力的工业新贵族之间的死锁。</li><li>派系与路线矛盾：贵族化的传统魔法（依靠神赐属性与血脉传承垄断）与学院派的新兴魔法（普及化、系统化的魔导机械术式）之间的尖锐对立。</li><li>国家与地缘矛盾：处于“耻辱战役”战后间歇期的大争之世，列强在飞速发展中为了抢夺不可再生能源（魔晶）、深层技术以及国际话语权而产生的剧烈冲突。参考现实石油争夺逻辑，魔晶矿脉成为国家命脉与战争导火索。</li><li>种族矛盾：在历史沿革与工业化进程中，曾垄断魔法的长生种（天使/精灵）在“概念解析”和“人口消耗”被人类拖垮，最终双方达成基于互相毁灭保证的妥协，文化与民族逐渐交融。</li><li>人神信仰矛盾：科学的启蒙使人类逐渐解构世界法则，导致旧神明的力量与统治被削弱；同时人类出于欲望塑造出残酷的“人造神明”（如钢源神），反向造成了人性的异化与严重的信仰污染。</li></ul><h3 id="核心名词-各类名词索引-必看" tabindex="-1">核心名词（各类名词索引，必看） <a class="header-anchor" href="#核心名词-各类名词索引-必看" aria-label="Permalink to &quot;核心名词（各类名词索引，必看）&quot;">​</a></h3><ul><li><ol><li>歧路： 大争之世，世界处于命运的分叉路口。历史的稳定性因“信息熵污染”而动摇，时间本身也走到了分叉点。</li></ol></li></ul><h3 id="核心概念" tabindex="-1">核心概念: <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念:&quot;">​</a></h3><ul><li><strong>信息熵</strong>: 魔法代价的体现，分无序废热与有序信息，流失会导致世界枯竭。</li><li><strong>等价交换</strong>: 世界核心法则，任何魔法行为必须支付代价。</li><li><strong>乱序区</strong>: 信息熵过载导致的区域，内部历史和潜意识呈叠加态。</li><li><strong>预兆点</strong>: 乱序区形成前，虚境吐出的无序信息残渣导致的局部概念扭曲。</li><li><strong>信息虚境</strong>: 高维空间，存放被消耗的有序历史信息和无序废热。</li><li><strong>虚境溃疡</strong>: 虚境容量超载时向现实世界喷发信息残渣的现象。</li><li><strong>概念剥落</strong>: 虚境与现实接轨导致现实基础概念随机消失。</li><li><strong>奇点</strong>: 命定之人期望的世界最终坍缩成的绝对稳定状态。</li><li><strong>大重置</strong>: 信息熵彻底枯竭时重启世界的逆熵过程。</li><li><strong>认知降熵</strong>: 智慧生物通过观测解析未知，将无序转化为微量有序认知的过程。</li></ul><h3 id="核心资源" tabindex="-1">核心资源: <a class="header-anchor" href="#核心资源" aria-label="Permalink to &quot;核心资源:&quot;">​</a></h3><ul><li><strong>魔晶</strong>: 天然高纯度固态信息存储介质，不可再生工业血液。</li><li><strong>深海原晶</strong>: 深海极端环境下的高能量密度变异原晶。</li><li><strong>残渣</strong>: 魔晶使用后完全无序化的废料。</li><li><strong>虚晶</strong>: 二阶污染源，一阶污染凝结产物，底层廉价能源。</li><li><strong>极品变异虚晶</strong>: 奇观打捞虚境高维残片孕育出的纯净核心，真自律人形材料。</li><li><strong>伪魔晶</strong>: 经贸会转化虚晶产生的极度稳定平替能源，伴生三阶污染。</li><li><strong>熵之种</strong>: 熵序者坍缩乱序区的产物，高纯度信息结晶，战略资源。</li><li><strong>真实历史之花</strong>: 完美储存有序信息，填补剧本主干道，化作新魔晶矿脉。</li><li><strong>可能性之花</strong>: 玩家越界干涉产出，透支底层算力，成为新世界基石。</li><li><strong>空白之花</strong>: 玩家记忆抵押物，维持空天武器运转的高维钥匙。</li><li><strong>渊息石</strong>: 乱序区坍缩残渣，能散发辐射抵御三阶污染，极度稀缺。</li><li><strong>先祖结晶</strong>: 长生种祖地保留的古代纯净高维概念灵魂结晶。</li><li><strong>抑制剂</strong>: 含真实历史粉末的药剂，唤醒免疫系统抵抗认知重写。</li></ul><h3 id="污染体系" tabindex="-1">污染体系: <a class="header-anchor" href="#污染体系" aria-label="Permalink to &quot;污染体系:&quot;">​</a></h3><ul><li><strong>一阶污染</strong>: 魔晶机械破坏产生的无序物理废热。</li><li><strong>二阶污染</strong>: 虚晶使用产生的精神认知污染，缓慢抹除自我。</li><li><strong>三阶污染</strong>: 伪魔晶转化产生的具穿透性、同化意识的极度高危污染。</li><li><strong>死寂走廊</strong>: 一战遗迹武器造成的时空重度紊乱废土。</li><li><strong>时间异常区</strong>: 遗迹武器充能后坐力导致的时间流速混乱或回溯区域。</li><li><strong>零阶时间奇点</strong>: 阿国首都时间锚点排出的带有绝对时间坍缩概念的极度高危废渣。</li></ul><h3 id="生物与异象" tabindex="-1">生物与异象: <a class="header-anchor" href="#生物与异象" aria-label="Permalink to &quot;生物与异象:&quot;">​</a></h3><ul><li><strong>无面者</strong>: 底层劳工受二阶污染长期侵蚀失去自我后的异化形态。</li><li><strong>奇观</strong>: 无面者本能建造的吸附污染的巨型钢铁尖塔（古代防御工事投影）。</li><li><strong>灾厄Boss</strong>: 大型奇观过载后由污染与高维残片催生出的强大实体怪物。</li></ul><h3 id="技术与造物" tabindex="-1">技术与造物: <a class="header-anchor" href="#技术与造物" aria-label="Permalink to &quot;技术与造物:&quot;">​</a></h3><ul><li><strong>概念隔离桩</strong>: 宜居区用于将污染打入深层虚境的传导基建。</li><li><strong>以太气动管网</strong>: 阿国利用时间锚点废热进行物资解压缩的独家物流技术。</li><li><strong>幽灵专列</strong>: 阿国在时间缝隙中行驶、用于排放零阶废渣的极密列车。</li><li><strong>识别码</strong>: 十三局植入熵序者体内的定位与状态监测装置。</li><li><strong>湿件</strong>: 许国被切除脑前叶的狂热信徒大脑，用作伪自律人形核心。</li><li><strong>自律人形</strong>: 填补劳动力缺口的机械造物（分低/中/伪/真四阶）。</li><li><strong>康斯坦丁之瞳</strong>: 国联掌握的能精准溯源排污特征码的战略级雷达。</li><li><strong>移动圣物盒</strong>: 许国提供局部信仰网络与物理偏导力场的战术基站。</li><li><strong>单向意识体虚像滤网</strong>: 经贸会利用渊息虫等技术伪装三阶污染的设施。</li><li><strong>上帝之杖</strong>: 合众国搭载三阶毒核的轨道概念级穿甲武器。</li></ul><h3 id="势力与组织" tabindex="-1">势力与组织: <a class="header-anchor" href="#势力与组织" aria-label="Permalink to &quot;势力与组织:&quot;">​</a></h3><ul><li><strong>国联 (国际联合)</strong>: 战后成立的中立协调组织，掌握空天武器与战略雷达。</li><li><strong>经贸会 (贸联会)</strong>: 垄断全球晶币定价与伪魔晶转化的跨国金融组织。</li><li><strong>十三局</strong>: 各国设立的专门管控熵序者、乱序区及污染的暴力监管机构。</li><li><strong>杀戮小队</strong>: 进入奇观内部进行纯物理排爆并回收极品虚晶的精锐武装。</li><li><strong>无国界之军</strong>: 驻扎高危区的PMC组织，充当国联的黑手套。</li></ul><h3 id="神明与特殊存在" tabindex="-1">神明与特殊存在: <a class="header-anchor" href="#神明与特殊存在" aria-label="Permalink to &quot;神明与特殊存在:&quot;">​</a></h3><ul><li><strong>命定之人</strong>: 轮回剧本的导演与掌控者，追求世界坍缩为奇点。</li><li><strong>旅人 (玩家)</strong>: 跨越维度降临的变数，能产出改变历史的可能性之花。</li><li><strong>旧神</strong>: 沉睡的规则概念锚点。</li><li><strong>钢源神</strong>: 许国通过洗脑信徒与工业造物催生的人造信仰聚合体。</li><li><strong>圣愚</strong>: 许国用于欺骗世界底层逻辑、充当钢源神剥壳后门的高维熵序者。</li></ul><h3 id="职业分类" tabindex="-1">职业分类: <a class="header-anchor" href="#职业分类" aria-label="Permalink to &quot;职业分类:&quot;">​</a></h3><ul><li><strong>熵序者</strong>: 对信息流有适格度，能进入乱序区核心干涉历史的人类。</li><li><strong>清道夫</strong>: 负责平民记忆锚定疗法与微小乱序区风控的基层维稳人员。</li><li><strong>处刑专员</strong>: 负责在现世追杀失控叛逃熵序者并用死域回收碎片的执法者。</li><li><strong>寻秘使</strong>: 负责侦察预兆点和微型乱序区的战术侦察兵。</li><li><strong>长生种</strong>: 天生操控信息熵的古老种族（如精灵/天使），寿命极长。</li></ul><h3 id="信息熵的循环与恢复机制" tabindex="-1">信息熵的循环与恢复机制 <a class="header-anchor" href="#信息熵的循环与恢复机制" aria-label="Permalink to &quot;信息熵的循环与恢复机制&quot;">​</a></h3><h3 id="a-认知降熵" tabindex="-1">A. 认知降熵 <a class="header-anchor" href="#a-认知降熵" aria-label="Permalink to &quot;A. 认知降熵&quot;">​</a></h3><p>智慧生物对未知事物的观测、解析、记录与知识传承，将无序现象转化为有序认知。（基于熵的质量差异理论：缝合剂是高度有序的负熵，而废热是完全无序的正熵。人类基础科学修补了核心漏洞但也产生最严重的废热）。</p><ul><li>纯粹观测界限：此过程仅限于建立理论模型和记录知识，不干涉现实物理状态。 此过程消除世界的不确定性，产生微量信息稳态，延缓世界枯竭。 认知降熵消耗的是人类的“生物能”或“精神力”。即人类通过消耗自身的寿命、脑力或群体潜意识的算力，强行将无序转化为有序。这也是为什么长生种（脑力强）在古代能维持世界运转的原因。 认知降熵必须建立在“个体保持清醒自我和未知探索欲”的基础上。一旦被强行圈养洗脑或变成无面者，就失去了产生“真实有序信息”的能力，只会变成无序废料。 阶级分化、基本人权与算力壁垒：在列强的资本主义工业逻辑下，维持“未知探索欲和清醒自我”的特权属于宜居区的居民。国家在宜居区推行全民强制教育、维持基本福利和人权保障，这批庞大的中产和平民人口构成了维持世界概念不崩塌的“认知降熵压舱石”。平民大量使用魔导工业产生的“物理污染废热”虽然庞大，但与认知降熵产生的“高维概念缝合剂”在质量上存在不可跨越的维度壁垒。国家忍受巨大的物理排污压力去保障平民生活，是因为只有具备自由意志的活人产生的概念缝合剂，才能修补底层逻辑。普通市民对“世界濒临毁灭、自身是算力电池”这一真相完全不知情，他们只过着正常的现代化生活。相关真相与“认知降熵”的深层知识，被国家高层严格封锁，仅由专门的科研人员进行绝密研究。国家推行的强制教育与基础福利，本质上是一种受控的未知释放（如鼓励基础科学探索、艺术创作），使市民在不知情的前提下仍持续产出微观有序信息，构成了合理的降熵动机闭环。</li><li>虚境扩张与现实修复：认知降熵确实能产生极微量的“真实有序信息”，这部分信息被用来“缝补”现实世界的物理法则漏洞，现实会因此缓慢修复。但在缝补过程中产生的“废热（无序熵）”被转移到了虚境。虚境在吸收这些废热后会超载，并在超载中逐渐缓慢地扩张。虚境存在分层结构，概念隔离桩的真正作用是将污染从容量小的浅层虚境打入容量极大的深层虚境。深层虚境扩散满溢需要千年，列强为解决当期危机而选择这种推迟反噬的治理模式。这种扩张现象虽然延缓了现实的立刻崩溃，但本质上加重了世界整体的负担，加速了虚境最终的反噬。</li><li>世界枯竭的表现包括：整段历史被抹除，概念消失被更换为新的名字等。</li></ul><h3 id="b-乱序区坍缩" tabindex="-1">B. 乱序区坍缩 <a class="header-anchor" href="#b-乱序区坍缩" aria-label="Permalink to &quot;B. 乱序区坍缩&quot;">​</a></h3><p>乱序区内存在大量未确定的历史可能性，处于高熵叠加态。所有乱序区都是历史和潜意识叠加态的。 旅人进入乱序区，参与事件并确立唯一历史进程，消除该区域的不确定性。 乱序区坍缩为确定历史，释放高纯度信息产物（如熵之种、历史之花）。 此转化过程为有损转化，产出的能量远小于引发异常所消耗能量。本质上仍然是在减缓亏损，而不是恢复。</p><ul><li>坍缩的物理表现与历史固化：坍缩指乱序区消失，该区域恢复在产生乱序区前的原状。但是，恢复的原状会因为熵序者、其他人员或玩家在乱序区中的行为产生物理层面的永久变化。例如，如果一段历史被完美填补，乱序区消失后，其内部的核心物理建筑或地形会直接镶嵌到现实的荒野中。</li><li>记忆瞬间填充与认知覆盖机制：坍缩的代价是基于“信息相关性”。当乱序区产出对应产物并填补历史空洞时，相关人群的大脑认知以及相关的物理记录会被“强制合理化覆盖”。大众的认知会自然而然地平滑过渡，认为“这个村庄一直都在那里”，相关的文字或照片也会被重构成符合新历史逻辑的内容。</li><li>废热物理填充与渐变磨损生成（三维物理缝补机制）：世界法则在进行认知覆盖时产生的“无序废热”，部分被底层规则直接用来在三维空间中进行物理缝补。当核心建筑镶嵌进现实荒野时，废热会在其边缘强制生成符合宏观逻辑的“物理过渡带”。它会强行扭曲地貌，生成生锈的连接管道断面、制造符合年代感的车辙磨损痕迹、催生特定年份的苔藓。这种宏观物理层面的严重错位被粗暴但无缝地掩盖了。常规工程勘探无法看出破绽，阿国的高精尖仪器之所以能测出断层，是因为这种“物理催生”在微观晶体结构或同位素半衰期上，与自然演化的物质存在绝对的年代偏差。</li><li>覆盖范围与等级划分：认知覆盖的范围取决于坍缩事件的历史权重。只有涉及核心概念或国家命脉的“重大历史事件”坍缩时，才会引发全球范围的认知覆盖。平常小、微、中型乱序区的坍缩，其影响范围仅限于周边区域或特定相关人群，对全球的损害可忽略不计。</li><li>废热缓冲与物理异象：记忆重写会产生无序废热。世界底层规则将这股废热强制转化为物理层面的空间畸变，由荒野和底层承担。异象程度按等级划分：小微型事件坍缩仅导致周边荒野出现短暂的重力异常或微型预兆点；中型事件坍缩会导致附近的边缘乱序区面积扩大；重大历史事件坍缩则会引发全球范围的随机异象，如无面者奇观瞬间拔地而起，或形成新的重度污染沼泽。</li><li>距离失神效应：虽然认知平滑过渡，但距离乱序区坍缩中心越近的人，在历史覆盖的瞬间越会产生短暂的“失神效应”或眩晕感。</li><li>物理观测漏洞与微观缝隙：世界法则的重构覆盖存在“刷新率/分辨率”极限。在宏观层面（记忆、照片、报纸）能完美造假；但在微观层面（原子的衰变率、极高精度的光波干涉），重构会出现无法解释的断层缝隙。这造成了人脑记忆与高频监测仪器波形之间的悖论。基于此漏洞，衍生出了新的学科和职业。阿国高层正是通过这种极高精度仪器记录的断层确信世界被篡改，并依靠遗迹技术保留了部分未被篡改的底层公式作为“锚定真实”的特殊手段，该设定与技术对外国绝对保密。阿国高层本身并不绝对免疫认知覆盖，他们的记忆同样会被平滑修改。他们是通过保留的遗迹底层公式和物理常数缝隙确信现实被重构过，他们只能追逐碎片化的真实，知道世界被篡改却不知道真相究竟是什么。</li><li>遗迹公式的被动放行与宕机闪烁（认知覆盖冲突解决）：阿国首都的时间锚点（遗迹公式）其底层逻辑是镇压“无序的时间回溯与废热”。当命定之人引发全球认知覆盖时，这股力量是“绝对有序的高维补丁”。遗迹公式在底层判定中会将其视为“合法的系统更新”而直接放行。因此，阿国首都内平民的认知依然会被覆盖，并没有成为认知孤岛。然而，遗迹公式在放行高维补丁的瞬间，会因为数据流的摩擦产生一次“物理级的微小宕机（如全城电网闪烁0.1秒）”。阿国高层正是通过捕捉这种规律性的宕机闪烁，配合防篡改介质，才确信了世界被篡改的事实。</li><li>学术界认知：高精尖领域都知道这种物理断层的存在。它作为虚境科学的分支的一部分，作为常识和未解之谜存在于顶尖学术圈中。</li><li>记忆豁免与模糊违和感：长生种、具备高抗性的清道夫以及部分老熵序者，虽然依然会受到世界法则强制合理化重构的影响，其认知和纸质记录会被修改，但极高的精神抗性会让他们在记忆覆盖后产生持续且强烈的“模糊违和感”。这种违和感促使他们在看似合理的物理记录中寻找断层。在近代防篡改介质出现之前，古代长生种只能依靠这种集体违和感口耳相传，导致历史充满了神话与矛盾。</li></ul><h3 id="c-轮回重启机制与物理损耗" tabindex="-1">C. 轮回重启机制与物理损耗 <a class="header-anchor" href="#c-轮回重启机制与物理损耗" aria-label="Permalink to &quot;C. 轮回重启机制与物理损耗&quot;">​</a></h3><p>信息虚境作为命定之人的领域，其意象表现为一片由“空白之花”、“真实之花”以及“熵之种”构成的花海。命定之人在虚境中拥有概念神和管理级别的能力。 魔法消耗的信息熵并未真正消失，而是跌落并堆积在信息虚境中。</p><ul><li>虚境容量临界值与反噬机制：信息虚境存在容量上限。人类这一百多年的工业狂飙，虽然消耗是指数级上升，但在虚境的绝对总容积面前，物理排放量原本不足以迅速填满虚境。但由于虚境的初始状态在这一轮回被命定之人故意设定为“99%满载的高压状态”，且人类魔导工业对魔晶的物理碾碎不仅产生无序废热，还产生了一种特殊的“低维高频物理震荡”。这种工业震荡波排入虚境后，搅动了虚境底层几万次轮回积攒的古老死寂废料，使其沸腾膨胀，瞬间顶破了现实世界的概念外壳。当局部区域魔晶消耗过大导致虚境超载时，会发生“虚境溃疡”。现实世界会随机吐出上一个世界线的混乱概念或实体（如古代兵器坠落、局部重力异常）。超载的核心体现是“虚境越来越与现实相连”，两者的物理边界变得越来越模糊和薄弱。</li><li>信息分层沉淀机制：虚境溃疡吐出的仅仅是无法被虚境消化的“无序信息废热（一阶污染残渣）”。而命定之人真正积攒的，是被抽取的“有序历史信息（灵魂/概念）”。废热的溢出如同泄压阀，保护了核心有序信息的安全积攒。</li><li>概念剥落灾难：当虚境严重超载逼近临界值时，现实世界会发生基础“概念”的随机剥落（如某区域突然失去“重力”或“语言”的概念）。这种现象在历史上仅发生过几次，更多时候表现为信息的损失，被作为重大历史灾难记录在案，是列强高层察觉“末日倒计时”并采取极端自救计划的直接原因。概念剥落体现了虚境和现实的逐渐接轨。</li><li>大重置逆熵代价：当现实世界的信息熵彻底枯竭时，命定之人会引发大重置，以此来重启世界，开启下一次轮回。此逆熵过程的代价是献祭掉当前轮回的大部分的生命意识，只有少部分被选中者成为了下一个轮回的规则神，导致整个世界进一步固化，同时消耗掉命定之人自身的一部分本源（自我）。大重置时，命定之人不仅使用真实历史之花，还会动用一整个虚境的绝大部分能量，将这些庞大的能量和信息强行压缩、降维，转化为新轮回的魔晶底座。</li><li>本源消耗逻辑：命定之人的本源（自我）在几万次轮回中是逐渐消耗的，这并非指她的实力减弱，而是她作为独立个体的“自我认知”在不断磨损。目前她的自我已经接近枯竭，快要彻底消逝。这也是她急于在这一轮回达成“绝对稳定的奇点”永恒结局的根本原因。本源枯竭带来了具体的能力衰减，命定之人无法再进行全球尺度的精确微操，只能通过剧本惯性进行宏观引导。她在近几次轮回中开始出现剧本漏洞（如塔万汀大群岛破碎后无法完美修复），只能强行将其物理合理化，这正是她控制力下降的直接表现。 真实历史之花在引爆后会化作魔晶矿脉（此为命定之人大重置重启世界时的现象），并将完全储存的所有信息永远记录在其中，造成世界逐渐稳态。 可能性之花无法被虚境消化，会吸收魔晶，成为新世界基石，一个乱序，但是有无限未来可能的新世界。</li><li>轮回损耗与世界边界缩小：由于每次轮回的信息转化均为有损转化，且魔晶在每次轮回中都会将相关信息固化，导致世界的物理边界在不断缩小。曾经存在的大陆在后来轮回中直接消失，连概念都不复存在。内部的地核、地壳等也在发生变化。在深海或世界边缘，会不定时出现一堵“绝对虚无之墙”作为海上奇观。任何接触到墙的物质都会无声无息地消失，这是世界边界坍缩的直观物理显现。</li></ul><h3 id="世界深层危机与列强自救" tabindex="-1">世界深层危机与列强自救 <a class="header-anchor" href="#世界深层危机与列强自救" aria-label="Permalink to &quot;世界深层危机与列强自救&quot;">​</a></h3><p>魔导工业化的滥用，导致原本被神祇锚定的信息熵持续、不可逆地流失到“信息虚境”中。 列强高层并不知道世界轮回的真相，但察觉到了某种“末日倒计时”。</p><ul><li>倒计时的表象为：极端天气频发，列强开始大量无序开采魔晶，以及历史上发生过的几次重大“概念剥落”灾难。 为了应对这种危机，各国开始进行极端的自救计划，例如造神（如许国的钢源神）或寻找遗迹（如阿国挖掘遗迹武器）。每个国家在寻求破局的道路上都支付着对应的“代价”。</li></ul><h3 id="耻辱战役-的遗产" tabindex="-1">“耻辱战役”的遗产 <a class="header-anchor" href="#耻辱战役-的遗产" aria-label="Permalink to &quot;“耻辱战役”的遗产&quot;">​</a></h3><h3 id="事件描述" tabindex="-1">事件描述 <a class="header-anchor" href="#事件描述" aria-label="Permalink to &quot;事件描述&quot;">​</a></h3><p>大战末期，为扭转颓势，阿邦联的军事同盟不顾后果动用了禁忌级战略魔法，引发了不可逆的信息熵失控连锁反应。</p><h3 id="直接后果" tabindex="-1">直接后果 <a class="header-anchor" href="#直接后果" aria-label="Permalink to &quot;直接后果&quot;">​</a></h3><ul><li>人口锐减：造成三国适役人口80%的损失。</li><li>地理灾难：创造了横跨三国的“死寂走廊”。死寂走廊内部永远处于混乱的历史叠加态。走廊本身会周期性地向外“喷发”高浓度的乱序风暴，迫使周边国家必须维持高度的军事戒备。</li><li>战略动机：死寂走廊内部蕴含着丰富的失落技术与资源遗产。各国军队驻守在走廊边缘，表面上是防御乱序风暴，实际上是为了争夺这些能够颠覆世界格局的旧日遗产。死寂走廊本身被定性为极度高危地区，一般国家仅能派遣特种部队进入并探测外围，且走廊被几个主要国家环绕，其范围在法理上仍然属于各国的宣称领土，并未沦为完全的无主之地。</li><li>污染蔓延：产生了大范围的陆陆污染带，以及阻断跨海航行的全球洋流熵污染。</li><li>战争终结：直接迫使各国签署停战协议，第一次世界大战正式落幕。</li></ul><h3 id="隐秘的深层威胁-零阶与三阶次生灾害隐患" tabindex="-1">隐秘的深层威胁（零阶与三阶次生灾害隐患） <a class="header-anchor" href="#隐秘的深层威胁-零阶与三阶次生灾害隐患" aria-label="Permalink to &quot;隐秘的深层威胁（零阶与三阶次生灾害隐患）&quot;">​</a></h3><p>死寂走廊作为“历史叠加态的无底洞”，不仅埋葬了一战的亡魂，目前正被列强与中立组织暗中当作倾倒高危废渣的超级垃圾桶。阿国的零阶时间奇点在走廊外围洋流倾倒，而经贸会的三阶空间毒核被沉入走廊底部的海沟。目前这两种截然相反、能引发概念崩塌的极端污染尚未在宏观尺度上直接碰撞。但在世界底层规律的引力牵引下，这两股被掩埋的高维质量正在死寂走廊深处缓慢靠近。一旦两者发生接触并相互湮灭，将会引发一场足以颠覆当前维度的超级次生灾害。这一潜伏的炸弹目前未被任何国家和势力所察觉。</p><h2 id="二、环境" tabindex="-1">二、环境: <a class="header-anchor" href="#二、环境" aria-label="Permalink to &quot;二、环境:&quot;">​</a></h2><h3 id="环境区域划分" tabindex="-1">环境区域划分 <a class="header-anchor" href="#环境区域划分" aria-label="Permalink to &quot;环境区域划分&quot;">​</a></h3><ul><li>宜居区：各国核心城市及周边区域。宜居区在全球范围内数量众多，并非极少数孤岛。宜居区的选址建立在自然环境相对稳定、大气流动规律且地壳活动极度平缓的区域。这些区域天然不易积聚游离的污染。宜居区的过滤屏障并非消灭污染，而是通过深埋地下的“概念隔离桩网络”，将城内的污染强制倒灌进周边的贫民窟、下水道或者就近的小型乱序区与信息虚境。宜居的本质是将代价转移给视线之外的底层和荒野。</li><li>缓冲污染区：存在轻度信息畸变与轻微重力异常，是资源回收者、探险者的主要活动区域。</li><li>核心畸变区：“耻辱战役”的原爆点，是生物无法生存的废土，存在严重的时空紊乱与物质湮灭风险。</li></ul><h3 id="底层信息地漏机制与环境矛盾的动态平衡" tabindex="-1">底层信息地漏机制与环境矛盾的动态平衡 <a class="header-anchor" href="#底层信息地漏机制与环境矛盾的动态平衡" aria-label="Permalink to &quot;底层信息地漏机制与环境矛盾的动态平衡&quot;">​</a></h3><p>宜居区地下密布“引流符文阵列”，作为城市的“信息地漏”。 隔离桩本身起传导作用，与符文阵列搭配使用，将污染打入虚境并隔绝乱序区和有序区界限，建设排污阵列必须需要隔离桩。</p><ul><li>市民日常使用魔导机械产生的一阶污染（废热和微量无序信息）在汇集成微型乱序区前（注：微量魔晶污染自动汇集成早期乱序区的现象，仅适用于前工业时代或无隔离桩的荒野区域。在现代宜居区，由于地漏系统的存在，微量污染被强制导流），会被阵列吸附，汇入主隔离桩排向荒野或虚境。 只有当短时间内魔晶消耗过载（如工厂事故、非法施法），超过地漏吸收阈值，才会在宜居区内爆发微型乱序区。</li><li>缓慢消散技术与总量累积：在排污体系之外，列强通过逆向研究或自主研发，在荒野路网的人造基站上加装了能够吸收部分污染并将其排向虚境的功能。同时，各国在这个过程中也发展出了各式能够缓慢消散污染的技术。然而，这种技术手段处理污染的速率是极其缓慢的。整体上，全球工业产生的污染排放量依然远大于技术的消散量，导致环境中的污染总量仍在不可逆地缓慢增加。这种环境矛盾构成了列强必须在污染满溢引发全面反噬之前，强强行寻求技术突破（如寻找遗迹、造神）的底层环境压力。</li><li>衍生学科与工业：基于此机制，诞生了“城市排污工程学”这一新学科，专门研究污染流体力学与阵列承载极限。同时催生了庞大的“地下管网维护工业”与“符文阵列制造工业”，成为宜居区运转的隐形支柱。</li></ul><h3 id="全球洋流熵污染与空间分层机制" tabindex="-1">全球洋流熵污染与空间分层机制 <a class="header-anchor" href="#全球洋流熵污染与空间分层机制" aria-label="Permalink to &quot;全球洋流熵污染与空间分层机制&quot;">​</a></h3><p>耻辱战役的原爆点至今仍在持续产生污染，随洋流扩散至全球。</p><ul><li>污染分层：原爆点产生的污染主要集中在“表层与中层洋流”，这层狂暴的污染带像盖子一样封锁了常规海运，海洋被高浓度的洋流污染和变异海兽占据，导致常规航海受阻。</li><li>深海恶化归因闭环：列强的采掘母舰实际上是依靠极其昂贵的装甲和灯塔技术，强行穿透中层污染带，进入深海相对静止的“极高压惰性水域”进行深海原晶作业的。而深海开采引发的海底虚境溃疡，其喷发的高维废热和三阶污染，并不会停留在海底，而是会因为“虚境流体力学”直接上浮、倒灌进中层洋流。耻辱战役只提供了一个“初始污染温床”，而列强近百年来为了争夺高阶能源进行的疯狂深海开采，实际上是在暗中、持续不断地为全球洋流的恶劣环境“加压充能”。列强自己亲手把海洋变成了不可逆死地，却在对外宣传上将其全部归咎于一战的历史遗留问题。</li></ul><h3 id="乱序区" tabindex="-1">乱序区 <a class="header-anchor" href="#乱序区" aria-label="Permalink to &quot;乱序区&quot;">​</a></h3><h3 id="成因" tabindex="-1">成因 <a class="header-anchor" href="#成因" aria-label="Permalink to &quot;成因&quot;">​</a></h3><p>由污染达到临界值、个体或群体潜意识剧烈波动、人为扰动等方式形成。过量的信息熵堆积、魔法的无节制滥用，尤其是“耻辱战役”中禁忌魔法的释放，导致部分区域的信息结构“过载”“错乱”。当信息乱序、人群集体情感乱序达到临界值，因为某个事件触发，会导致该区域从守序区转化为乱序区，引发局部的时间回溯、时间停滞、时间流速异常等现象。乱序区的形成并非毫无征兆，在彻底转化为乱序区之前，该区域会出现“预兆点”。这些预兆点是信息虚境因容量过载而向现实世界“吐”出的无序信息残渣，表现为局部的概念扭曲或物理法则短暂失效。乱序区容量达到临界变化体现四周小型熵花绽放。</p><h3 id="表现形式" tabindex="-1">表现形式 <a class="header-anchor" href="#表现形式" aria-label="Permalink to &quot;表现形式&quot;">​</a></h3><p>产生乱序区后，外界的历史本身不会消失，只有进入其中之后历史才会呈现混乱。 乱序区当中的整个时空是彻底混乱的，可能在里面上演几百年前的历史片段。所有乱序区都是历史和潜意识叠加态的。 人们可在特定区域看到历史的“投影”或“回响”，如同全息影像一般重现过去的事件。</p><ul><li>时间流速同步与异常：一般情况下，大部分乱序区内部的时间流速与外部现实是完全同步的。里面的人感知经过了10秒钟，外部现实也同样过去了10秒钟，其主观时间与外部时间同步。只有极少数极端特殊的“风暴点”或高危区域，才会出现时间流速异常（如时间停滞、时间回溯或流速倍率差异）。 乱序区能诞生附属的虚晶产物，能在一定程度上代替魔晶的使用。 虚晶是类似凝结核一类的物品。 乱序区边缘拥有灰色生态。 小微中型乱序区对正常人的危险集中在里面的信息流中产生的怪物和历史的混乱，相对没那么危险。</li></ul><h3 id="时间修正副作用与物质带出" tabindex="-1">时间修正副作用与物质带出 <a class="header-anchor" href="#时间修正副作用与物质带出" aria-label="Permalink to &quot;时间修正副作用与物质带出&quot;">​</a></h3><ul><li>极少数时间异常区的时间修正：在那些极为稀少的极端时间流速异常的风暴点中，乱序区内部的时间并不具备真正的物理质量，它只是一段高频运转的“信息幻影”。当离开者从这种极端时间流速异常的区域返回现实世界时，会遭遇严重的“时间修正”。 这种修正会导致离开者的认知被很大程度上污染，产生不可测的精神副作用。同时，离开者在风暴点内经历的冗余时间，在返回现实时会瞬间叠加到身体上，导致细胞基因端粒迅速老化。这种老化的物理机制并非信息幻影直接做功，而是世界法则在修正时间线时，必须从离开者肉体中抽取等量的生命力与细胞端粒作为填补时间差的燃料，以维持现实因果闭合，这是底层法则强制抽税的结果。</li><li>极端风暴点探索机制（长生种与自律人形协作）：为了应对这种超越短生种生理极限的瞬间老化（即几十年甚至上百年的物理刻录叠加），国家在针对阿国首都外围等高危时间异常区进行探索时，采用特殊的编队模式。执行此类任务的熵序者必须是“长生种干员”。长生种的基础寿命以千百年计，其生理结构和细胞端粒上限足以硬抗风暴点离开时的极端时间修正扣除而不至于当场报废。同时，为了最大限度减少高阶熵序者的不必要消耗，探险小队会派遣大量具备抗污染能力的“自律人形”进行物理协助与前排探路。人形机器在承受时间老化时仅表现为金属疲劳与零件磨损，不会遭受基因层面的崩溃。短生种人类熵序者绝不被允许深入此类高危风暴点。</li><li>豁免机制与物理代价：熵序者拥有特殊的生理机制，其细胞端粒和信息锚定能力能够抵抗时间修正带来的瞬间衰老，可以将这些冗余信息转化为自身的熵积累，从而免于肉体崩溃。但这并非完全免疫衰老，熵序者是将“瞬间的基因崩溃”转化为了“不可逆的细胞透支”。他们在极端风暴点里度过的时间，依然会以某种“倍率”刻在骨龄上。部分遭遇极端情况的老熵序者退居二线，不仅是因为污染，更是因为他们的实际生理年龄已经被时间修正加速到了极限。</li><li>高维信息死锁与修复限制：列强向长生种租借的“局部细胞端粒逆转阵列”只能修复人类熵序者在常规任务中过度做功造成的轻度端粒磨损。而在极端风暴点遭遇的瞬间老化，其本质是被刻录了乱序区内的“高维时间残渣死锁”。如果将带有高维死锁的短生种放入长生种逆转阵列进行修复，强行干涉会导致其物理结构与高维信息发生排异反噬，该熵序者会在仪器内直接“时间逆流至受精卵状态”并彻底湮灭。这彻底断绝了列强用人海战术白嫖风暴点探索的可能。目前，人类列强的科研机构正在秘密研发能够绕过此死锁的“新型抗修正端粒锚定技术”。</li><li>物质带出与信息半衰期：从时间异常的乱序区带出物质（如虚晶、熵之种），在跨越时间边界的瞬间会发生“信息半衰期”现象，其内部的纯度和能量会瞬间流失一部分。为了抵抗这种损耗，诞生了专门的“时间锚定收容封装技术”及相关的制造工业。</li></ul><h3 id="怪物生态" tabindex="-1">怪物生态 <a class="header-anchor" href="#怪物生态" aria-label="Permalink to &quot;怪物生态&quot;">​</a></h3><p>乱序区中的怪物表现为从乱序信息中具象化的各种信息的纠缠体。 这些怪物与进入者或周边人群潜意识里害怕的事物相结合，形成具象化的实体。</p><h3 id="处理机制与后果" tabindex="-1">处理机制与后果 <a class="header-anchor" href="#处理机制与后果" aria-label="Permalink to &quot;处理机制与后果&quot;">​</a></h3><p>如果乱序区处理不当，会导致乱序区进一步扩张。小微型会变为中型，逐渐扩张。每次处理乱序区会导致一部分信息损失。在玩家出现之前，各势力的处理方式分为封存和湮灭：</p><ul><li>小微乱序区：宜居区的小微乱序区产生第一时间清道夫就要到现场，进行局面控制和封锁。采用封存、风控或放任不管的方式，以避免处理带来的信息损失。中大型的以及边缘区的乱序区才是暴力机关负责日常维护。</li><li>中型乱序区：派遣对应专员进行处理（湮灭），会造成大量信息损失。熵序者进入虽能产出熵之种坍缩乱序区，加之熵序者数量有限，常规国家无法负担大量消耗，因此依然倾向于采取物理封锁和暴力湮灭的粗暴手段。</li><li>大乱序区：采用建立隔离带的方式进行封锁。</li><li>国家暴力湮灭机制：国家能够通过实体攻击（如重火力轰炸、高能魔法阵）强行让乱序区湮灭。但这种方式得不偿失，会造成该区域历史信息的永久性毁灭，并引发剧烈的物理灾害。</li></ul><h2 id="三、资源" tabindex="-1">三、资源: <a class="header-anchor" href="#三、资源" aria-label="Permalink to &quot;三、资源:&quot;">​</a></h2><h3 id="核心能源与产物等级体系" tabindex="-1">核心能源与产物等级体系 <a class="header-anchor" href="#核心能源与产物等级体系" aria-label="Permalink to &quot;核心能源与产物等级体系&quot;">​</a></h3><p>资源在经济体系与世界逻辑中存在明确的等级与品质划分，由低到高依次为：</p><ul><li><ol><li>残渣： 最低品质，魔晶使用后的废料与工业污染的核心源头。内部信息已完全无序化，且残留的信息极少极碎，对人类和神明均无利用价值。但在降热与去污染处理后，可作为廉价工业材料回收利用。</li></ol></li><li><ol start="2"><li>虚晶： 边缘区与底层劳工的主要消耗品。作为二阶污染源，其本质是对一阶污染中“最后残存结构”的降级榨取，并非凭空再生，当彻底消耗后会化作无序的残渣。虚晶通过虚境和乱序区凝结，在经历了虚境的凝结后，个人意识会被抹去并沉入集体意识海中。这种抹除是非定向的，但由于抹除现象极多，表现为定向抹除个人情感。</li></ol></li><li><ol start="3"><li>魔晶： 天然形成的高纯度固态信息存储介质，工业血液。按品质分为原晶（天然高纯度）和工业晶（人工提炼），完全不可再生。</li></ol></li><li><ol start="4"><li>熵之种： 中档战略资源，熵序者坍缩乱序区的产物。其产生过程消耗的不仅是魔晶，同时也是大量虚晶聚合信息后的提纯，用于极大程度上满足各国的高耗能消耗（如遗迹武器充能），伴随信息流失。熵之种存在各种形态。</li></ol></li><li><ol start="5"><li>熵之花： 最高等级产物，完美保存所有信息。非玩家产出的“花”类物品，必须满足极其苛刻的条件才能成型。分为以下三类：</li></ol></li><li>空白之花：由玩家跨越维度壁垒降临时，与命定之人达成约定，将其自身高维记忆抵押转化而成。它是维持国联空天武器等极高维物理装置运转的纯白介质。在国联空天武器发射时，空白之花作为“高维钥匙”，在承受毁灭级污染的瞬间发生“概念级升华（燃烧）”，强行中和掉最致命的概念冲击，并在燃烧殆尽的最后一秒将剩余的纯物理废热踹进虚境。这也意味着空天武器的主炮是一次性的，一旦开火，空白之花彻底消失。实际上，空白之花是玩家原始记忆的封印容器。当其在空天武器中升华燃烧时，销毁的仅是高维封印外壳，其核心记忆碎片会在瞬间回归玩家或散落乱序区，使得玩家找回自我的核心动机不至于被彻底虚无化。</li><li>真实历史之花：完全储存所有信息，完美填补命定之人剧本中的核心主干道，化作魔晶矿脉稳固世界。这种花的结算功能是即时的，在玩家交出花的瞬间，其代表的核心概念会立刻被命定之人用来“缝补”当前世界正在剥落概念漏洞，防止剧本烂尾。</li><li>可能性之花：吸收魔晶成为新世界基石。</li></ul><h3 id="魔晶——工业血液" tabindex="-1">魔晶——工业血液 <a class="header-anchor" href="#魔晶——工业血液" aria-label="Permalink to &quot;魔晶——工业血液&quot;">​</a></h3><ul><li>基本属性：魔晶是天然形成的固态信息存储介质，本质上是上一个世界线遗留的信息和重启之后的残渣。魔晶内部存储着大量有序的信息，这是过去几万次轮回积累下来的产物，总量固定且完全不可再生，只有等到整个世界线重置、轮回重启时才会重新生成。新轮回魔晶的“单位能量密度”在极度飙升，这也是为什么最终会形成奇点的原因。</li></ul><h3 id="储量与消耗逻辑" tabindex="-1">储量与消耗逻辑 <a class="header-anchor" href="#储量与消耗逻辑" aria-label="Permalink to &quot;储量与消耗逻辑&quot;">​</a></h3><ul><li>探明储量：全球魔晶的绝对总量极其庞大。命定之人为了加速奇点结局，在这一次轮回初期故意将大部分高纯度高阶矿脉沉降到了深层地壳和深海（这也符合现代的地质学，为后面工业发展埋伏笔），导致浅层、易开采的优质矿脉在近百年的工业化狂潮中已基本枯竭。</li><li>虚境根系悬浮与物理配重转嫁（地壳承载机制）：地壳由于世界缩小变得更薄，而新轮回沉降在深海和地底的魔晶蕴含着高维质量与极高的能量密度。星球地壳之所以没有被这些高密度的魔晶压碎，是因为命定之人在大重置生成这些矿脉时，让矿脉长出了穿透现实维度的“虚境根系”。深层矿脉处于半悬浮的维度叠加态，其庞大的重量被转移挂载到了下方的信息虚境洋流中。现世的地壳只是作为一层物理封层。这也是列强深海开采必须使用重力锚链和防塌陷灯塔的原因，一旦物理封层被粗暴打穿，失去虚境托举的局部矿脉质量会瞬间引发海底重力塌陷。</li><li>开采难度与工业繁荣：剩余的庞大储量集中在深海海沟、深层地壳、死寂走廊深处等高危区域。随着工业扩张，常规魔晶的开采成本与难度确实在稳步上升，但这并没有阻碍列强工业的发展，目前各国的工业和民众生活水平依然处于快速飙升的黄金时期。</li><li>深海原晶的地理隔离：列强能到达的“深海”仅限于大陆架延伸的高压海沟。而真正的世界坍缩边界“虚无之墙”，位于完全被极高浓度三阶污染和空间乱流封锁的“禁忌洋流区”深处。列强目前的采掘母舰装甲根本无法靠近那个深度的观测范围，因此无法观测到世界的坍缩边界。</li><li>深海原晶的高能量密度与专属用途：列强在深海高压海沟开采的并非普通的工业魔晶，而是在极端高压和三阶污染环境下变异的“深海原晶”。深海原晶的单位能量密度极大，蕴含的纯粹有序信息足以产生大量能源。深海原晶作为战略资源，专门截留用于填补“遗迹武器充能”、“造神计划核心驱动”等高阶概念消耗。</li><li>移动采掘城与高压加仓设计：列强在深海开采的并非普通的工业魔晶。采掘母舰实际上是依靠极其昂贵的装甲和灯塔技术，强行穿透中层污染带的“巨型移动工业平台”。为了防止原晶表面的生物质钙化壳在母舰内部因水压骤降而失稳液化成腐蚀性毒液，母舰的传送带和初级处理舱室全部采用了极端的“高压加仓”设计。原晶在被运入母舰内部时，始终处于与海底极高压同等的人造高压水密环境中。声波剥离阵列在这个高压水箱内作业，剥离废料。</li><li>子舰转运排污机制：剥离下来的钙化壳等废料绝不能留在母舰或在作业海域直接排放。深海原晶在极端高压下形成的生物质钙化壳，本身是高浓度的三阶活体生物质沉积。如果直接排入作业海域，这层没有经过任何工业死锁的活体沉淀会立刻与周边的深海乱序环境发生剧烈的“生物性高频共振”，瞬间撕裂局部的空间结构，形成当场喷发的溃疡，反噬母舰。母舰配备了专用的“深海排污子舰”。这些子舰接收高压舱排出的废料，将其运离母舰开采区，前往指定的废料封存区（如特定的深海冷泉永冻泥层或远处的洋流死角）进行冰封或抛填，从而在物理距离上彻底隔绝了排污引发的局部震荡对母舰作业的威胁。</li><li>降维重力锚链技术与深海后勤：为了解决母舰潜浮穿越中层污染带的巨大损耗问题，列强利用阿国的相关物流技术延伸，在特定的深海作业区上方的大陆架边缘建立“发射台”。物资与人员被装入重力舱，沿着排斥污染的“物理锚链轨道”极速下坠，直接砸穿中层污染带，落入深海母舰的接驳口；开采的原晶也同样通过锚链发射回地表。这种专用物流管线必须建立在极其罕见的洋流薄弱点上，是各国争夺深海海域控制权的核心焦点。阿国正是依靠其特有的地理出海口和技术垄断，在这种深海后勤技术上占据了极大优势。</li><li>钢铁浮岛与固定开采带：虽然大部分国家采用移动采掘城，但合众国凭借其强大的工业实力，采用了另一种极端方式。他们将大量的“魔导灯塔”长期汇聚在一起，利用灯塔矩阵产生的强大排斥场，强行在深海中撑开一片相对稳定的无海兽区域。这些灯塔相互连接，最终形成了一座庞大的“钢铁浮岛”。这种浮岛作为固定开采带，能够进行持续、大规模的深海原晶开采，但维持灯塔矩阵运转的能源消耗极其惊人，且一旦矩阵被攻破，整个浮岛将面临灭顶之灾。</li><li>深海冷泉锚定与惰性冰封机制：声波剥落下来的钙化壳（三阶污染活体沉淀）不能直接冲回深海。子舰在排污区，会寻找深海特有的“极低温高压冷泉区”。在熔铸时，子舰会注入从冷泉中抽取的“绝对零度惰性液”，将钙化壳与废岩混合物瞬间“冰封”成极寒的固态冰岩桩。这种冰封阵列和惰性液本质上是在人工模拟经贸会三阶毒核的“惰性死锁”，强行压制钙化壳的活体共振，然后将这些冰岩桩沉入冷泉底部的永冻泥层中，死死压制住钙化壳的活性。深海虚境溃疡频发，是因为地质变动导致某些冷泉区温度上升，冰岩桩融化渗漏。</li><li>消耗速率：随着魔导工业的全面普及、自律人形的大规模应用以及列强军备竞赛的加剧，魔晶的整体消耗速率呈几何级数增长。目前人口消耗仍然小于魔晶与虚晶的总产出量，能源系统维持着相对平稳的高速运转。</li><li>危机根源：列强高层感受到的“末日倒计时”，一方面源于常规开采难度跨越临界点导致的远期“能源断供预期”；另一方面，强行向深层高危区域开采深海原晶，直接触动了世界底层的乱序结构，引发了频繁的“概念剥落”灾难与虚境反噬。</li><li>状态变化：魔晶内部存储着有序的大量信息，使用后这些信息变为无序。</li></ul><h3 id="物理与概念隔绝机制" tabindex="-1">物理与概念隔绝机制 <a class="header-anchor" href="#物理与概念隔绝机制" aria-label="Permalink to &quot;物理与概念隔绝机制&quot;">​</a></h3><p>魔晶自带来自上一世界线的“保护”性外壳。 魔晶物理外壳对神力的绝对排斥，且命定之人设下的界限为不得抽取魔晶中的信息，也是这一轮回中有部分神明对命定之人有反心原因。 这种外壳不仅是物理的，更是“概念”的。魔晶结构分为三层：外层物理结晶层、中层概念外壳层、内层核心信息层。物理碾碎只能破坏外壳获得低维热能，中层外壳会自动坍缩转化信息为废热。只有人类的探索欲信息波能与概念外壳产生信息共振解锁。机械无意识无法提供负熵维持信息展开，且概念外壳主动识别自由意志，拒绝神明直接干预。 对神明有用的信息只能是人去发掘和探索。只有当前世界线具有“未知探索欲”和“独立观测能力”的智慧生物（如人类）产生反应。“破壳”的本质是非神明的观测者进行观测和产生“使用”的意识后，里面的核心信息流才能被真正提取出来。 普通机械破壳算作正常利用其中的能量和少量信息流。普通机械进行物理层面的切割或碾碎，只能让魔晶释放出表层的物理能量和极少量的散碎信息流，这构成了现代魔导工业运转的基础。机械本身没有观测意识，无法产生对神明有用的深度有序信息。 神明受世界规则限制，其行为属于“已知规则的延伸”，无法触发魔晶外壳的深度破裂提取信息，因此无法直接接触和获取魔晶内的核心信息。 神明本身仅能操纵其固有的权能与概念。 湿件（伪自律人形核心）由于生前已被污染彻底洗脑异化，且受到信仰网络和无线传输节点的物理控制，本质上失去了“自主未知探索欲”。因此，它们无法触发高级魔晶外壳的破裂提取深层信息，只能燃烧低端魔晶（虚晶）表层的物理能量。 真自律人形具有未知探索欲，但在玩家出现之前，在世界底层法则的判定中，无法产出花。它们无法对核心历史主干道进行任何物理层面的干涉或扭曲。真自律人形即使有探索欲，由于是大重置后诞生的产物，缺乏跨轮回记忆的信息残留，其灵魂信息熵密度达不到产花阈值，无法产生游离因果碎片，只有玩家与熵序者能产花。后期作为队友存在有可能会突破限制。 因此，神明必须将特定的智慧种族作为代理人，驱使他们进行魔晶的开掘与深度使用。</p><h3 id="现代魔导工业的建立与运作逻辑" tabindex="-1">现代魔导工业的建立与运作逻辑 <a class="header-anchor" href="#现代魔导工业的建立与运作逻辑" aria-label="Permalink to &quot;现代魔导工业的建立与运作逻辑&quot;">​</a></h3><p>魔导工业的基础建立在“机械表层破壳利用”之上。通过特制的魔导粉碎机和锅炉阵列，对魔晶进行物理级别的强行碾压与燃烧。 这种物理破坏释放魔晶表层的能量差（表现为高温、高压蒸汽或强电流），用于驱动工厂、火车和初级魔导兵器。</p><ul><li>物质去向与残渣形成：在机械强行破坏外壳的过程中，魔晶内部深层的“有序历史信息”由于失去了物理载体，大部分直接消散并跌落进虚境，形成一阶污染（废热）。少部分相对不有序的信息被物理残留下来的外壳锁住，集中在燃烧后的“残渣”中。由于这些残留的信息太少太碎，无法构成完整的概念，对人类和神明均无任何利用价值。</li><li>废热残渣的再利用闭环：在经历了近百年的工业狂飙后，堆积如山的坚硬物理残渣并没有成为掩埋在地下的高热定时炸弹。列强通过发展配套的降热与去污染工业，将这些高硬度的物理废料集中抽取热能后进行物理洗消。处理完毕的惰性残渣被大规模粉碎并重新浇筑，化作极其廉价且坚固的复合装甲填料、重工业建材以及各类基建的底层基石。这种将废渣转入军工与民建的循环体系，成功消解了工业化进程中庞大的物理废料堆积压力。</li><li>工业运作逻辑：资本与国家通过机械流水线，将魔晶粗暴地转化为纯粹物理动能。在这个过程中，未被真正利用的深层有序信息伴随着无序废热，以“一阶污染”的形式被白白浪费并排入地下或虚境。现代魔导工业本质上是一种“买椟还珠”的粗放式消耗。</li><li>核心用途：可作为“燃料”直接湮灭释放能量，也可作为“硬盘”存储术式模板。</li></ul><h3 id="产物分类与收集机制" tabindex="-1">产物分类与收集机制 <a class="header-anchor" href="#产物分类与收集机制" aria-label="Permalink to &quot;产物分类与收集机制&quot;">​</a></h3><h3 id="通用收集流程" tabindex="-1">通用收集流程 <a class="header-anchor" href="#通用收集流程" aria-label="Permalink to &quot;通用收集流程&quot;">​</a></h3><p>无论是熵序者还是玩家，收集产物的标准流程均为：进入乱序区前收集信息要素 → 进入乱序区 → 推动历史发展 → 击败乱序区核心异常（Boss） → 收获产物 →离开。</p><h3 id="产物品级差异" tabindex="-1">产物品级差异 <a class="header-anchor" href="#产物品级差异" aria-label="Permalink to &quot;产物品级差异&quot;">​</a></h3><p>产出的花与种子存在大小和等级之分，并非每一朵花或每一颗种子的等级都是相同的。 产物的完整度取决于收集流程的完美程度以及收集者的适格程度。</p><h3 id="熵序者收集机制-熵之种" tabindex="-1">熵序者收集机制（熵之种） <a class="header-anchor" href="#熵序者收集机制-熵之种" aria-label="Permalink to &quot;熵序者收集机制（熵之种）&quot;">​</a></h3><ul><li>产出物：熵序者进入乱序区，通过坍缩乱序区产生“熵之种”。</li><li>熵之种本质：熵之种并非凭空产生的“有序能量”，而是乱序区内无数种历史可能性坍缩成“唯一确定历史”时，被“剪枝”掉的其他可能性的信息残骸，被世界规则强行压缩而成的结晶。它本质上依然是“高压封装的无序”。</li><li>熵之种用途：熵之种作为中档资源，能够极大程度上满足各种高耗能消耗。使用它（解压）会释放巨大能量，并伴随剧烈的信息流失和污染。</li><li>信息流失去向：熵序者坍缩乱序区收获熵之种是伴随着信息的流失和损耗的。流失的信息被虚境抽走，同时弥散少量污染，视乱序区大小而定。熵序者本质上是在无意识地帮命定之人打工。完成流程越完美，种子完整度越高；历史流失的信息量取决于种子的完整程度和熵序者的适格程度。命定之人彻底抽走了全部的核心有序概念，一点没留。</li><li>高维防伪标签与抑制剂原料：国家刮下来的所谓“真实历史粉末”，其实并不是真正具有可延展性的历史信息，而是那团有序信息在被命定之人抽走瞬间，于高压物理外壳上留下的一道“高维拓印/概念划痕”。这层划痕没有实质内容，但带有“曾经装载过绝对真实”的防伪物理残留。熵序者的免疫系统识别的正是这层“高维防伪标签”的物理波段。命定之人故意不抹掉这层微小的残留，是因为她需要国家能够继续量产抑制剂，维持熵序者这批“矿工”的存活，以便他们能继续干活。</li><li>污染代价：熵序者每次回收种子都会对自身产生一定量的污染累积。</li><li>行为限制与历史修正惯性：熵序者的工作要求在乱序区内只能去推动真实历史的发展，绝对不能去改变历史。乱序区内的历史本身具有极强的“自我修正惯性”和“剧本容错率”。只要熵序者的物理干涉（如击杀怪物、移动物体）没有偏离核心事件的节点（如保证关键人物的存活或死亡），底层规则就会将这些干涉视为“合理的微调”并予以吸收，从而产出高纯度信息结晶。</li><li>改变历史的后果：①如果造成的小偏差在容错率内，历史会自行修复圆回，结局不变；②如果干涉越过阈值，偏差过大，历史会强行修复导致严重错乱，流失极大信息，极可能形成更大的乱序区。</li><li>产物伪装消耗：高纯度产物被视作战略级资源，用于极高能级的消耗（如遗迹武器充能）。正常按资源投入使用时，外部观测表现为剧烈的能量释放和信息蒸发，认为其已正常流向虚境；但实际上，命定之人只抽走了纯粹的“有序信息（灵魂）”，留下了极其庞大的“无序能量（物理外壳）”灌注进武器。在其核心信息结构崩塌的瞬间，会被信息虚境中的“命定之人”直接截获并培育成花。国家高层对此一无所知。</li><li>封装机制与便携收容箱：熵之种在刚产出时，是一团极度狂暴的高压无序信息流。熵序者必须使用国家配发的“特制收容匣”将其瞬间封装，同时为了保证提取出的极微量“真实历史粉末”（抑制剂成分）不失活，前线小队会配备专用的“便携收容箱”保存药剂。粉末的失活倒计时并非固定的几天，而是“视周围污染浓度而定”。脱离收容箱暴露在现世低熵环境下会迅速失效变成废料。</li></ul><h3 id="玩家收集机制-历史之花-可能性之花" tabindex="-1">玩家收集机制（历史之花/可能性之花） <a class="header-anchor" href="#玩家收集机制-历史之花-可能性之花" aria-label="Permalink to &quot;玩家收集机制（历史之花/可能性之花）&quot;">​</a></h3><ul><li>产出物一（真实历史之花）：玩家和熵序者一样去顺应真实历史发展时，不会像熵序者那样丢失信息，而是完全储存所有信息，直接产出真实历史之花，填补空洞。真实历史之花只能完美填补命定之人剧本中的“核心主干道”，而那些在乱序区中被剪枝掉的“边缘可能性（无数个支线）”的信息，则被永久抛弃了。真实历史之花在引爆后会化作魔晶矿脉（此为大重置现象），并将完全储存所有信息永远记录在其中，造成世界逐渐稳态。世界边界的缩小，正是因为这些庞大的“边缘信息”在每次轮回中被不断舍弃，以及魔晶固化相关信息，用来换取核心剧本的绝对稳定。命定之人对于玩家产出花并没有急迫的引导，她只是觉得“到时候了”，将花用于即时缝补概念剥落。</li><li>产出物二（可能性之花）：玩家改变历史会导向全新的可能性，产出可能性之花。可能性之花无法被虚境消化，会吸收魔晶，成为新世界基石，一个乱序，但是有无限未来可能的新世界。</li><li>记忆回收与产花的因果绑定：玩家在乱序区内接触高维记忆回响的过程，本质上是一次极高强度的“信息观测与物理扰动”。玩家的观测会与乱序区内的历史纠缠态发生反应。如果玩家在寻找自身低维记忆拼图时，顺应了乱序区的核心既定历史没有越界干涉，这股因观测产生的巨大算力就会结晶为“真实历史之花”，被虚境自然吸收去稳固世界。这相当于是玩家在乱序区活动的“场地费”。而如果玩家为了拼凑自我，用自身的意志去强行违逆乱序区的固有悲剧轨迹，强行改变了历史走向，这种干涉会打破原有的信息闭环。由于记忆回响赋予了玩家抵抗剧本修正的动力，这种越界的干涉直接产出“可能性之花”。可能性之花不是对剧本的修补，而是玩家主观意志对当前稳定世界架构的强制透支。因此，找记忆是驱动玩家去观测乱序区的主观动机，而产出不同种类的花则是其干涉行为在世界底层引发的客观结果。</li><li>惰性封装态与引力收容：无论是真实历史之花还是可能性之花，在玩家摘取后、未被真正“绽放（结算/引爆）”之前，它们均处于世界底层规则施加的“绝对惰性封装态”。这种物理封装壳完美隔绝了花朵内部庞大的高维质量与算力波动。在外界仪器的观测和常规物理接触中，未绽放的花仅呈现出与高纯度熵之种完全一致的物理特征与重量。只有当花被命定之人用于缝补剧本，或被玩家引爆成为新世界基石的瞬间，封装态才会解除，其蕴含的高维质量才会释放。因此，玩家携带花朵在现世行动时，并不会因为高维变量的质量堆积而压碎肉体或引发局部的重力畸变。</li><li>可能性之花的代价（透支剧本稳定性）：在“等价交换原则”下，可能性之花本质上是在透支命定之人精心编织的“走向奇点的既定剧本的稳定性”。命定之人的剧本是单线程的，玩家摘取花，是强行从这个单线程剧本中撕扯出原本不存在的“平行可能性”。这种撕扯消耗了当前世界的底层算力，打破了奇点结局的唯一性，为世界争取到了“不被固化为奇点”的生机。</li><li>物理边界坍缩与地理惩罚因果闭环：摘取可能性之花透支底层算力的惩罚并不是普通的地震灾害，而是将世界板块直接用于“抵债”。塔万汀大群岛破碎的真正原因，是前任旅人拔出可能性之花透支算力后，命定之人为了维持剧本强制平衡，将那片超级大陆最核心的承重板块直接投入了海上“绝对虚无之墙”中彻底湮灭。群岛的现状仅仅是未被吞噬的大陆边缘残骸。玩家拔花引发物理灾难程度，与改变历史的幅度挂钩。这直接导致了世界物理边界在不断缩小。</li><li>高维变量与命定之人的干预界限：可能性之花一旦成型，其本质即为“不属于当前世界线的高维变量”。命定之人的权限仅限于操控当前世界线的“既定历史信息”，她无法直接没收或销毁这种高维变量，只能通过物理手段或规则引导来阻止玩家。玩家若要达成破局，必须收集最高等级的“完美结局的可能性之花”，才能在不引发灾难的前提下逆转历史。</li></ul><h3 id="空白之花" tabindex="-1">空白之花 <a class="header-anchor" href="#空白之花" aria-label="Permalink to &quot;空白之花&quot;">​</a></h3><ul><li>属性：由玩家跨越维度时抵押的高维记忆转化而成，是用来存储无序与有序信息流的纯白介质。这也是玩家与命定之人之间的约定产物。</li><li>作用：作为维持特定事物运转（如国联空天武器）的能源和信息载体。在国联空天武器发射时，空白之花作为“高维钥匙”，在承受毁灭级污染的瞬间发生“概念级升华（燃烧）”，强行中和掉最致命的概念冲击，并在燃烧殆尽的最后一秒将剩余的纯物理废热踹进虚境。这也意味着空天武器的主炮是一次性的，一旦开火，空白之花彻底消失。实际上，空白之花是玩家原始记忆的封印容器。当其在空天武器中升华燃烧时，销毁的仅是高维封印外壳，其核心记忆碎片会在瞬间回归玩家或散落乱序区，使得玩家找回自我的核心动机不至于被彻底虚无化。</li></ul><h3 id="产物的战略价值" tabindex="-1">产物的战略价值 <a class="header-anchor" href="#产物的战略价值" aria-label="Permalink to &quot;产物的战略价值&quot;">​</a></h3><p>熵之花是核心道具和收集品，用于解锁真结局。 在世俗层面，高纯度产物的具备极高价值，是通往虚境之路的钥匙、过往历史的记录，以及高纯度的能源。 供需端相对平稳，只有最重要的物品（如遗迹武器充能）才需要消耗高纯度产物。 一般人（非熵序者）进入乱序区，只能通过强行引爆核心事件来粗暴地催熟乱序区。 强行引爆会导致乱序区内的“错误历史”以物理形式溢出到现实世界，形成无法被常规武器消灭的“信息畸变体”（类似游荡的灾厄Boss）。</p><h3 id="虚晶获取与量产机制" tabindex="-1">虚晶获取与量产机制 <a class="header-anchor" href="#虚晶获取与量产机制" aria-label="Permalink to &quot;虚晶获取与量产机制&quot;">​</a></h3><p>虚晶与魔晶均已实现工业化量产。</p><ul><li>高压催化工厂与重工业产能替代：由于劳工自然异化为无面者的周期长达数十年，纯靠捡漏奇观产出完全无法填补工业狂飙的虚晶消耗。资本与国家不再依赖缓慢的荒野打捞，而是在中大型稳定态乱序区四周建立了庞大的“高压催化工厂”。这些重工业流水线通过特制的物理泵，将城市排污产生的游离一阶废热和收集到的二阶精神毒素强行注入乱序区边缘。利用乱序区边缘自带的“时间与空间微小扭曲特性”作为高压锅，强行加速污染的聚合与沉淀反应。一阶废热本质是无序物理流，无法直接变为针对认知的二阶污染。虚晶的形成需要吸附乱序区边缘游离的二阶情感信息残渣（如劳工绝望）作为催化核。虚晶本质是一阶物理废热包裹二阶情感毒素，使用时外壳释放废热，内层渗透精神毒素，完成阶跃闭环。这种重化工逻辑产出的是不含历史残片、仅具备基础能量的“标准虚晶”，以此粗暴地弥补了产能断层，维持社会基础运转和经贸会的二次转化。</li><li>劳工散采区分：底层劳工去荒野奇观冒死打捞的，并非这种重化工量产的廉价标准货，而是具有微量特殊信息残片、能够被用于高阶转化实验的“未定型畸变晶簇（毛货）”。这种毛货产出量低，具有极高的黑市溢价。 转化率视虚晶自身的品质而定。</li><li>形成机制：虚晶为一阶污染在特定环境下的凝结产物，是对残余能量的榨取。当乱序区发生变化（如扩张、波动）时，虚晶的凝结速度会显著加快。</li></ul><h3 id="农业与粮食来源" tabindex="-1">农业与粮食来源 <a class="header-anchor" href="#农业与粮食来源" aria-label="Permalink to &quot;农业与粮食来源&quot;">​</a></h3><p>极端天气和污染蔓延对传统农业造成打击。</p><ul><li>阶级化饮食结构：宜居区和边缘区的居民主要食用自然耕地出产的无污染粮食作为中端享受品或日常主食；底层的劳工则主要依靠地下农场产出的催熟粮食维持温饱。</li><li>传统自然耕地与双轨制供应：宜居区内部依然保留有正常的自然耕地，自然粮的产量并未达到极度稀缺的地步。这些自然粮由国家粮农组织和贸易网络供应给宜居区居民和边缘区市民。这与地下农场的催熟粮食体系并行，后者主要用于解决底层暴涨人口的最基本热量需求。贸联会的农业体系与国家粮农组织是相互独立的两个系统，贸联会依靠海外净土产出的极高品质自然粮则在黑市走私网络中流通，作为高级硬通货或权贵的特供品。</li><li>地下农场选址与荒野污染运输网络：地下农场并未建立在宜居区正下方，而是依托于远离城市的“地壳惰性断层（死地脉）”。这些区域的地壳对虚境信息具有极强的物理惰性，虚境溃疡极难在此喷发。农场的污染废渣通过类似概念隔离桩的技术，排入遍布荒野的“污染运输网络”。这个网络将污染定向输送至深层地脉或特定的荒野处理节点，成为了现代农业和工业运转的隐形命脉。</li><li>农场超载与钻探泄压机制：列强对于大型地下农场的污染承载量有严格的监控。当农场所在区域的污染浓度达到超界值时，列强会强制该农场停产，并进行人员隔离。随后，军方和工程部队会执行“钻探泄压行动”，通过物理钻探将淤积的污染定向引导至安全的荒野区域释放，以避免地脉炸裂或引发不可控的虚境反噬。这种泄压行动是可控的工程作业，不会以牺牲国家领土为代价。</li><li>运力护送与要塞化：由于农场远离城市，粮食的运力成为维持国家运转的关键要素。阿国的以太气动管网主干道受限于极高的稳压算力需求，只能铺设在大型城市枢纽之间。荒野上的地下农场属于边缘节点，无法撑起管网基站。因此，粮食运输必须依赖重装装甲列车进行点对点输送至最近的城市管网枢纽。为了防范荒野上的无面者、奇观灾厄以及敌国的劫掠，各国会派出精锐的护送队伍（包含熵序者与重装部队）保护实体运输线。地下农场与运输节点形成了一个个高度堡垒化的“农业要塞”。 地下农场依然使用魔晶或虚晶作为能源。地下农场采用了类似宜居区城市排污系统的“引流符文阵列”，将污染集中排向深层。植物本身没有复杂的神经系统和自我意识，对针对“认知和记忆”的二阶污染具有天然的物理惰性，污染无法在植物体内富集。因此，食用这种利用魔晶或虚晶种植的粮食，不会导致人体发生变异，也不会产生认知污染。</li><li>物理躯壳与概念饥饿：地下农场产出的催熟粮食是用残破的信息强行拼凑的物理躯壳，缺乏自然时间信息沉淀的微量有序信息。底层劳工食用这种信息空洞的食物，会产生一点可被人体吸收的微量污染，并不会因此加速异化为无面者。只要配合国家规定的定期基础医疗体检，这股微量的污染就能被代谢或监控，从而维持劳工正常的生活和工作能力。</li><li>重水冷却循环与晶化提纯物理闭环：地下农场除了符文阵列，还配备了庞大的物理冷却水循环系统以吸收虚晶消耗产生的大量废热。为防止带有二阶污染的废热向自然水系渗透，地下农场从荒野“死寂地脉”中抽取“高压重水（惰性液）”进行循环。为解决重水枯竭危机，农场并不全天候持续抽取地脉，而是建立了一套完整的二次回收闭环。重水在一个绝对封闭的钛合金内循环管道中运行，吸收废热并转化为驱动蒸汽机械的动能。做功完毕后，含有无序信息的废弃重水不会被打入虚境浪费，而是被导入庞大的“晶化沉淀池”。在沉淀池内，重水经过物理离心和特殊符文过滤，析出高浓度的污染废渣（物理打包打入虚境或进入工业循环），而净化后的重水则被重新加压回注到主循环管线中进行二次使用。只有在循环过程中发生不可避免的物理蒸发损耗时，农场才会极其节制地从死寂地脉中抽取少量新重水进行补充，从而确保了整个地脉系统的长久可持续运转。</li><li>农场维护与劳工轮换机制：地下农场的维护工作大部分由“低阶自律人形”承担，以减少人类在封闭高浓度二阶污染环境中的暴露。对于必须由人类执行的操作，部分国家采取高频轮换制，确保劳工在出现严重异变前被调离。这些被轮换下来的劳工不会被直接送往矿坑，而是被安排到其他相对低污染的岗位，以维持地下农场作为稳定粮食来源的运转。</li></ul><h2 id="四、魔法本质" tabindex="-1">四、魔法本质: <a class="header-anchor" href="#四、魔法本质" aria-label="Permalink to &quot;四、魔法本质:&quot;">​</a></h2><ul><li>魔法的科学定义：魔法并非神秘力量，而是信息操控的技术，其本质是信息熵的定向转移与释放。科学界存在相关新学科与职业，利用物理观测仪器发现现实重构漏洞，通过遗迹底层公式锚定真实。</li></ul><h3 id="核心原理与规则" tabindex="-1">核心原理与规则 <a class="header-anchor" href="#核心原理与规则" aria-label="Permalink to &quot;核心原理与规则&quot;">​</a></h3><h3 id="a-基本原理" tabindex="-1">A.基本原理 <a class="header-anchor" href="#a-基本原理" aria-label="Permalink to &quot;A.基本原理&quot;">​</a></h3><ul><li>术式学：术士通过解析空间里的信息乱流，从中获得有效的信息和概念，并将这些有效信息和概念释放出来，形成法术效果。</li><li>干涉做功界限：术士的“施法”是将解析出的概念强行用于“物理做功”（如产生火焰、动能）。一旦信息被用于干涉现实做功，其结构就会崩塌并跌落虚境，产生巨大的熵增。 通过特定媒介（魔晶/术式/人脑）将物质的信息编码转录至“信息虚境”（类似AE存储空间），通过湮灭该空间内的信息结构，释放出巨大的能量差。 物质的信息被剥夺后，失去了在现实存在的锚点，因此跌落进虚境，在这个跌落的过程中产生了能量落差。 魔晶湮灭时，通过直接释放巨大的能量差来驱动物理机械运转，或者魔晶本身不完全坍缩，而是留下某种高热的物理残渣。 若消耗的是“概念级”的信息，则需要智慧种族去再次“命名”和“再发现”，该概念才能再次具有意义并重新生效。 表现为物理现象与认知的分离，例如物理上的燃烧现象依然存在，人类失去了对“火可以被利用、火能带来温暖”的认知，将其视为一种无法理解的随机灾害。 直到有人重新解析这种现象，才能完成“再发现”。 对于概念级的操作，只有神明有这种实力，以及部分遗迹武器能达到。</li></ul><h3 id="b-守恒规则" tabindex="-1">B.守恒规则 <a class="header-anchor" href="#b-守恒规则" aria-label="Permalink to &quot;B.守恒规则&quot;">​</a></h3><p>遵循严格的质能守恒，释放的能量 = 被湮灭信息的熵值 × 转换系数。 转换系数视情况而定，其中少于1的部分即为产生的污染等损耗。 能量做功后会消散为“常规物理废热”，而产生的污染则是“无法被物理世界消化吸收的信息残渣”。 任何魔法行为都无法凭空创造，其代价以信息熵的形式体现。</p><ul><li>科学界的认知：人类科学家已经认知到了“信息虚境”的存在。他们通过实验推算得出，现实世界消耗的能量与跌落进虚境的信息熵，其总和始终等于1。这解释了为何在现实物理层面看似违背了热力学第一定律，实则是能量跨越了现实与虚境的边界。</li><li>转换效率： 不同媒介的转换效率排序为：人脑计算 &gt; 机械术式 &gt; 原始符文，且施法代价与效率成正比。</li></ul><h3 id="d-机制与代价" tabindex="-1">D.机制与代价 <a class="header-anchor" href="#d-机制与代价" aria-label="Permalink to &quot;D.机制与代价&quot;">​</a></h3><p>能量释放效果优于正反物质湮灭。</p><ul><li>施法代价：会产生“裂缝”与“污染”（信息畸变）。 污染的本质是“无效的冗余信息”。 魔法使用越频繁，裂缝越大；失控时会直接引发个体爆炸或区域级引爆。</li></ul><h3 id="当代魔法使用普及" tabindex="-1">当代魔法使用普及 <a class="header-anchor" href="#当代魔法使用普及" aria-label="Permalink to &quot;当代魔法使用普及&quot;">​</a></h3><p>借助魔导工业的发展和仪器的普及，在当代，即使是普通人，只要借助相关仪器并结合自身的部分天赋，也能够使用基础的术式。魔法不再是长生种或古代贵族完全垄断的特权。</p><h2 id="五、科技" tabindex="-1">五、科技: <a class="header-anchor" href="#五、科技" aria-label="Permalink to &quot;五、科技:&quot;">​</a></h2><h3 id="自律人形分类与定义" tabindex="-1">自律人形分类与定义 <a class="header-anchor" href="#自律人形分类与定义" aria-label="Permalink to &quot;自律人形分类与定义&quot;">​</a></h3><ul><li><ol><li>低阶自律人形：从过去的信息流（历史记录、死者残留意念等）中抽取零碎的、可完成特定指令的信息片段，注入人形机械中。无完整自我意识，仅具备部分人格碎片。大量使用对底层劳工的就业构成了巨大竞争压力。</li></ol></li><li><ol start="2"><li>中阶自律人形：可被视为独立个体，拥有完整的自我认知与行为逻辑，受《人权保障公约》保护，具备基本人权认定。</li></ol></li><li><ol start="3"><li>伪自律人形：使用被重度污染洗脑报废的底层信徒大脑（湿件）作为核心处理器，通过魔导接口驱动人形机械。可执行复杂指令，甚至模仿原主人的部分记忆与性格，但本质上是“囚禁”在钢铁中的废料意识。根据用途和改装程度，分为军用和民用/民改军两种规格：</li></ol></li><li>军用伪自律人形：配备完善的无线回传系统与物理阻断阀。湿件在机甲内燃烧低端魔晶（虚晶）时，剧烈的污染废热会通过“强频魔导收发器”实时回传给战场的“移动圣物盒”，确保湿件不在开机瞬间溶穿。只有当无线连接被切断，或者圣物盒过载被毁时，物理阻断阀才会强制落下，将无法排出的废热反向灌入自身装甲。此时它才会进入预设的无差别狂暴自爆模式。军用机甲大脑皮层被物理刻录了底层的“机械神谕（基础战术阵型与敌我识别逻辑）”。</li><li>民用与民改军伪自律人形：主要用于后方高危劳作或被地方武装简单拼凑。这类机甲没有昂贵复杂的无线收发与战术倒灌系统。为了解决地下密闭高压环境中的物理自燃与废热淤积问题，民用机甲必须定期插管连接地下矿坑或农场的“冷却液循环系统”，进行强制的物理洗消与排热。它们的核心仅仅是加装了“污染结晶”来维持基础指令传导。因此，它们在网络断开或受损时不会触发废热倒灌狂暴，只会进入呆滞或停摆状态。如果未能按时连接排热管线，它们会因自身产生的物理高热和污染而在极短时间内熔穿报废。</li><li>结晶物理自毁与酸液中浓特征码机制：无论是军用还是民用，当信徒（湿件）彻底报废或失去底层生命协议时，其大脑内的污染结晶都会启动物理自毁。这种缓慢物理溶解的自毁不仅破坏硬件结构防止逆向工程，其产生的特定酸液还会瞬间中和掉残余污染中的“高维伪历史波段”。被降维后的污染只会呈现为普通的二阶精神毒素。这确保了在战场残骸引发局部溃疡时，国联的“康斯坦丁之瞳”溯源雷达只能侦测到许国使用了精神生化武器，而无法抓取到其篡改历史特征码的概念级罪证。</li><li><ol start="4"><li>真自律人形（艺术/奇迹）：极少数情况下，通过未知的、无法复制的技术或奇迹，从庞大的信息流中完整塑造出拥有独立人格、完整记忆与自我意识的全新人形，甚至能完美“复活”已故的历史人物。这是魔导技术的顶峰，被视为无法复现的“艺术”，也是部分国家的核心技术目标。达成此奇迹的代价是需要消耗高能的魔晶，且目前该技术仅被少数几人掌握。真专门律人形的制造一般都被放在死寂走廊内的乱序区中，以应对制造过程中产生的巨大污染和能量波动。真自律人形具有未知探索欲，但在玩家出现之前，在世界底层法则的判定中，无法产出花。它们无法对核心历史主干道进行任何物理层面的干涉或扭曲。后期作为队友存在有可能会突破限制。</li></ol></li></ul><h3 id="自律人形的大批量使用与湿件实验" tabindex="-1">自律人形的大批量使用与湿件实验 <a class="header-anchor" href="#自律人形的大批量使用与湿件实验" aria-label="Permalink to &quot;自律人形的大批量使用与湿件实验&quot;">​</a></h3><p>随着底层劳工因虚晶污染不断消耗异化，各国开始大批量制造和使用自律人形。 自律人形被广泛投入到高危开采、重工业生产和前线战场，用以填补庞大的劳动力缺口。 各国明面上签署了关于中高阶自律人形和相关技术的《人权保障公约》，谴责许国的“湿件”技术为异端。</p><ul><li>湿件逆向人体实验的受挫与边缘化：暗地里，列强高层和军方为了解析这种无视疲劳与疼痛的“廉价生物核心”技术，曾经在战俘营或绝密实验室中秘密进行过针对本国重度污染者或战俘的“湿件逆向人体实验”。然而，由于许国湿件的核心在于不可复制的“圣愚”阵列与大规模信仰概念绑定，列强的逆向实验在耗费海量资源后被证明是得不偿失的。虽然产出了一定量的数据成果，但始终无法突破核心技术壁垒。目前，这项实验已经接近被高层放弃，沦为极少数狂热科学家还在试图强行推进的边缘学科，其相关的地下网络与军方黑库也处于收缩和废弃状态。</li></ul><h3 id="交通与通讯" tabindex="-1">交通与通讯 <a class="header-anchor" href="#交通与通讯" aria-label="Permalink to &quot;交通与通讯&quot;">​</a></h3><ul><li><ol><li>资讯传播： 各国拥有基于传统无线电波等技术的资讯传播系统，能够进行跨区域的信息交流。</li></ol></li><li><ol start="2"><li>交通运输： 整体受海洋污染限制，但列强与贸联会共同维护着贸易网。现代化路网和铁轨网建设正在飞速进行中。</li></ol></li><li><ol start="3"><li>安全贸易航道与灯塔技术： 在海洋中，列强与贸联会掌握着“灯塔”技术，利用魔导灯塔发射特定频率驱散海兽并稳定小范围洋流，开辟安全区与贸易航道。但魔导灯塔的排斥场原理基于“虚境洋流的流体力学”。在海洋中，海水作为物理缓冲介质能让波段平滑扩散。而在陆地上，缺乏海水缓冲，灯塔的高频波段会直接与地脉中固化的乱序信息产生剧烈共振。若在荒野上开启灯塔，不仅无法驱散污染，还会激怒周边数百公里内的所有沉睡灾厄，并引发地层断裂，因此灯塔技术被物理规律死锁，无法在陆地使用，荒野穿行仍需依赖奇观的航道。</li></ol></li><li><ol start="4"><li>高空与地效飞行器： 高空存在大量的乱序点云集，极大地限制了传统航空运输的发展。为了弥补海运的局限和避开高空乱序点，列强广泛使用了紧贴海面或地面飞行的“地效飞行器”，以及利用低空稳定气流的“重装装甲飞艇”。这些构成了全球贸易网的另一核心部分。</li></ol></li><li><ol start="5"><li>物流网道技术： 掌握着上一世界线遗留的物流网道技术。该技术建立在穿梭信息虚境之中，同时也作为传送锚点，以此维持跨大陆的物资调配与人员传送。</li></ol></li><li><ol start="6"><li>以太气动管网与算力寄生闭环： 阿国拥有的独家物流技术，依托高空魔导转录网络（管道），可实现物资与信息的解压缩。该技术解决了跨越时间边界的物资损耗问题。对于粮食等物资的传输，阿国采用了国家标准隔离的集装箱技术，确保物资在管网传输过程中的稳定与安全。但管网的主干道传输存在极高的稳压算力门槛，这种算力无法由常规魔晶独立支撑，而是必须建立在与超级城市时间锚点阵列的“寄生绑定”上。管网主干道实际上是首都时间锚点阵列的“物理散热血管”。物资解压缩所需的庞大算力，直接抽调了时间锚点在镇压历史回溯时排出的降级后的“二阶时间废热（算力冗余）”。每一次物资瞬间传输，本质上是借用时间扭曲降级后的能量差。这解释了阿国为何能卡住物流命脉——一旦切断首都的算力溢出，整个管网物流将瞬间瘫痪。</li></ol></li><li>以太管网的物理援助与统一路网霸权：阿国并未将管网技术完全封闭在国境之内。为了建立跨大陆的物流霸权，阿国向部分盟国及中立区输出了管网的“次级基站技术与装甲列车配套标准”，并通过强大的阿国技术援助，在全球范围内强制推行了“阿国主导的统一一期路网标准”。各国的物流链必须与阿国的管网接口接轨。这套统一的物流链标准不仅是商品流通的血管，更是阿国控制全大陆经济命脉的基石。在管网向外延伸时，为了解决跨国传输“终点端解压缩物理冲击”的问题，阿国的技术援助方案是利用在目标国荒野末端修建深埋地下数百米的“物理缓冲抗压仓”，并利用沿线各国必须承担费用的重装装甲基站来进行物理降压，从而将维护成本转嫁给其他国家。</li><li>东方新基准的冲击：目前，这套被阿国垄断的统一一期路网标准正受到来自东方帝国的剧烈冲击。东方帝国正在秘密开发一种“全球新一代路网基准”与各式尖端技术。这套新基准试图绕过阿国的算力绑定与抗压仓壁垒，建立更低成本、更高冗余的物流网络，这直接威胁到了阿国赖以维持霸权的技术基石，加剧了地缘矛盾。</li><li>时间减压闸道机制与物流封闭性：阿国首都内部时间虽然正常，但外围存在严重的时间异常区。人员与列车并非畅通无阻地直接穿过异常区进出首都，否则频繁跨越时间边界会遭遇致命的瞬间时间修正。阿国在进出首都的固定通道上设置了极其庞大且缓慢的“时间减压闸道”。列车和人员必须在闸道中停留数天甚至数周，在特定的符文阵列下极其缓慢地适应时间流速落差，平滑释放时间修正带来的熵增。这种机制保住了人命，但导致阿国首都物流效率极低，形成了一个相对封闭的“时间孤岛”，因此阿国极其依赖无需活体押运且能瞬间传输死物的“以太气动管网”，并且必须在外部荒野建立庞大粮仓。</li><li>管网动态负荷与时间风暴联动机制：管网作为时间锚点的排热系统，管网处于高负荷运转（大规模物资传输）时，首都时间风暴产生的二阶时间废热被高效抽走并消耗，首都核心区的时间屏障处于相对稳态。但若管网因战时封锁或被敌国物理切断核心排压枢纽，导致长时间处于极低负荷，无法排出的时间废热会在首都地下淤积。这种能量倒灌会导致首都外围的“时间异常区”向内坍缩，引发时间停滞或回溯风暴冲击核心城区。阿国因此必须在管网沿线部署重兵死守，保卫物流动脉即是保卫首都的物理存活。</li><li>管网反向配重与实体质量调度网络：阿国将首都庞大的实体工业废料进行极高密度的物理压缩制成“配重块”。这些废料在输出前已经过严格的降热与去污染化处理。管网在传输物资前会有精确的“预先通知与算力排队机制”，配重块通过管网进行“反向解压缩”输送至荒野基站地下的巨型物理缓冲仓。装甲列车依据调度班次拉走废料。这些无污染的高强度废料并未被单纯遗弃掩埋，掩埋场本身具备配套的处理与重铸机制。处理后的复合残渣被大规模循环利用，作为廉价且坚固的重工业建材，直接用于荒野边缘区新工厂的建设、核心实验室防辐射层的加固以及底层平民房屋的建造，完成了实体质量在国家基建系统内的完全闭环。</li><li>管网运力上限与材料学抗压机制：阿国的管网并不是无限量传输的。为了防止瞬间解压缩大量物资引发局部空间塌陷和致命的引力畸变，管网系统具有极其严格的“单次运力上限”。阿国能够维持管网的日常运转，得益于其飞速发展的现代材料学。他们研发出的高强度魔导合金管道与抗压基站，能够在规定的运力上限内，硬扛住物资解压缩瞬间产生的物理冲击。只要不超过材料的疲劳极限，首都的空间结构就不会被瞬间的质量堆积压垮。</li><li>管网底层逻辑与物理限制：管网底层逻辑为“物质解压缩”，仅能处理当前维度物理形态稳定、信息熵极低的死物（如常规钢铁、标准加工粮）。对于“熵之种”或“花”这类高压封装的无序历史狂暴信息，强行传输会导致管网信息过载并引发毁灭性爆炸。管网的安全检查：管网具有严格的实体押运和人工检查。对送入管网的集装箱有严密的军事级别的看管，避免敌对势力利用管网进行活体（自律人形/湿件）的伪装输送，以此保障首都与核心基站的内部安全。因此，高阶产物依然必须由熵序者使用特制收容匣人工运送，而荒野的农场物资也必须由装甲列车先运到城市枢纽。</li><li>管网动能回收闭环：管网内部除了信息流，填充了特殊的“惰性冷却液/气体（如深海底层抽取的高压重水）”。物资解压缩时产生的瞬间废热，大部分被冷却液物理吸收，转化为高温高压的蒸汽动能。阿国利用这股附带微量污染的蒸汽动能，顺势驱动沿线装甲列车的轨道网或基站的次级发电机，完成二次榨取。最后，真正无法转化的残余污染，才通过特定的节点排入深层地脉。这种机制解释了管网为何没有在沿线引发大面积虚境反噬。</li><li>概念导航避震阵列与幽灵专列的绝对暗流搬运（零阶废渣排污盲区）：阿国利用时间异常区的特性制造了一列“幽灵专列”用于排污。时间阵列排出的零阶高危废渣并非液态或固态的大体积废料，而是经过极致高压后形成的“时间坍缩奇点”。这种零阶废渣带有绝对的时间坍缩概念，极度危险。为了避开任何地表雷达的探测，这批零阶废渣在首都地下的锚点阵列生成后，根本不会升上地表装车。阿国在地下建立了直通时间异常深处的物理对接舱。零阶废渣直接在地底装入幽灵专列的特制收容仓。专列启动时，并非在物理轨道上行驶，而是利用遗迹底层公式强行劈开“一秒钟的时空缝隙”。列车在启动的瞬间便沉入这道时间缝隙中，跨越物理维度的荒野，像潜水艇在水下潜行一样。装卸过程采用信息化注入与半显化锚点机制。物理交互仅在纳秒级短脉冲内完成。同时，康斯坦丁之瞳的时间分辨率为1秒，专列在0.1秒内劈开闭合缝隙完成搬运，完美躲避了雷达拍摄的信息快照。直到列车抵达死寂走廊内部的坐标点，才在缝隙中直接将零阶奇点倾倒出舱。这种“地下生成——缝隙搬运——死区抛填”的绝对暗流物流机制，彻底切断了与现世物理空间的交互。这就是为什么国联的“康斯坦丁之瞳”无法抓取到阿国排污特征码的根本原因——雷达的波段只能扫描现实维度的地理空间，无法扫描那些被折叠在“时间缝隙”内部的高维质量转移。</li><li>逆向情绪发射桩与地脉诱导机制：阿国不能被动等待奇观在专列航线上违建。为彻底解决航线可能被随机生长的奇观堵死的风险，阿国军方在幽灵专列的物理航线两侧地下，深埋了高密度的“逆向情绪发射桩”。这些桩不吸收污染，而是持续向外辐射一种特定的“高频驱离波”（类似于极度厌恶、排斥的潜意识信号）。这种信号对正常人无效，但对于仅靠本能游荡寻找地脉节点的无面者来说，这片排污专线区域在感知中变成了绝对死地。无面者会本能地避开专线附近的地壳节点，转向更远的荒野深处去建造奇观。但这套系统存在致命副作用：高频驱离波会加速当地虚境的熵增，并吸引比无面者更危险的高阶情绪吞噬者。因此只能在专线等极少数核心点临时部署，无法大规模普及。</li><li>物理清道夫列车与绝对净空区：在驱离波和避震阵列的双重保护下，在幽灵专列发车前，阿国军方仍会提前半天在同一条物理路线上开出一列重装甲的“物理清道夫列车（破冰船）”。这列实体火车搭载着巨型空间稳定锚和重炮，任务是用物理手段强行碾平沿途极少数漏网的微型活跃奇观，或者用稳定锚强行镇压空间湍流，硬生生犁出一条“绝对净空区”。幽灵专列紧随其后在缝隙中极速穿过。如果清道夫列车被意外灾厄摧毁，幽灵专列会立刻紧急刹车绝不涉险。这种在荒野上强行开辟净空区并运送高危废渣的行为，属于阿国的绝对内政，别国无权干预。</li></ul><h3 id="高精尖观测仪器与魔晶使用" tabindex="-1">高精尖观测仪器与魔晶使用 <a class="header-anchor" href="#高精尖观测仪器与魔晶使用" aria-label="Permalink to &quot;高精尖观测仪器与魔晶使用&quot;">​</a></h3><p>各国用于测量虚境科学的高精尖观测仪器，正统情况下均使用高纯度的天然魔晶（原晶）作为能源驱动，以确保观测数据不受能源自身波动和杂质干扰。 只有在资源极度匮乏或进行特定的对照组实验时，列强才会使用贸联会提供的“伪魔晶”。伪魔晶由于自带三阶污染，不被作为常规和主要的观测能源。</p><h2 id="六、污染" tabindex="-1">六、污染: <a class="header-anchor" href="#六、污染" aria-label="Permalink to &quot;六、污染:&quot;">​</a></h2><h3 id="污染分层与隔离桩排污机制" tabindex="-1">污染分层与隔离桩排污机制 <a class="header-anchor" href="#污染分层与隔离桩排污机制" aria-label="Permalink to &quot;污染分层与隔离桩排污机制&quot;">​</a></h3><p>宜居区通过概念隔离桩排出的主要是高浓度的二阶和三阶工业污染。 隔离桩本身起传导作用，与符文阵列搭配使用，其作用是打入虚境并隔绝乱序区和有序区的界限，建设排污阵列必须需要隔离桩。</p><ul><li>虚境流体力学与溃疡随机喷发：虚境内部并非静态的水池，而是存在极其狂暴的“信息洋流”。宜居区打入的污染瞬间被洋流卷走、打碎，并在虚境的“地壳薄弱处”发生喷发。污染在虚境潜伏期极长，洋流会将污染带至全球，导致平时发生小规模的随机喷发。每次虚境溃疡产生的污染会很剧烈，呈指数级排放。这就解释了为什么排污点和溃疡爆发点在地理上不重合。科学界为此衍生了“虚境流体力学”等新学科，试图预测信息洋流的走向和溃疡的爆发点。</li><li>罕见异象与一般排放：虚境溃疡现象产生的被虚境洋流扭曲后的“狂暴概念残渣”或“高维实体异象”，本质统一还是可以被吸附的一阶、二阶污染聚合表现以及大量的无序一阶污染。这些异象是很罕见的现象。一般情况下，溃疡喷发的还是一阶污染排放。</li><li>虚境增强与排污协定：对于信息虚境而言，列强排入的污染并非破坏，而是增强虚境的养料。虚境不断发生的“溃疡”现象，实际上是虚境容量与力量增强的物理表现。然而，这种溃疡会导致现实世界频繁出现局部灾厄。列强高层察觉到了排污量与灾厄爆发频率的正相关性，为了避免自身核心区被溃疡波及，各国被迫在国际上签订了秘密的《排污限制协定》，互相监督对方的工业排污规模。</li><li>康斯坦丁之瞳与因果牵引：国联的“康斯坦丁之瞳”能够检测并精准溯源某次溃疡中污染的“信息特征码”，从而锁定排污国。同时，虚境洋流存在底层的“因果牵引”机制。平时的小喷发是全球随机倒霉，但当“全球虚境总容量”逼近阈值引发大范围溃疡时，世界底层规则会溯源锁定总排污量最大的国家，导致其本土遭遇毁灭性的高强度溃疡。这构成了列强不敢做排污出头鸟、必须维持协定的硬性约束机制。</li><li>污染的最终去向：虚境入口产生伴随预兆点产生，本身出现地点和吸收量不确定，学界认为污染最终是流向虚境的。</li><li>排污独占物理死锁（死寂走廊排污限制）：死寂走廊被列强环绕且法理上仍是宣称领土，它确实拥有恐怖的消化历史残渣的能力。但走廊的“垃圾桶”特权具有严格的物理死锁。阿国能倾倒首都废渣，是因为零阶废渣带有“高维时间属性”，能与走廊内混乱的历史叠加态同频湮灭。如果列强强行用装甲列车往死寂走廊里倾倒常规的二三阶工业污染，不仅无法被走廊消化，这种低维的狂暴能量反而会像往滚油里泼水一样，引发走廊缓冲带的“反向爆炸溃疡”，将污染千万倍地反吐回列强本土。这种物理反噬彻底堵死了列强将死寂走廊作为公用排污场的念头，也确立了阿国的特权。</li></ul><h3 id="污染分级与交互机制" tabindex="-1">污染分级与交互机制 <a class="header-anchor" href="#污染分级与交互机制" aria-label="Permalink to &quot;污染分级与交互机制&quot;">​</a></h3><ul><li>一阶污染：魔晶使用后产生的无序信息流污染，不具备可恢复性。</li><li>二阶污染：虚晶使用产生的认知污染，具有可恢复性，极其缓慢，优先抹除自我意识和复杂记忆，并逐渐破坏人脑的精细逻辑协调与物理机械判断力。工业生产集中在二阶污染。</li><li>三阶污染：经贸会转化虚晶与魔晶过程中产生的污染。具有污染穿透性，信息和意识同化于虚境中。</li><li>交互机制：无面者奇观只能吸附游离在地表浅层的一阶污染和少量二阶污染。三阶污染具有穿透性，奇观无法吸附。三阶污染会反向侵蚀无面者，导致无面者发生更深层的异变（如彻底虚境化）。因此，经贸会必须在乱序区内秘密生产，利用乱序区内“历史死循环”特性，将三阶污染的特征“加密包裹”成一阶污染的普通废热，让虚境（和命定之人）将其误判为正常的历史自然损耗，以此来瞒天过海。</li></ul><h3 id="魔晶污染机制" tabindex="-1">魔晶污染机制 <a class="header-anchor" href="#魔晶污染机制" aria-label="Permalink to &quot;魔晶污染机制&quot;">​</a></h3><p>魔晶的开采是不会造成污染的，是使用才会造成污染。 微量魔晶使用会自动将自己的污染汇集在区域内某一点，也就是早期乱序区点，正常生活使用魔晶产生的污染可以忽略不计。 但是当一次性大批量使用魔晶才会导致直接产生中型甚至大型污染区。 魔晶使用后会变成无序信息流污染，且不具备可恢复性。</p><h3 id="虚晶污染与影响" tabindex="-1">虚晶污染与影响 <a class="header-anchor" href="#虚晶污染与影响" aria-label="Permalink to &quot;虚晶污染与影响&quot;">​</a></h3><p>虚晶具有可恢复性，能量转化率视其品质而定，且使用虚晶会产生无法被过滤的“二阶污染”，被视为给底层平民的廉价能源。 二阶污染指心灵上的类似铅中毒。在平稳情绪下确实是慢性病，持续数十年。转变是缓慢的，不是极高烈度的人口损耗，更类似病症而不是送死。底层劳工的消耗并非极度绝望的疯狂消耗。</p><ul><li>异化周期与非必然性：二阶污染导致劳工异化为无面者的过程是以几十年计算的，并非短期工作就会发生转变。由于转变周期漫长，列强能够维持庞大的底层劳动力池。同时，并非所有的底层劳工最终都会变成无面者，异化是少数情况，且与工作环境的恶劣程度直接相关。</li><li>绝境情绪催化机制：当人的情绪长期处于极度崩溃或狂热状态时，大脑的防御机制会瓦解，二阶污染的侵蚀速度会呈指数级上升。原本需要几十年的异化，在极度绝望的矿坑或高压流水线上，可能只需要几个月就会彻底爆发，将劳工转化为无面者。</li><li>群体阈值共振效应与特大灾难防线：二阶污染在人群中存在“群体阈值共振效应”。当一个密集居住区内携带二阶污染的人口密度超过临界值时，体内污染会产生共振，导致区域污染浓度局部飙升。几十万人的下城区爆发群体共振属于罕见的“特大灾难”。在特大灾难发生时，国家机器会介入进行宣传和动员，引导正向舆论以平息群体情绪的崩溃。在这个环节中，清道夫不再仅仅是心灵医生，他们同时转变为维稳者和专业防疫部队。清道夫放弃挨个治疗，转而在平民中筛选出精神力较强的老劳工等特定人员，对其进行极深度的药剂锚定，将他们打造成人体“绝缘节点”。这些绝缘节点混居在贫民窟中，物理切断情绪的传导链路，死死压制住整个街区的污染共振飙升。</li><li>生存条件恶化与排污协定：污染的威胁性主要体现在底层生存条件的逐渐恶化。随着工业化推进，边缘区的污染浓度缓慢上升，导致新生儿畸形率增加、农作物减产以及慢性病普及。列强高层签订《排污限制协定》，并非因为底层人口即将死绝，而是未雨绸缪，防止污染浓度突破某个临界点，导致整个生态系统崩溃。 虚晶对人的污染主要是在认知方面的，从微小事物开始遗忘和认知改变。 这种“遗忘”具有高度的定向性。 虚晶的污染优先抹除的是“自我意识、情感、反抗精神和复杂记忆”，以及对自身来说的锚点。二阶污染在抹除情感的同时，也会逐渐破坏人脑的“精细逻辑协调与物理机械判断力”。</li><li>资本家妥协机制：由于精细逻辑协调受损，如果劳工异化过深，他们虽然不再反抗，但会因为物理机械判断力下降而频繁发生操作失误。这种失误会导致昂贵的魔导流水线炸膛或地下农场冷却管线断裂，突发公共安全事件的概率急剧上升。为了保住高昂的生产资料不被损坏，黑心包工头和资本家才被迫妥协，允许并捏着鼻子让清道夫介入进行记忆锚定，以维持劳工“最低限度的清醒与操作能力”。 这种遗忘是缓慢进行的，且一开始是可以被重复训练给复健的，越年老效果越严重。 污染算是慢性病。</li><li>异化预兆：在彻底异化为无面者之前，劳工会出现明显的预兆，例如在潜意识中“听”到来自虚境的低语或启示。这种预兆为劳工提供了预警。底层劳工的生存路径并非只有死路一条，许多人在出现预兆或积攒到一定财富后，会选择离开高危岗位，转入地下农场或边缘区的其他服务行业，从而避免了彻底异化的结局。</li></ul><h3 id="伪魔晶的三阶污染废料闭环与格式化溯源机制" tabindex="-1">伪魔晶的三阶污染废料闭环与格式化溯源机制 <a class="header-anchor" href="#伪魔晶的三阶污染废料闭环与格式化溯源机制" aria-label="Permalink to &quot;伪魔晶的三阶污染废料闭环与格式化溯源机制&quot;">​</a></h3><p>伪魔晶技术是近十年才产生的新锐技术，相关的产业链和排放体系也是在最近十年内逐步建立的，其三阶废料排放并未引发全球性地质灾变。 经贸会在生产伪魔晶时，不仅利用滤网将废热伪装，还将伪魔晶底层的“信息特征码”进行了“物理格式化”。三阶污染具备物理维度的绝对穿透性，但在信息维度上可被分离。单向滤网剥离了三阶信息内核层并将其加密包裹。隔离桩只能阻挡预设信息特征，如果要检测本质信息熵则需消耗无法承受的渊息石代价。渊息石本身存在自然信息衰变，未激活的半衰期为50年，导致其无法大量囤积。经贸会依靠技术和蚀核伴生矿稳定提取，构筑了生态壁垒。当伪魔晶被燃烧形成纯粹的三阶污染固态毒核并排入虚境（如下沉深海或作为脏弹引爆）时，康斯坦丁之瞳溯源雷达所抓取到的只是一段“无主乱码”，根本无法定位到使用伪魔晶的列强头上。这解释了列强为何敢将危险的毒核作为武器或直接深埋而不惧怕因果反噬，同时也巩固了经贸会作为“干净排污额度”提供者的不可替代地位。各国也在暗中进行溯源研究。经贸会排出的三阶毒核最外层固化了一层基于遗迹技术的“物理格式化死锁外壳”。这层外壳让毒核在虚境洋流判定中表现出极强物理惰性，像密度极高的铅球一样笔直砸向虚境底部，不会与中上层洋流发生化学反应而引爆溃疡。</p><ul><li>死寂走廊的自然底噪平账掩盖：康斯坦丁之瞳是战略级雷达，突然出现的海量“无主乱码”在宏观数据上会形成巨大黑洞。经贸会目前并没有掌握高级的漂流掩护技术，其排污策略依然是简单粗暴的“顺风掩埋”。经贸会在生产时不仅利用死寂走廊或超大型活跃奇观掩盖废热，在排放毒核时也利用了死寂走廊本身的特质。经贸会故意将这批被格式化溯源的毒核沉降在死寂走廊底部的虚境海沟中。死寂走廊本身永远在喷发极高浓度的混乱历史叠加态，其产生的自然污染底噪是天文数字。经贸会把毒核排入其中，国联的雷达在进行宏观统计时，会将这些乱码完全误判为“死寂走廊历史遗留问题的正常波动溢出”。这种物理掩护使得凭空多出的三阶污染在宏观统计上完美平账，打消了国联的警觉。</li><li>虚境洋流漂流瓶机制（绝密理论阶段）：目前科学界与列强内部提出了“漂流瓶机制”的设想。该理论认为若将带有自锁结构的三阶毒核打入虚境极深处的狂暴洋流，让其随波逐流数月甚至数年后再爆发，就能在地理坐标上让爆发点与投放点彻底脱节，完全摧毁国联雷达的行为地理统计学溯源。然而，该技术由于对虚境流体力学的极高算力要求以及自锁外壳材料在虚境深海中的极高破损率，目前全世界没有任何一个国家（包括经贸会）掌握该技术，仅停留在理论与绝密研发阶段。</li><li>雷达威慑与国家级排污核试验：由于漂流瓶技术尚未实现，如果国家实体（如合众国）强行在地底或深海引爆三阶毒核脏弹，国联的康斯坦丁之瞳雷达必定能够通过“行为地理坐标重合度”直接将其锁定，根本瞒不住。这就像在现实中引爆核弹一样。列强在进行此类武器实验或战略打击时，根本不屑于去掩盖这团“无主乱码”，而是干脆当作一种半公开的“战略核威慑”。向世界宣告本国掌握了概念级穿甲杀伤武器，以此震慑敌国。但对于经贸会这种必须维持中立且暗中敛财的组织而言，三阶污染的排放是必须死死隐藏的把柄，因此经贸会只能极其谨慎地依赖死寂走廊等天然盲区进行平账。</li><li>遗迹自锁结构与瞬间坍缩：伪魔晶在未被完全榨干前，其内部存在的“遗迹自锁结构”死死锁住了三阶污染不外泄，表现为能量输出的绝对平稳，使精密仪器免受污染穿透烧毁。当能量被抽取至临界值（如低于5%）时，该自锁结构瞬间崩塌，被压制的污染在一秒内物理坍缩为高辐射的三阶固态毒核。列强利用此物理时间差将其作为平稳能源使用，并在临界点前切断并回收残渣制造脏弹。</li></ul><h2 id="七、动物种群" tabindex="-1">七、动物种群: <a class="header-anchor" href="#七、动物种群" aria-label="Permalink to &quot;七、动物种群:&quot;">​</a></h2><h3 id="无面者群落" tabindex="-1">无面者群落 <a class="header-anchor" href="#无面者群落" aria-label="Permalink to &quot;无面者群落&quot;">​</a></h3><p>这些彻底失去记忆和自我的劳工，其肉体会自发寻找最近的乱序区，成为乱序区扩张的“生物质养料”；或者他们会聚集成一种被称为“无面者”的游荡群落。荒原上的无面者大多是由边缘区的底层劳工转化而来的，他们在边缘区被压榨异化后本能地向荒野游荡。 各国军队会定期清剿中型区域的无面者集群，回收为虚晶。</p><ul><li>行为特征：无面者虽然失去了个人记忆，但保留了“工作”的本能。他们会在荒野中无意识地建造巨大的、毫无意义的钢铁建筑（奇观）。</li><li>奇观的防御工事投影本质：无面者并没有“创造”奇观，他们只是在潜意识深处接收到了上一世界线遗留的“信息回响”。在上一世界线，这种尖塔是人类为了抵抗虚境入侵而建造的防御工事。无面者失去自我后，大脑变成了空白的接收器，本能地开始复刻这种防御工事。世界底层规则并没有主动制造炸弹，奇观吸附污染并孕育灾厄，是因为当前的物理法则已经无法支撑这种古代防御工事的正常运转，导致其变成了一个失控的“污染高压锅”。</li><li>奇观的物理质量来源（地脉元素强抽与生物矿化机制）：奇观并非无面者搬运废铁凭空搭建的，奇观的物理质量遵循严格的等价交换。奇观的选址必须在“地壳喷发点”。无面者聚集后，其体内同源的污染会与地脉节点产生剧烈共振，这种共振激活了古代防御工事投影底层的“纳米级采矿协议”。奇观的基座会像植物的金属根系一样刺穿岩层，深扎入地下，强行抽取地壳深处游离的铁、硅等各种物质结合体元素，在地面上进行疯狂的“生物矿化生长”。这就解释了为什么奇观具有极其恐怖的成型速度，且其物理质量完全来源于对周边地壳物质的强行抽取，不仅是钢铁，而是各种物质的粗暴缝合。</li><li>生态异化：无面者的消化系统已经异化，他们能通过吞噬“虚晶残渣”获取能量，同时存在基础的畜牧等行为。</li><li>奇观的食腐生态位与容量区分：这些钢铁尖塔并不是每次都会孕育出区域灾厄。它们在环境中作用相当于“污染吸尘器”，能自发聚集并吸附四周大范围游离的污染和乱序信息。奇观的吸附量并非恒定极低，而是与其体积和形成时间呈正相关。小微型奇观只能吸附极少量的污染；而经过长期聚合形成大型奇观，其吸附量极大。由于宜居区的高浓度污染被打入深层，奇观就像荒野上的食腐动物，吸附着从虚境溢出的二次污染。</li><li>奇观的污染利用与打捞残片：奇观吸附的一阶污染只是“诱饵”或“培养基”，极品虚晶真正的核心信息，是奇观凭借其古代防御工事的特性，从“虚境洋流深处”反向打捞出来的上一世界线的残片。命定之人并没有主动截断这些残片的上浮，她顺势推动了奇观对高维残片的打捞，将这整个现实世界的结晶化与被杀戮小队争夺的过程，视为一个巨大的“磨床”。她在利用当前世界线人类的贪婪和物理消耗，去缓慢消磨和溶解这些残留碎片里的上一代高维意志，以绝后患。一阶污染作为诱饵被吸附并用于在奇观内部结晶化，融合残片最终孕育出极品变异虚晶。</li><li>奇观引力核介质与漩涡效应（打捞锚点）：奇观能够“跨越维度”打捞高维残片，并非无端垂钓，而是依赖其特殊的“高密度引力核”。当奇观吸附海量一阶废热时，其内部由地脉元素构建的防御工事结构会对废热进行极限物理压缩。这种压缩在奇观核心形成了一个“局部高密度信息引力核”。由于一阶废热本质上源自被粉碎的古老信息，其高压聚合态在质量上达到了干涉虚境流体力学的阈值。引力核就像一块沉重的礁石，在平稳的虚境洋流中强行制造出一个“微小的漩涡”。这个漩涡的向心力会将洋流深处漂流的高维残片直接“吸”入奇观的物理漏斗中。这就是为什么游离的废热无法打捞残片，只有经过奇观极致压缩后的引力核才能作为锚点介质。</li><li>三阶污染过滤与极品虚晶的稀缺性成因：经贸会秘密排放的三阶污染增加了荒野奇观吸附时的致命风险。极品虚晶之所以极其稀有，根本原因在于洋流的不可控性。绝大部分奇观在漫长的孕育过程中，会不可避免地吸附到游离的三阶污染。三阶污染的穿透性会直接破坏虚晶内部精密的残留概念结构，导致其在成型前“变质碎裂”，化作毫无价值且高危的毒块。只有极少数位于特定洋流死角、幸运避开了所有三阶污染暗流的奇观，才能成功孕育出纯净的极品虚晶。这直接导致了真自律人形的核心材料具备无法人为干预的“极高报废率”，彻底锁死了列强试图将其量产的计划。</li><li>荒野重度污染沉淀区：虚境溢出的污染总量庞大，奇观并不能将其全部吸附。那些未被吸附的过量一阶污染，会在特定的荒野低洼地带或气旋中心自然沉降，形成致死率极高的“重度污染沼泽”或“信息风暴带”。这些区域彻底断绝了物理交通，形成了自然的天堑，阻隔着不同城市之间的荒野陆路。</li><li>奇观选址的地理严苛性与不可控性：奇观不是随便建的，必须建立在“地壳喷发点或虚境地壳极度薄弱的天然节点”上。这些节点的位置是完全随机且稀少，无法人为搬运或强行聚集，具有高度的随机化特征。无面者是依靠本能寻找这些天然节点进行建造。人为干预或圈养会导致无面者失去这种本能，建出来的只是普通的废铁。而且，奇观一旦建成，就相当于在现实和虚境之间插了一根吸管。如果奇观过于密集，会引发“共振”，导致大范围的虚境溃疡，直接把现实区域拖入虚境。这种地理选址的苛刻性直接堵死了任何国家试图将奇观作为廉价大规模杀伤性武器部署的战术意图。国家只能被动寻找，绝对不敢主动量产。</li><li>相对安全航道与活跃期危险：奇观在正常吸附污染时，其周围确实会形成一条相对安全的“低污染航道”，列强可以利用这些航道在荒野中穿行。但是，当奇观吸附达到临界值进入“活跃期”或“过载期”时，其高频的吸附运作会引发强烈的“重力湍流”或“空间微小错位”。此时，这条原本安全的航道会变得极度危险，极易将穿行者切碎或卷入空间乱流。</li><li>奇观可拆卸性与沿线维护：如果奇观的自然生成位置恰好阻断了列强的路网或管网，军方能够对其进行拆除。这种拆除不仅可以使用纯物理手段（如重炮阵列平推），也可以使用大型术式强行将其结构湮灭。为了保护国家级的物流大动脉，列强在主干道沿线部署了“自动沿线维护系统”。该系统一旦检测到路网周边出现奇观的地基生长，就会自动调用火力坐标或调度护路装甲列车，在其形成复杂的高维概念迷宫和孕育出灾厄之前，趁其脆弱将其直接摧毁抹平。</li><li>奇观过载与灾厄化：当大型奇观吸附的污染达到物理饱和界限，而其内部孕育核心又未被及时取走时，奇观并不会发生炸毁路网的毁灭级爆炸（此为世界规则对物理连贯性的底层保护）。而是会将满满溢的污染与打捞的高维碎片直接融合，在奇观内部或周边具象化地“催生”出一个强大的灾厄Boss实体。该实体的诞生会迅速恶化周边的空间稳定度，严重威胁附近的航道与农场补给线。列强为了防止这些灾厄实体游荡截断路网或冲击宜居区边缘，被迫高频派遣杀戮小队进行危险的“放血排爆”。</li><li>杀戮小队清剿机制与代理人战争：国家派人进入奇观内部，击杀未成熟核心（或刚诞生的Boss），产出虚晶并观测现象。由于奇观内部高浓度的污染结晶极易因魔导武器的能量波动而引发过载破裂，军队不会大规模进场，也不会在内部使用高能魔导武器。而是派遣精锐的“杀戮小队”，依靠纯物理的动能武器（如蒸汽动力重锤、高压气动枪、大型冷兵构）或熵序者的肉体力量进行近战肉搏清剿。产出的极品虚晶具备极高的战略价值，能够作为制造真自律人形的核心材料。因此，荒野上围绕这些高价值奇观的暗杀和抢夺从未停止。列强之间为了争夺奇观的控制权和产出物，频繁在荒野上爆发残酷的代理人战争。PMC雇佣兵、敌国杀戮小队和地下黑市武装在奇观周围进行着持续的绞杀。</li><li>奇观内部时间流速塌缩：奇观内部高度聚合了上一世界线的残片，当其过载化作灾厄子宫时，其内部空间的时间曲率会发生“内向塌缩”。杀戮小队在内部进行的为期数周或数月的物理排爆和迷宫探索，在外部荒野的物理标尺上仅流逝短短几个小时。这就保证了外部国家级物流路网只会经历短暂的“风暴预警停运”，不会陷入长期的瘫痪。</li><li>宕机重启期与生态配额：奇观核心被击杀后，奇观会陷入一段时间的“宕机重启期”，无法吸附污染，导致周边区域污染浓度急急剧上升，形成短暂的“死亡禁区”。极品虚晶虽然珍贵，极造真自律人形等高精尖造物还需要其他极其高昂的配套材料，因此各方势力对极品虚晶的绝对需求量是受限的，并没有达到不顾一切疯狂开采的地步。同时，列强高层通过高精尖仪器监控着荒野的整体污染浓度。当宕机奇观的数量达到某个临界值，导致荒野污染浓度逼近反噬红线时，列强之间会达成短暂的停火默契，强行进入“休渔期”，禁止杀戮小队靠近剩余的活跃奇观。这种“奇观生态配额”机制维持了荒野污染的脆弱平衡，也为荒野上的代理人战争增加了周期性的战术博弈。</li><li>荒野生态下水道（液化深层填埋机制）：针对奇观Boss被击杀后其庞大物理身躯的降解去向，世界底层存在强制的“深层填埋物理闭环”。当灾厄核心被拔除后，其失去高维概念支撑的巨大肉体不会在荒野地表自然腐烂，而是会在极短时间内发生“高压液化/沙化”。这股高密度的污染淤泥受地心引力和地脉牵引，会像水往低处流一样，顺着奇观打穿的地壳裂隙极速倒灌回地底极深处的“地壳惰性断层/沉降泥层”。在那里，这些废料被世界底层的庞大地热和物理高压缓慢碾碎、固化。这不仅解释了荒野地表为何没有被一百年来的巨型怪兽尸体淹没，也确保了污染没有违背物理守恒地凭空消失，而是被塞进了星球极深处的不可见夹层中。</li><li>科研价值：尖塔中蕴含某些无面者潜意识中重现的失落技术，科学界会在战地科研人员的保护下进行研究。概念隔离桩的技术细节是通过逆向无面者奇观得到的。</li><li>掠夺本能：由于受到信息频率的趋光性影响，无面者会本能地掠夺普通人的贴身物品（如照片、日记）。他们并非看重物理纸张，而是为了吸食附着在这些物品上的“人类强烈的情感信息残余”，以此缓解失去自我的痛苦。</li></ul><h3 id="荒野污染生态" tabindex="-1">荒野污染生态 <a class="header-anchor" href="#荒野污染生态" aria-label="Permalink to &quot;荒野污染生态&quot;">​</a></h3><ul><li>析出异象：过量的污染在荒野中不仅会形成沼泽，还会形成“析出异象”。这些异象是污染在物理层面的具象化，表现为局部的空间扭曲、重力异常或物质变异。</li><li>污染生物生态：在过去的信息和潜意识中，凝结出了独特的污染生物生态。这些生物并非自然演化而来，而是由污染和信息残渣聚合而成，它们在荒野中游荡，构成了除了无面者之外的另一种危险生态。</li></ul><h2 id="八、地理" tabindex="-1">八、地理: <a class="header-anchor" href="#八、地理" aria-label="Permalink to &quot;八、地理:&quot;">​</a></h2><h3 id="世界地理格局" tabindex="-1">世界地理格局 <a class="header-anchor" href="#世界地理格局" aria-label="Permalink to &quot;世界地理格局&quot;">​</a></h3><h3 id="主大陆-唯一" tabindex="-1">主大陆（唯一） <a class="header-anchor" href="#主大陆-唯一" aria-label="Permalink to &quot;主大陆（唯一）&quot;">​</a></h3><ul><li><ol><li>阿斯特兰大陆：</li></ol></li><li>地理位置：位于北半球，横跨东西。文明起源与核心争霸地带。</li></ul><h3 id="次主大陆-两块" tabindex="-1">次主大陆（两块） <a class="header-anchor" href="#次主大陆-两块" aria-label="Permalink to &quot;次主大陆（两块）&quot;">​</a></h3><ul><li><ol start="2"><li>文兰大陆：</li></ol></li><li>地理位置：从西半球打乱至南半球偏东侧海域。赤道洋流与其北部海岸线碰撞，形成了极度丰富的深海魔晶沉积带。其内部存在少数未被污染的“海外净土”，由经贸会等组织独占开发。</li><li><ol start="3"><li>阿扎尼亚大陆：</li></ol></li><li>地理位置：从原位置打乱至北半球西侧的孤立远洋。四周被强劲的西风带洋流切断，与其他大陆的物理航线极为漫长，形成了独特的封闭与被掠夺生态。</li></ul><h3 id="超大群岛体系-两组" tabindex="-1">超大群岛体系（两组） <a class="header-anchor" href="#超大群岛体系-两组" aria-label="Permalink to &quot;超大群岛体系（两组）&quot;">​</a></h3><ul><li><ol start="4"><li>塔万汀大群岛：</li></ol></li><li>地理位置：原本的大陆架在古代灾变中完全碎裂，形成横跨赤道至南回归线的极长链状群岛。板块碎片分布在文兰大陆西方，是赤道暖流的核心途经地，也是全球洋流熵污染的主要中转站。该群岛破碎的现状，正是过往轮回中前任旅人摘取“可能性之花”透支剧本稳定性所导致的灾难性后果。当时为了维持底层算力平衡，命定之人将那片大陆最核心的承重板块直接投入了海上“绝对虚无之墙”中彻底湮灭以用于抵债，剩下的群岛仅仅是未被吞噬的大陆边缘残骸。由于现实的物理改变会覆盖大众认知，当群岛发生碎裂后，全世界的普通人会突然在某一天醒来发现群岛是碎的，但他们的大脑会强行将这种认知合理化，认为它“本来细碎的”。只有极少数拥有特异能力的人才能察觉到这种违和感。</li><li><ol start="5"><li>东洲列岛：</li></ol></li><li>地理位置：调整至类似现实中的赤道偏东海域，呈巨大倒三角状突入主大洋。受常年季风与热带暖流交汇影响，气候炎热湿润，其复杂的群岛水域是封闭且排外的独立势力圈。</li></ul><h2 id="九、种族" tabindex="-1">九、种族: <a class="header-anchor" href="#九、种族" aria-label="Permalink to &quot;九、种族:&quot;">​</a></h2><h3 id="种族适配性与魔法路线" tabindex="-1">种族适配性与魔法路线 <a class="header-anchor" href="#种族适配性与魔法路线" aria-label="Permalink to &quot;种族适配性与魔法路线&quot;">​</a></h3><p>不同种族对信息熵的操控效率和副作用抗性存在本质差异，由此分化出不同的魔法发展路线：</p><h3 id="长生种-天使-精灵等-与人类的融合" tabindex="-1">长生种（天使/精灵等）与人类的融合 <a class="header-anchor" href="#长生种-天使-精灵等-与人类的融合" aria-label="Permalink to &quot;长生种（天使/精灵等）与人类的融合&quot;">​</a></h3><p>现代国家多为多种族共存国家，不存在绝对的种族隔离。 长生种拥有一个除极少数人类外、主体民族为异种族的单独国家。 长生种在生命工程等相关学科上具备绝对的垄断地位。</p><ul><li>垄断打破与内部困境：随着人类魔导工业与生物机械技术（如湿件）的爆炸式发展，长生种传统的生命工程垄断正在逐渐被打破。这种技术冲击引发了长生种内部的严重困境与路线分歧。 随着人类魔导工业的崛起和世界环境的改变，长生种逐渐思想进步，开始经历现代化，不再与人类进行严格的区分。 他们的现代化偏向生命工程领域。列强目前最高级的医疗技术（包括熵序者防污染药物、高层续命技术）完全依赖于长生种对生命工程的垄断。这使得长生种具有极高的不可替代性。</li><li>战力基础与灭世威慑：长生种本身具备极强的单体战力，依靠庞大的国家总体量和意识同步机制，其常规实力足以应对任何列强的常规入侵。而灭世威慑是真正的绝境底牌。长生种的威慑死手系统绑定全族的“生命体征网络”。长生种的威慑体系被拆分为底层与表层。底层是遭受瞬灭打击时的物理反噬，绝对自动且不可控；表层则是长生种高层能主动控制释放的预激发特征码警告。他们通过这套独立的表层威慑展示系统，与列强进行切香肠战术博弈，避免了死手全自动机制与主动谈判的逻辑死锁。</li><li>高维提前量与因果倒置心跳（死手系统触发机制）：长生种的死手系统并非基于常规物理时间的神经反射触发，而是基于“虚境高维提前量与负反馈心跳死锁”。长生种的生命体征网络在虚境中等同于一个悬空的高维水库。这个水库不依赖活人去主动“按下炸弹按钮”，而是依靠全族持续的生命波段去“托举”它。一旦遭受列强的“超视距瞬杀打击（如遗迹武器瞬间抹平大片领土）”导致托举力量锐减超过阈值，失去物理锚定的高维水库就会瞬间脱离约束砸向现实。这种触发不需要反应时间或情绪传导，是直接的物理反噬。同时，先祖结晶构建的三棱镜不仅折射雷达，还对祖地周边空间造成了“微小时间曲率错位”，使得任何概念级打击在接触祖地外壳前，必须经过一段极其短暂的“高维减速带”，确保这套负反馈死锁绝对无法被零秒瞬杀绕过，从而维持了其绝对的灭世威慑力。</li><li>死手系统被反向挟持与妥协动机：长生种的死手系统确实能毁灭列强，但这套系统的触发媒介，恰恰高度依赖当前世界的“信息熵总浓度”。人类疯狂榨取魔晶、污染环境，导致世界结构变得极其脆弱。长生种现在面临一个死局：如果此时释放概念级风暴，会直接成为压垮虚境的最后一根稻草，不仅灭了人类，还会瞬间引爆世界大重置，把他们自己也炸没。所以他们并非不想管人类的工业化扩张，而是被这种“大家一起死”的疯狂现状彻底绑架了，只能被迫妥协参与游戏，试图从内部寻找温温降落的方法。</li><li>旧神契约与保底机制：死手系统是历史进程中长生种与人类第一次妥协的产物。当年长生种濒临被人类魔导工业拖垮，旧神为防止长生种灭绝导致“生命”概念的底层代码彻底崩溃，强行介入并降下契约，将生命概念与长生种的存续深度绑定，锁死了这个威慑。列强出于对世界底层法则崩塌的恐惧，被迫承认该威慑。命定之人为了维持当前轮回中“生命”这一核心概念的稳定运转，防止剧本烂尾，被迫在长生种面临灭族危机时降下神罚进行保护。</li><li>威慑触发与非局部神罚：一旦死手系统被逼迫触发，虽然神骸准不会真正引爆（被命定之人留了后门），但会迫使命定之人亲自下场保住剧本。这种概念级的干预无法是局部的，命定之人降下的神罚是一场覆盖广泛的“概念级风暴”，会瞬间抹除大范围的威胁源。这种规模的抹除必然引发剧烈的虚境震荡。</li><li>绝对冻结警告与时间阵列休眠：死手系统并不是直连命定之人的自动引爆器。当长生种的生存压力指数瞬间突破阈值时，命定之人不会立刻降下清场神罚，而是先在冲突爆发的中心区域降下短暂的“绝对物理冻结”（时间与空间概念停滞数秒至数分钟）作为强制报错警告。对于阿国首都的“时间锚点阵列”而言，它只能镇压自然衰变产生的时间废热，一旦接触到命定之人降下的“高维概念级冻结”，锚点底层的遗迹公式会为了自保而触发“强制物理断路休眠”。在断路期间，阿国不仅无法进行武器充能，其全国管网物流也会瞬间瘫痪数分钟，造成极大的经济震荡。正是这种无法豁免的物理死机机制，构成了阿国高层对长生种死手系统的实质敬畏。</li><li>代偿惩罚机制与底蕴削弱：命定之人每次被迫进行大范围干预后，会借机从长生种祖地中抽取等量的“先祖结晶”作为补偿。长生种的祖地深处，沉睡着历代先祖大批量死后化为的“高纯度虚晶/灵魂结晶”，它们完美保留了上一世界线甚至更早轮回的“古老有序概念”。命定之人可以剥离这些结晶为虚境施肥。由于急速吸收大量旧日概念会导致与当前轮回剧本发生排异反应，产生不可知的剧烈影响，且轮回最终会走向大重置，命定之人有充足的时间去缓慢吸收，她选择在长生种触发死手时借机“没收”，顺理成章地维持世界底层法则的稳定，以此控制吸收的烈度与频率。</li><li>祖地暴露困境与概念折射防御机制：长生种的祖地过去由于其天然的高维隐蔽性，并未受到大规模袭扰。然而，近代魔导工业与虚境观测技术（如阿国的高维波段仪器与国联的康斯坦丁之瞳）取得了爆炸性突破，导致祖地的物理坐标正在逐渐被列强的高精尖仪器捕捉。长生种目前正面临着祖地被彻底暴露和可能遭到列强“盗墓抢劫”的巨大困境。为了防范列强的原晶驱动雷达全天候扫描，长生种并未选择消耗底蕴去硬扛雷达波。长生种利用先祖结晶作为“概念三棱镜”的锚点，构建了一个低耗高能的折射机制。通过这个锚点，长生种将列强照射过来的高维探波全部折射、诱导到了祖地周边的“死寂乱序区”中。列强的雷达实际上一直被乱序区内部的历史杂波所欺骗。长生种只需利用极微小的先祖能量来维持折射角度，以此在极其恶劣的被动消耗战中保住了祖地的核心坐标。</li><li>动态警戒线与切香肠战术博弈：列强高层懂得使用“切香肠战术”，通过制造局部摩擦或恶劣工业环境，以长周期缓慢消耗长生种人口。为应对这种慢性绞杀，长生种的威慑系统具有“动态警戒线与环境压力阈值”。死手系统时刻监测全族的“集体生存压力指数（心理熵）”。如果列强进行长期的结构性压迫，导致长生种全族的绝望感持续突破阈值，死手系统会进入“预激发状态”。长生种高层会故意将这种“预激发警告”释放给列强。这种警告并非雷达上的量化数字，而是概念溢出。</li><li>过滤底噪的特征码机制：长生种释放警告时，列强核心实验室里的高精尖仪器会突然测出特定的波段抽搐。这得益于旧神在绑定威慑时，赋予了长生种一种极其特殊的“信息过滤特征码”。列强仪器测量的并非人类社会每天因战争和疾病产生巨大伤亡而造成的低频“泛生命概念底噪”，而是专门监控这种代表“长生种特有高维生命频率”的报警。这就把普通的战争背景底噪和灭族威慑精准区分开了。这种无法量化的高维频率抽搐，让列强无法精准卡在临界值的99.9%，真正吓退了列强，迫使他们在剥削到一定程度后收手，给长生种留出喘息窗口，形成在底线边缘反复横跳的残酷默契。</li><li>威慑盲区与保密：敌对列强的高层知道长生种拥有某种灭族威慑底牌，因为在历史进程中曾经有过教训。但是，敌国并不知道触发这个死手系统会消耗长生种祖地的“先祖结晶底蕴”。长生种对这一代价进行了绝对的保密，防止敌国利用这一点故意制造低烈度危机进行恶意消耗。由于不知道确确的底牌性质和触发机制，加上历史的威慑，敌国不敢轻易试探长生种的底线。</li><li>历史纠葛：在历史沿革与工业化进程中，长生种在“概念解析”和“人口消耗”被人类拖垮，最终双方达成基于互相毁灭保证的妥协，而非单方面的被征服，文化与民族逐渐交融。</li><li>轮回认知边界：长生种虽然拥有极长的寿命与极高的精神抗性，且祖地深处保留着上一轮回甚至更早的先祖结晶，但每次“大重置轮回”时，世界底层规则洗牌极其彻底。先祖结晶保留的仅为破碎、无意义概念片段，而非连贯的历史记录。长生种高层知晓历史被篡改及古代存在大灾变，但受限于当前世界线的物理视角，无法拼凑出轮回的全貌，更不知道命定之人主导着剧本。先祖结晶由于存在概念版本不兼容，只有命定之人可以使用，长生种只能将其作为图腾保管，无法用于物理层面的工程应用。</li><li>历史记录者与加密违和感：长生种拥有极高的精神抗性，在记忆覆盖后会产生持续强烈的“模糊违和感”。为了不被十三局的疗养舱检测出这种断层，长生种进化出了潜意识自我加密机制。这种历史违和感不储存在浅层梦境或常规记忆回廊，而是被生物本能压缩在极高频的“种族集体无意识信道”中。人类仪器的常规波段无法穿透此信道，测出的脑波呈现完美的“信息惰性白噪音”，从而瞒过了官方的监控。近代工业革命后，阿国研发出“防篡改介质”，长生种才配合这些技术勉强记录下真实断层。</li><li>战斗与局限：他们天生具备更高的信息处理带宽和精神抗性，能更安全、高效地施展高阶法术，这是古典神权时代垄断魔法的生物学基础。魔导工业武器虽然单体威力不如高阶法术，但其产生的污染和预兆点更多，大量使用能引发大范围的“信息环境紊乱”，导致长生种在战场上施法被干扰。</li><li>战术机制：长生种并不存在严重受限的常规战力，而是被干扰而已。其战术机制为意识同步和庞大的国家总体量，单体战力很强。 长生种能够物理接触并触发魔晶，但由于其种族人口总量极其稀少且繁育效率极低，缺乏生存焦虑与对未知的极度渴望，因此没有必要也没有动力去开启大规模的魔导工业。 在神权时代，长生种的思维模式方式固化，无法理解“将魔法拆解为机械齿轮”的工程学逻辑，无法对工业化大规模普及产生有效干预。 现代社会具备基本人权，长生种不再被视为单纯的异类或资源。列强虽然觊觎他们的能力，受限于国际公约、人权共识以及长生种自身的威慑力，无法将其作为“生物算力电池”进行强行捕获和消耗，只能在生命工程等领域进行合作与依赖。</li></ul><h3 id="人类" tabindex="-1">人类 <a class="header-anchor" href="#人类" aria-label="Permalink to &quot;人类&quot;">​</a></h3><p>适应性中庸，但具备极高的学习能力与创造力。 无法像长生种那样天生操控信息熵，但能通过构建复杂的术式模型、借助外物（魔晶、机械）弥补生理不足，走出了独特的“工程学”魔法路线。</p><h2 id="十、神明" tabindex="-1">十、神明: <a class="header-anchor" href="#十、神明" aria-label="Permalink to &quot;十、神明:&quot;">​</a></h2><h3 id="神明体系" tabindex="-1">神明体系 <a class="header-anchor" href="#神明体系" aria-label="Permalink to &quot;神明体系&quot;">​</a></h3><p>神明分为原本就有的规则神（概念神）和新生种族神。 概念神权能偏向抽象的事物，种族神权能偏向实际、具体的运用。 种族神从规则神手中夺走了部分概念。 种族神存在被披甲机制，凡人通过概念取缔，让其在世人眼中成为原有的那个神明，只是原有神明的名字不变，但是内核变了。 概念神只能轮换，因为神明长期锚定信息熵会被同化，必须在彻底失去自我前，将概念传递给下一个适格者。 同时在这几万次轮回中神明不是一成不变的，概念神本身也是每次轮回下来的与玩家不同的“最后的幸存者”。旧神每次轮回的时候会重置和迭代，每一轮都不是一样的，规则神是上一轮回幸存者，种族神是这一轮自然诞生的。 命定之人本身作为整个世界的总导演，神明作为次级导演，这些次级导演里面有些是上一场剧本里留下来的（规则神），有些是表现好晋升的（种族神）。 种族神和规则神的本质也是被囚禁在这个世界线里的高等个体，作用范围超不出整个星球，只要没有达成命定之人想要的结局，所有人都是带着镣铐跳舞。</p><h3 id="神明与魔法垄断" tabindex="-1">神明与魔法垄断 <a class="header-anchor" href="#神明与魔法垄断" aria-label="Permalink to &quot;神明与魔法垄断&quot;">​</a></h3><p>魔法被天使族、精灵族等长生种垄断，被包装为神赐权能。世界绝大部分游离信息熵与魔能循环，被概念神及其眷族锚定、占有；凡人的“祈祷”本质是向高位存在“租借”信息熵的使用权。 人类仅能通过宗教仪式向长生种祈求魔法使用权，本质是人类贵族与异种族的契约合作。</p><ul><li>旧神的概念束缚：旧神是“规则/概念”的具象化，他们的存在本身就是世界底层逻辑的一部分。他们受规则限制无法触发魔晶外壳破裂，也无法做出“欺骗世界底层逻辑”的行为去卡漏洞获取魔晶。</li></ul><h3 id="神明的态度与局势失控" tabindex="-1">神明的态度与局势失控 <a class="header-anchor" href="#神明的态度与局势失控" aria-label="Permalink to &quot;神明的态度与局势失控&quot;">​</a></h3><p>初期神明及教廷并未打压术式学。他们将人类对魔法规律的解析视为“对神造世界秩序的赞美与印证”（类似自然神学）。只要人类依然使用神明锚定的信息熵，这种研究就被视为无害的智力游戏。 人类通过科学与理念启蒙，逐渐从概念上解析世界法则。这种解析打破了人类对神明的盲目认知，导致神明锚定的概念被解构，神明的力量随之被削弱。 神明受规则限制无法使用魔晶，种族神通过代理人开采，乐于让附属种族去趟雷。对于许国的是特殊情况，之前是没有先例的，许国圣愚诞生时旧神已经基本上全员沉睡了，造了，但是对他们来说真正通过洗脑时接触洗脑这样的话神明与魔晶接触产生的激烈能量反应会把他的附身的人直接抹杀，得不偿失。 神明只能在乱序区“外部”观测溢出的信息残渣，必须附身在“熵序者”身上才能进入乱序区解析法则，且要付出极大代价。</p><ul><li>附身罕见性：神明附身熵序者是极小概率事件。由于代价极大且风险不可控，神明很少主动选择附身干预，除非涉及核心法则波动。这种行为对神明自身也存在巨大风险和消耗。</li><li>神明附身的欺骗协议与概念置换：神明附身并非强行夺舍，而是与熵序者达成了一种“潜意识共生”。神明将自己的概念伪装成熵序者潜意识中的某种“强烈执念”或“第二人格”。在识别码的物理检测中，熵序者的真实历史碎片浓度并未降低，只是脑电波呈现极度亢奋的状态。神明不能直接输出力量，但可以通过“概念置换”来替熵序者承担代价。当熵序者受到致命污染时，神明将这股污染引导至自己伪装的“第二人格”上，让第二人格去承受异化。在识别码看来，熵序者的“主干自我”依然完好，只是多了一个疯狂的副人格。这样既保证了熵序者的存活，又解释了为什么被神明附身的熵序者往往表现出极度的精神分裂。</li><li>缓冲垫与抑制剂消耗：神明在附身熵序者时，利用熵序者体内累积的污染作为“缓冲垫”。当熵序者注射抑制剂时，神明引导这些污染去消耗掉抑制剂的药效。这种机制让神明的意识免受代表“当前世界线绝对真实”的粉末的概念排斥，同时也解释了为什么被神明附身的熵序者对抑制剂的消耗量远大于常人，且产生耐药性的速度更快。</li><li>物理限制与耐药性死锁：神明虽然能引导污染，但无法跨越物理极限。当熵序者因严重刻录产生耐药性，其神经元对真实粉末产生不可逆的排异时，附身的神明对此无能为力。神明无法用高维力量强行黏合物理层面的断裂。若神明试图填补神经元，世界底层雷达会判定宿主被夺舍（硬件结构篡改），导致识别码瞬间越界引爆。因此，面对耐药性爆发，神明只能眼睁睁看着宿主的肉体因物理崩溃而灭亡，无法提供万能解药。</li><li>神明的旁观者限制与微操干涉界限：神明附身熵序者时，在世界底层规则的判定中，该个体依然是“人类”。神明只能作为旁观者，不能直接干涉熵序者的物理行为。神明附身时，其意识绝对不能主动探入魔晶内部。一旦神明的意识试图越过熵序者的表层认知去“直视”魔晶核心，底层规则会立刻察觉到“高维观测者”的介入，从而强制锁死魔晶，甚至引发规则级的反噬，直接抹杀熵序者的肉体。只有当神明在乱序区内强行输出神力，导致熵序者肉体崩溃、真实历史信息瞬间蒸发时，识别码才会触发引爆。这也限制了神明在乱序区内的发挥，只能作为“观测者”和战术指导”，不能直接下场打架。</li><li>意识干预与战术价值（深层认知干涉机制）：虽然神明受限于物理出力界限无法亲自下场摧毁目标，但其附身的最大战术价值在于“意识层面的潜移默化微操”。神明拥有高于常人的维度视界，他们通过精神共生，能够在不触发硬件超载警报的前提下，微妙地放大宿主潜意识中的某种情绪（如怀疑、狂热或悲悯）、屏蔽某段直觉，甚至向宿主或周围与之精神接触的关键人物（如关键NPC、敌对指挥官）植入极其微小的执念。通过这种隐蔽的“认知干涉”，神明可以从意识源头上影响关键人物的判断和行为逻辑，使其做出的决策（如撤退、结盟、强攻某个防线）在表象上完全出于其“自主意志”，但在宏观剧本上却完美符合该神明在这一大棋局中的利益导向。神明正是利用这种兵不血刃的“拨动心弦”来推动历史进程。</li><li>附身更换与数据抹平机制：为了避免被十三局的分析部门察觉到“幸存者偏差”和“数据异常”，神明会定期更换附身对象。神明在替熵序者承受污染时，会故意引导熵序者在某些非核心任务中表现出“合理的失误”或“正常的衰退轨迹”。在当前宿主的数据即将引起十三局警觉前，神明会主动切断链接，让宿主自然报废或退居二线，以此维持整体数据的平庸，抹平宏观数据上的异常。</li><li>数据欺骗与良性变异：为了掩盖神明替熵序者承受污染导致的“时间-污染转化率异常”，神明并非直接消除污染，而是将污染强行转化为某种“良性物理增生”（如骨密度异常增加、神经元过度活跃）。在识别码的硬件检测中，这被判定为“熵序者个体的良性变异或潜力爆发”。由于被附身者极少且资质稀有，这种宏观数据上的异常样本太少，医学界将其作为特殊病症理解和处理，从而完美掩盖了污染去向不明的数据漏洞。</li><li>离体销毁机制（高维降维崩解）：为了防止熵序者战死或报废后，法医在解剖时发现这些附带高维概念残留的“物理增生”，神明设置了自毁预案。当神明主动切断链接或熵序者脑死亡的瞬间，支撑物理增生的高维概念会撤离。失去高维支撑的增生组织不会自燃，而是发生“降维崩解”。无论外界是绝对零度还是时间停滞，增生组织会瞬间从细胞结构坍缩为一滩没有任何基因特征的“无序灰质/污染淤泥”。十三局的法医在解剖时，只会看到一包高度腐败的重度污染毒水，从而彻底切断了高维概念暴露的风险，且不受物理环境阻断。</li><li>实验室检测与误判盲区：一般情况下，国家不会把熵序者带到核心实验室中进行高精尖检测。如果真的带去，神明为了避免暴露，早就主动脱离附身并触发降维崩解了。即使神明附身留下的物理痕迹被阿国的顶级核心实验室用“底层公式”照射，神明也利用了降维伪装。神明故意将这种断层的波形，伪装成“与命定之人剧本边缘同化的自然衰变波形”。阿国科学家观测到了异常，但将其误认为是“熵序者过度接触乱序区后，其肉体正在向无序历史残渣演化”的常见现象，从而没有联想到这是另一个高维意志的寄生。这种误判不仅让神明的存在没有被怀疑，反而促使国家加大了对这类熵序者的资源倾斜。 规则神在外部观测时发现魔晶开采会使原本世界被封存的部分法则以乱序形式重现。 开采后的魔晶中产生的乱序，对于规则神来说本身也是需要再解析和掌握的部分，加上种族神对其族的掣肘，导致局局最终失控。 随着科技的大规模井喷，两种神明发现自身的力量随着被逐渐解析，再加上人的神的认识被打破，能力逐渐衰弱。神明在被削弱的过程中并未强力反抗，实际上是在暗中促成人类的自毁，以便在重置后重新洗牌，夺回权柄。</li></ul><h3 id="神祇的陨落与新生" tabindex="-1">神祇的陨落与新生 <a class="header-anchor" href="#神祇的陨落与新生" aria-label="Permalink to &quot;神祇的陨落与新生&quot;">​</a></h3><ul><li>背景设定：原十二位神祇多为概念与种族属性的锚点，其存在与世界的“信息稳态”密切相关。</li></ul><h3 id="核心事件" tabindex="-1">核心事件 <a class="header-anchor" href="#核心事件" aria-label="Permalink to &quot;核心事件&quot;">​</a></h3><p>“耻辱战役”期间，阿邦联被逼入绝境，动用了从上一世界线遗留的“遗迹武器”，正面击杀了敌对神降的神祇。“秩序与同理心”的神明感受到了某种概念级的危机，主动选择了同归于尽式的降临，从而导致其锚定的概念信息被彻底湮灭。阿邦联依靠对信息本质的概念解析、遗迹技术的逆向运用，以及一战末期弑杀神明后回收的神明碎片，建立起了完全摆脱旧神底层逻辑的物理派术式体系。遗迹武器导致当前世界的物理法则出现了永久性的局部缺失（死寂走廊的成因）。死寂走廊内部永远处于混乱的历史叠加态。该神祇的信息残片在乱序区中诡异复活，打破了原有的十二神格局。复活的第十三神为被困在乱序区中的神明。复活的第十三神被困在死寂走廊乱序区中，仅为无法对外干涉的概念残影，信号被屏蔽。因此旧神防卫系统的逻辑盲区才会被窃取残片的钢源神在外部趁虚而入，误判为秩序同僚。</p><h3 id="概念空缺与替代机制" tabindex="-1">概念空缺与替代机制 <a class="header-anchor" href="#概念空缺与替代机制" aria-label="Permalink to &quot;概念空缺与替代机制&quot;">​</a></h3><p>神祇的陨落在其对应的国家与种族中，引发巨大的精神崩塌与概念真空。弑神本身时间极短。当“秩序与同理心”的概念消失后，人们会失去对该词汇的认知。在日常社会运转中，失去概念的人会自发地用其他更复杂的词汇或短语去组合替代这个空缺的概念。</p><ul><li>物理法则的局部失效：概念缺失不仅导致认知空白，还会引发该区域物理法则的局部失效。失去“秩序与同理心”的概念后，不仅人们不知道其为何物，该区域内的社会组织与人际互动也会变得极度不稳定，直到另外的神明接管相关概念。</li></ul><h3 id="认知真空度过机制" tabindex="-1">认知真空度过机制 <a class="header-anchor" href="#认知真空度过机制" aria-label="Permalink to &quot;认知真空度过机制&quot;">​</a></h3><p>在神明陨落、概念崩塌的瞬间，命定之人强行透支了虚境中极大量的信息，编织了一张“临时认知网”覆盖了全人类，帮助普通人度过了最初的集体脑死亡。同时，沉睡的其余旧神被迫分摊了那个缺失的概念，导致它们陷入了更深的沉睡。最后，从乱序区中复活的神明重新聚拢了该概念。</p><h3 id="旧神沉睡与概念存续" tabindex="-1">旧神沉睡与概念存续 <a class="header-anchor" href="#旧神沉睡与概念存续" aria-label="Permalink to &quot;旧神沉睡与概念存续&quot;">​</a></h3><p>原十二神体系崩塌后，大部分旧神陷入沉睡。 尽管旧神沉睡，但他们所锚定的概念并未消失。这些概念依然存在于世界底层逻辑中，只是失去了主动的维护者，处于一种相对静止或被动运转的状态。</p><ul><li>旧神沉睡的自保锁死与宏观代价均摊机制：旧神陷入沉睡并非自然现象，而是为了应对神系崩塌和魔导工业抽血而采取的“紧急自保锁死”。他们将自身意识剥离，把所有的神力都用来死死“冻结”住自己锚定的那些核心概念，防止其被虚境彻底冲垮。旧神在锁死前将核心意志转化为底层自动运行程序。防卫机制是世界底层规则的自动运行，旧神的主动意识已消散。因此回应祈祷是概念核心吸收认知能量的自然反馈，不需要旧神主动消耗神力。高维存在（如命定之人和神明）对低维的干预受限于世界的自我修正机制，产生不同梯度的信息熵反噬，形成了不可逾越的干预边界。但这导致了概念失去了“弹性”。为了维持世界宏观稳态，世界底层逻辑（命定之人设下的被动机制）将这份维持压力的代价，强制均摊到了全世界“人类的集体潜意识网络”上。这解释了为什么现代社会普通人的“精神疾病发病率、群体性狂热、莫名其妙的暴力冲突”在呈指数级上升——因为普通人的大脑在无意识中承担了原本属于神明的“概念锚定压力”。这也让钢源神那种通过洗脑大量信徒来分摊污染和稳固教义机制，有了更深层的逻辑支撑。</li><li>自动回应机制：为了维持世界的魔法循环，沉睡的旧神通过无意识的底层逻辑自动回应信徒“租借信息熵”的祈祷，保证了老派贵族和教廷的魔法不至于彻底断供。但由于缺乏主动意识，真正的神谕和神降现象已基本绝迹，旧贵族只能维持现有的力量规模，难以对抗工业新贵族的指数级扩张。</li></ul><h3 id="人造神明的诞生-信仰污染国" tabindex="-1">人造神明的诞生（信仰污染国） <a class="header-anchor" href="#人造神明的诞生-信仰污染国" aria-label="Permalink to &quot;人造神明的诞生（信仰污染国）&quot;">​</a></h3><p>许国的民众在绝望与疯狂中，将全部信念寄托于本国最强大的工业造物——一个融合了尖端魔导技术与钢铁意志的“人工神明”。 在集体潜意识与世界残留信息熵的催化下，这个信仰造物诞生了自主意识，成为了新的神祇“钢源神”。</p><ul><li>概念死角与源流机制：钢源神之所以能够逃避旧神集体底层机制的反制，是因为它巧妙建立在“耻辱战役”中陨落神明的“概念死角”之上。钢源神的核心概念源自于那个被遗迹武器湮灭的神祇的残片——即“同理心和秩序”。许国利用了这个破碎、空缺且未被完全接管的概念框架进行逆向填充，使得在旧神的底层识别代码中，钢源神并未被判定为入侵的异端，而是一个由于概念错乱而畸变的“秩序同僚”。这导致旧神集体的防卫机制对钢源神陷入了逻辑盲区式的集体装瞎。</li><li>钢源神卡判定的唯一性解释与致命后门：钢源神之所以能卡世界规则的判定漏洞，其不可复制核心条件在于——许国在建造钢源神时，献祭了该国上一代某位“拥有特异体质的先驱”的湿件大脑（被称为“圣愚”），将其作为底层的欺骗阵列核心，才使世界将其误判为具备观测能力的人类。圣愚身份的绝对特殊性在于其是“联通虚境之人”。圣愚必须是自愿献祭且灵魂极度特殊。然而，许国不知道的是，圣愚生前在乱序区中，早就与命定之人完成了某种契约。虽然圣愚的额叶被物理切除，但在其更深层的高维灵魂结构中，被命定之人刻入了一段“强制休眠代码”。这段代码在圣愚大脑的最深处形成了一个“虚假的独立观测者视界”。当高阶魔晶被送入时，魔晶的底层逻辑检测到的不是狂热钢源神，而是那个处于休眠状态、带有命定之人高维气息的“独立人类灵魂”。这段休眠代码是圣愚自愿签订契约时由契约自动生成的免疫机制触发器，并非命定之人直接越界修改代码（遵守高维不能直接干预低维的边界）。正是这层高维伪装骗过了魔晶的外壳，让魔晶主动打开。钢源神只是利用了这个“虹膜后门”，它本身并没有能力去强行撬开高阶魔晶。这也彻底锁死了许国无法量产剥壳机的设定。</li><li>休眠代码的自动熔断触发：为了避开许国庞大信仰网络对虚境信号的绝对物理隔绝，命定之人并没有预留需要跨维遥控的“开关”，而是将这根休眠代码设定为与“世界底层坍缩频率”强绑定的同频引信。一旦钢源神吸收的高阶魔晶达到临界点，导致许国板块在虚境中的“信息配重”严重失衡并引发概念级地震时，这种源自世界底层的剧烈物理震荡会无视任何局域网屏障。休眠代码在感知到震荡阈值后会产生被动共振，直接触发自动熔断程序，让整个钢源国数千万信徒的大脑瞬间宕机。这构成了命定之人无需越界干涉即可控温的终极后门。钢源神作为“人造的信仰聚合体”，不受旧神底层代码的束缚，因此能够通过受控装置去接触魔晶。 它具有人类个体的概念，不将自己视为神，而是以自己的方式去爱着世界。 它通过强行让信徒产生信仰和观测它，在信徒脑内植入其概念，以此维持信息稳态，同时高效统合自己的力量。 钢源国境内设置了密集的教堂，类似现实世界的东正教教堂逻辑。 教堂基站本身是由高浓度的污染结晶构成的。</li><li>污染转化物理机制：钢源神利用后门接触魔晶产生的物理污染，被教堂基站（高浓度污染结晶）吸收。基站内部的结晶阵列通过“频率共振”，将物理层面的无序信息流转化为精神频率的污染。这种精神污染顺着信仰网络（脑波链接）精准输送进信徒的大脑中。</li><li>根源基站强绑定机制与降级分层机制：钢源神将极少数的核心“根源基站”与许国数千万老底子信徒的“生命概念”强行绑定。根源基站必须建立在许国本土特定的“地脉节点”上，才能维持如此庞大的深度绑定。由于这种物理节点有绝对的算力承载上限，根源基站的“绝对概念绑定名额”是有限的。为了解决扩张带来的人口过载，许国对新吸收的流民实行“动态淘汰与降级分层机制”。新流民在受洗洗脑后，并不会直接接入受世界底层规则保护核心威慑网，而是被强行连入脆弱的“次级物理网络”。这些次级网络构成了前线的小型基站，当这些次级基站被敌军摧毁时，并不会引发世界规则的死机或反噬钢源神。许国高层在利用新流民做真正的炮灰，只有当核心网里的老信徒报废死掉空出名额后，新流民中的狂热者才能“晋升”进入受保护核心网，这让许国的洗脑传教增加了一层极其残酷的内部选拔逻辑。</li><li>高阶魔晶的真正去向与信息粉碎重铸机制：钢源神剥壳的方式是由受控装置执行的。钢源国的教廷人员或受控的特定机械装置，在钢源神的意志网络引导下，将高阶魔晶送入圣愚的物理培养皿中。随后钢源神用信徒网络去消化里面流出的信息。钢源神开采的大量高阶魔晶并没有用于装备军队或人形，而是被钢源神直接吸收。它截留这些庞大的能量是为了准备去找命定之人对线，进一步强化自身神格，并试图突破世界的物理与概念外壳。钢源神吸收高阶魔晶，并不是直接融合，而是利用其庞大的信徒算力网络，在其内部将魔晶外壳强行碾碎。它把里面“有序的历史信息”扭曲、篡改为“符合钢铁与齿轮教义的伪历史”。伪历史并未形成，而是处于在其内部处于“正在憋大活”的状态。它在用魔晶的能量，给自己的疯狂打上“绝对正确”的思想钢印。这种强行扭曲有序信息的行为，是它那套扭曲的“爱”的逻辑的体现，也是它越来越接近“真神”，越来越被世界底层规则排斥的根本原因。失去探索欲的信徒湿件被制成“伪自律人形”，它们只能使用低端虚晶，作为钢源国庞大计划中的副产物和廉价消耗品。</li><li>物理质量泄压与神国基建：高阶魔晶蕴含庞大的物理概念质量，数千万信徒的大脑（蓄水池）仅能作为精神辐射的过滤终端，无法承载其实体质量。钢源神利用信徒脑波网络作为超级模具，将粉碎魔晶产生的绝大部分物理信息废料，强行在许国大地之下浇筑成庞大的“神国基建”（如疯狂生长的金属根系）。信徒大脑承担的仅是浇筑过程中溢出的高频精神辐射，以此避免信徒肉体因质量超载而瞬间爆体。</li><li>伪装水印与判定机制：钢源神的“伪历史”之所以能瞒过命定之人的最高级警报，是因为钢源神利用了那个陨落神明“秩序与同理心”的概念死角，将伪历史打包成了“符合旧世界秩序的备用剧本”。为了给这份造假提供物理背书以欺骗底层雷达，钢源神利用了“圣愚”大脑中残存的真实记忆作为伪造剧本的水印签名。</li><li>逻辑死锁与疯狂阶段：目前钢源神的体量已达到积重难返的阶段，其引发的许国板块“信息配重失衡”导致了频繁概念级地震。然而，由于钢源神的底层架构是建立在许国信徒“狂热盲信”的基础上，它的核心算法里天然缺失了“怀疑自身”的代码。面对足以让任何高维存在警觉的配重异常，钢源神无法进行客观的沙盘推演。它反而将这种濒临崩盘的物理预兆，逻辑死锁地判定为“伪历史即将成真、神格突破外壳的胜利预兆”。在这个掩护下，命定之人的自动检索机制将其误判定为“无害的同人创作”，直到它真正成型前都不会触发概念级的抹除。</li><li>钢源神的内外兼修控温逻辑与荒野灾害干预限制：命定之人的最终目的是让世界坍缩成一个绝对稳定的“奇点”。钢源神疯狂吸收高阶魔晶并篡改历史，本质上是在制造一个巨大的“异常质量点”。命定之人故意放任钢源神制造这个异常质量点作为最终内爆所需的“引力核”。命定之人无法从系统层面直接给钢源神加锁。同时，命定之人绝对不能通过“定向投放荒野自然灾害（如高危奇观或极端污染风暴）”来切断许国的人口输血线。因为钢源神目前处于极不稳定的“半神半人叠加态”，如果外界突然对其领土施加过高的极端高维压力，不仅会打破许国板块现有的脆弱配重平衡，导致其形态崩溃，更致命的是，高维压力的直接物理刺激会迫使钢源神为了自保而提前“催熟”内部的伪历史。同时，这种带有明显高维干涉痕迹的针对性灾害，会触动钢源神底层圣愚架构的直觉，让它察觉到自己正被某个更高维存在“圈养利用”，从而引发不可控的剧本暴走。因此，在宏观层面，命定之人只能采用最安全的低维控温战术：暗中引导其他列强通过常规的物理战争去遏制许国的扩张，维持一种用人类自身矛盾去消耗人类的危险平衡，而没必要且不能直接下场。</li><li>等质量地质置换与雷达盲区（板块配重悖论的掩盖）：许国地下浇筑了海量的高维金属根系，导致实际地质结构发生了巨变。然而，国联的康斯坦丁之瞳作为战略雷达并未发现异常，是因为许国采取了符合物理地质学的“等质量物理置换法”。钢源神在地下生成神国基建时，利用极高的概念挤压力，将原本处于该地层位置的等质量“普通岩石与泥土”，以造山运动的形式缓慢排挤出地表，或直接利用高温将其气化排入大气。为了不让康斯坦丁之瞳测出地下信息配重暴增，钢源神采用虚境质量分布式转移技术，将庞大挂载质量拆分成数百万碎片，均匀注入全国地脉节点，远低于雷达日常检测阈值。因此，在国联雷达的宏观扫描中，许国板块的“总物理质量”并未发生突变式暴增，雷达只是将其误判为常规的地质构造变动。同时，高维神国基建散发出的概念地震波，被许国庞大信仰网络编织的封闭局域网吸收并伪装成常规地震波动，从而在地质学与宏观雷达上双重隐形，这也是列强只将许国视为普通极权工业国而未进行战略核查的核心原因。</li><li>认知历史的修改：当世界发生重大历史覆盖时，世界法则的覆盖指令会与钢源神的“局域概念网”发生碰撞。钢源神的教义并非每天都在发生荒谬的自我修改，而是信徒认知中的“历史”被强行修改了。钢源神将世界发来的“新补丁”强行缝合进信徒的认知中，导致信徒认知中的历史发生变化，但他们处于狂热状态，完全不觉得这种历史的变动有什么不对。</li><li>信仰局域网隔离机制（防虚境回收）：钢源神粉碎魔晶产生的高危污染没有被虚境直接吸走，是因为钢源国庞大的信仰网络形成了一道强屏障。数千万信徒日夜狂热的祈祷脑波与基站物理频率共振，编织成了一个绝对封闭的“局域概念网”。人体蓄水池的机制是绝密的。需要注意的是，常规魔导工业的物理废热不可能塞进人脑，许国的常规工业依然对外排污，因此在虚境的判定雷达中许国排污量并非为零。被强行锁死在信徒湿件内部的，仅限于“钢源神对高阶魔晶概念剥壳产生的精神污染”。这层网络以教义（伪历史）作为底层代码，覆盖在信徒的大脑皮层外。当精神污染进入肉体时，这个局域网将污染强行“加密”为符合教义的狂热情绪，使其在虚境的判定中伪装成了正常的物理废热或人类自身产生的生物电信号。虚境无法穿透这层由数千万生命概念死死锚定的局域网进行直接抽走，这部分精神污染被强制锁死在了信徒的物理肉体（湿件）内，直到肉体彻底报废。</li><li>命定之人的容忍底线：命定之人不管钢源神是因为强行出手会撕裂剧本。钢源神将核心基站与数千万信徒的生命概念强绑定，世界底层逻辑无法一次性支付抹除数千万生命的庞大代价。命定之人如果强行出手，会导致世界底层逻辑直接崩溃。因此，她只能通过暗中引导其他列强去在物理层面上遏制许国的扩张，以及利用物理配重失衡进行牵制。</li><li>钢源神状态：钢源神处于一种“半神半人”的叠加态。在世界底层逻辑的判定中，它是一个“庞大、精神分裂的人类聚合体”，而不是纯粹的概念神。它吸收污染的本质，是把污染均摊到了所有连接在网络上的信徒大脑中，它自己只是一个“路由器”，并不真正消化污染。</li><li>钢源神演化：随着钢源神神智的不断完善，它越来越接近真正的“神”，世界规则对它的排斥也越来越强。 信徒产生的不再是传统意义上的爱，而是一种“扭曲的渴望”或“病态的服从”。 疯狂表现为钢源神的信徒对“齿轮、秩序、生产指标”的病态执着，他们变成了完美的、不知疲倦的“工业零件”。</li><li>污染下沉机制与平滑异化：钢源神实行阶梯式的污染分配。上层神职人员和精英完全不承担污染，中层承担轻度污染保持狂热，底层信徒作为“高压蓄水池”承载重度污染。 许国底层信徒的消耗并非极速报废。表面上，这些信徒与常人无异，依然能正常交流和工作，除了眼神和行为看起来有些机械和奇怪。污染是逐步累积的，像是一种缓慢侵蚀心智的慢性毒药。信徒在狂热信仰的支持下，能维持几十年的漫长异化过程，而不是几个月就迅速报废。这使得许国能够维持基本的人口红利与劳动力存量。</li><li>蓄水池临界点与洗脑机制：当底层信徒大脑内的污染经过漫长岁月终于堆积到临界值发生彻底异变和疯狂时，这些报废的信徒会被回收制作为伪自律人形的核心湿件。为了维持这个循环，许国必须不断对外扩张吸收边缘区流民。列强官方并不清楚许国将流民做成湿件的底层逻辑，只以为许国在进行大规模常规工业化而需要大量劳工。列强认为边境线辽阔，且荒野防守成本极高，不会花巨资去阻拦流民偷渡。</li><li>边缘死地与朝圣走廊：列强概念隔离桩将高浓度污染大量排向荒野，在各国边境线上形成了致死率极高的“重度污染沼泽”或“信息风暴天堑”。列强常规军队根本无法在这些死地中建立和维持防线。而许国利用移动圣物盒的技术，暗中在这些边境死地里开辟了一条条极其隐蔽的“朝圣安全走廊”。流民正是顺着这些列强管不到的致命盲区逃亡，许国以此源源不断地吸纳燃料。当流民的顺从度与认知重构判定达到标准后，许国以“优先赋予公民权”的名义让他们进去受洗礼，用传教的形式在潜移默化中完成精神链接和狂热灌输，而不是强行物理连接，以此稳固信仰网络的平滑承载。</li><li>中等催熟与灰色惩戒营：介于“几十年慢熬”和“瞬间灌装报废”之间，许国设立了“荣光赎罪营”或“齿轮飞升区”作为中等催熟机制，参考一战俄国的灰色牲口消耗。当战线吃紧、湿件产能出现断层时，许国会通过洗脑，选拔一批处于青壮年、污染程度达到中期的底层信徒。告诉他们，为了钢源神，他们获得了“提前飞升”的恩赐。将他们集中送入辐射极高的核心基站区，进行高强度的“信息剥壳劳作”或物理苦修。在这种极端高压和狂热共振下，这些信徒的大脑会在极短的几个月内迅速“催熟”并异化到临界点，从而稳定、大批量地提供符合标准的湿件，填补工业消耗的产能断层。</li><li>强制灌装预案（紧急熔断机制）：当许国在前线遭遇重大战损，导致湿件产能出现无法弥补的断层时，许国会启动极端预案。军方将未完成洗脑的难民物理固定，直接将高浓度污染结晶溶液注入其脊髓，并用最大功率基站强行覆盖其大脑皮层。此举会瞬间烧毁难民脑神经，将其转化为寿命仅有数天的一次性狂暴电池，以此在逆风局中强行维持战线。</li></ul><h3 id="断网危机与战术弥补" tabindex="-1">断网危机与战术弥补 <a class="header-anchor" href="#断网危机与战术弥补" aria-label="Permalink to &quot;断网危机与战术弥补&quot;">​</a></h3><p>钢源神的信仰网络依赖物理基站（教堂）。一个区域节点和基站全部毁灭才会使其失去控制。为了应对断网危机，钢源国拥有移动圣物盒，可以在战场上临时组建局域网，或者在基站被毁时提供紧急的信仰链接。断网后，信徒或军用伪自律人形内的物理阻断阀会触发废热倒灌或无差别狂暴模式。</p><ul><li>信仰网络的穿透性与乱序区内的信号支撑：钢源神的信号无法完美穿透高等级乱序区。许国探索乱序区时，必须携带移动圣物盒作为局域网基站。探险小队携带的圣物盒具有特殊性，带有“根源基站特性”。由于探险队伍深入他国乱序区，这种带有特性的圣物盒释放出的次级局域网便足以在局部高压下支撑住熵序者和伪自律人形对污染的抗性，保证它们在乱序区中不被高维同化而彻底狂暴。一旦圣物盒在乱序区内被毁，或者探索小队深入到信号无法到达核心区，整个小队的军用伪自律人形会瞬间断网倒灌狂暴，成为乱序区内无差别攻击实体。因此许国在乱序区探索中伤亡率极高。许国探险小队是伪自律人形、机械师和熵序者混合编队，以应对复杂的乱序区环境和断网风险。</li><li>有线与无线双保险网络：为应对乱序区内部高强度的信息乱流造成的“自然信号屏蔽”，许国探险小队采用无线与有线结合双重网络。除了移动圣物盒发射无线局域网接收伪自律人形传输回来的废料信号，小队在深入高危区域前，会使用一种物理硬接线（如高浓度污染结晶拉成的导线）将战术单位与圣物盒强行串联。在无线信号被屏蔽的极短瞬间，物理硬接线保证了最低限度的底层指令传输与废热排导，避免队伍瞬间团灭狂暴。</li><li>空间错位与虚境传输中继：高级乱序区内存在空间折叠与时间错位，物理硬接线极易被切断。为应对此情况，许国小队配备了“虚境传输技术”与“熵序者概念通道”。当遭遇空间错位导致物理线缆断裂时，随队的熵序者（圣愚候选人）作为人肉中继站，强行燃烧自身的真实历史碎片，在错位的空间之间短暂撑开一条概念通道。圣物盒的信号通过虚境传输技术跨越历史切片进行传输。此战术极大消耗熵序者寿命，导致许国熵序者在乱序区内折损率极高。</li><li>前线基站防御机制：许国必须不断对外扩张，其在新占领区建立的新基站尚未与庞大人口完成深度绑定，无法形成概念级威慑。为了保护这些脆弱的战术节点，许国依靠其极度强悍的常规军队强度进行硬性防卫。许国真正的作战核心与主力是未被洗脑的正常人类士兵，他们以重装甲、重火力和不计伤亡的冲锋著称。他们在基站周围构筑密集的物理防线，用血肉和钢铁硬生生填补了概念威慑形成前的防御真空期，而军用伪自律人形更多被作为战术消耗品使用。</li><li>战后新锐测试与雷达盲区（排污监控漏洞填补）：伪自律人形作为一战后才诞生的新锐工业造物，并未经历过“耻辱战役”级别的海量消耗。目前，许国的高层处于“积攒底牌”的冷战期。他们刻意避免在常规国境线上引发数以万计的机甲自爆，以免惊动国联的康斯坦丁之瞳。当前阶段，许国军方将伪自律人形的“毒丸实战测试”与小规模摩擦，全部定向安排在了“死寂走廊边缘缓冲带”或“荒野极端信息风暴区”进行。这些高危盲区自带天文数字的乱序底噪。军用机甲在这些盲区内断网自爆所释放的二阶精神污染，在宏观雷达的波形中，完美地混入了自然灾害的狂暴背景音里。这解释了为何许国的这套血肉消耗战术目前在国际明面上依然没有触发全面的《排污协定》制裁。</li><li>信仰锁与污染吸收机制：许国不使用十三局研发的识别码。许国熵序者体内植入的是属于该国特有的“信仰锁”。信仰锁与移动圣物盒直接链接，圣物本身具有极强的识别和吸收污染的功能。在乱序区中，外部环境的污染会被圣物优先吸收和过滤，因此外部污染对许国熵序者来说相对较少，他们承受的主要是信仰网络内部的狂热同化。</li><li>移动圣物盒的空间偏导力场与高频认知干扰：许国的移动圣物盒在吸收外部污染后，并非将其无害化储存，而是将其与信仰网络中的“狂热精神毒素”（包括伪自律人形无线传回的废料）混合，形成一种“高频认知干扰场”向外辐射。这种干扰场具有极高的信息质量，在圣物盒周围形成了一层扭曲的“空间偏导力场”。高速射来的远距离动能弹头（如狙击枪子弹）在接触力场的瞬间会被空间错位直接碾碎或偏转，使得物理狙击完全无效。该空间偏导力场对高动能、小质量的物体具有强偏转效应，但当面对低速、大质量的近战人体单位时，人体质量会局部扭曲力场频率产生湍流盲区，偏转效率急剧下降，导致敌国杀戮小队能够冲入近战。许国熵序者因脑内植有信仰锁，对该特定频率干扰免疫。但敌国杀戮小队若要摧毁圣物盒，必须顶着干扰场强烈的精神毒素，冲进力场内部进行极度危险的近战物理强拆。同时，敌国熵序者若靠近该区域，其体内的“识别码”会受到精神毒素冲击，极易触发强制引爆。这种机制使圣物盒在防御远距离狙击的同时，成为了PVP战场上的强力近战Debuff发生器。</li><li>毒丸战术与友伤反噬的权限接管：针对移动圣物盒被毁的弱点，许国探险小队采用了极度惨烈的“毒丸战术”。圣物盒内部不仅是基站，还连接着军用伪自律人形的“污染泄压阀”。一旦圣物盒被敌方近战强拆摧毁，不仅小队会狂暴，圣物盒本身会瞬间引爆，将内部积攒的所有二阶污染以“精神毒素风暴”的形式瞬间释放。</li><li>高频替死分流与狂热灰烬化（基层断层弥补机制）：为了避免毒丸战术必定导致带队指挥官脑死亡从而引发基层指挥系统极速断层的致命缺陷，这股毁灭性的反噬并非直接全数冲击带队熵序者。在圣物盒即将引爆的零点几秒内，指挥官脑内的信仰锁会触发最高权限的“高频替死分流”。这股狂暴的废热会顺着物理线缆和战术局域网，被瞬间强制转嫁、均摊到小队内所有残存的“军用伪自律人形”以及随队的低阶惩戒营炮灰的湿件大脑中。这些被作为蓄水池的炮灰会因瞬间超载而“灰烬化”自燃，引发更猛烈的物理殉爆。而熵序者指挥官本身则通过这种牺牲全队的替死分流，扛过了最致命的第一波概念冲击。虽然指挥官依然会受到严重的精神重创和物理刻录，但能保住性命带回高价值情报，确保了许国基层指挥骨干的存续。在圣物盒被毁前，队长会临时接管权限，引导即将狂暴的单位进行最后的战术冲锋。</li><li>备用概念网络：钢源神在一定程度上能操控信徒的自我意识，且拥有备用的概念网络。在物理基站被大规模摧毁时，底层信徒不会瞬间全部失控。</li><li>神系重组与旧神现状：原有的十二神体系彻底崩塌，新生的“钢源神”与其余十一位旧神、复活的陨落神祇并存，形成了非稳定态的“十三神”格局。大部分旧神目前陷入沉睡，一般情况下无法插手凡界。</li></ul><h2 id="十一、职业" tabindex="-1">十一、职业: <a class="header-anchor" href="#十一、职业" aria-label="Permalink to &quot;十一、职业:&quot;">​</a></h2><ul><li>寻秘使：战术级侦察兵，只能携带仪器靠近已经出现的小型预兆点和微乱序区进行人工测量，预测下一步的进化还要多久。负责插桩后对桩的日常检测与维护。</li></ul><h3 id="熵序者" tabindex="-1">熵序者 <a class="header-anchor" href="#熵序者" aria-label="Permalink to &quot;熵序者&quot;">​</a></h3><p>分为不同种类和职业，不只局限于回收熵之种。</p><ul><li>伴随寻秘使的熵序者：负责在寻秘使进行测量时提供保护和辅助。</li><li>守护历史的记录者：负责记录和保存未被覆盖的真实历史信息。</li><li>回收专员：专门进入乱序区坍缩并产出熵之种的人员。</li><li>安第斯猎手：受重度污染者转化，回收全球污染。</li></ul><h3 id="清道夫" tabindex="-1">清道夫 <a class="header-anchor" href="#清道夫" aria-label="Permalink to &quot;清道夫&quot;">​</a></h3><p>负责对早期乱序区进行心灵和认知防治工作。 负责产生乱序区后的乱序区隔离。 宜居区的小微乱序区产生第一时间，清道夫就要到现场进行局面控制和封锁。 负责无序微小乱序信息的隔离和清除。 承担心灵医生的作用，负责对平民进行记忆锚定疗法。</p><ul><li>防疫部队与绝缘节点构建：在几十万人爆发特大灾难和二阶污染群体共振时，国家机器介入舆论维稳，清道夫在此过程中转变为专业防疫部队。他们放弃逐一进行心灵疏导的低效方式，转而在贫民中筛选出精神抗性较强的特定人员（如老劳工），对其进行极深度的药剂锚定，将其打造成人体“绝缘节点”。这些节点像防火墙一样混居在下城区，物理切断群体情绪的传导链路，从而死死压制住街区的污染共振飙升。</li><li>认知污染防御机制与对撞盲区：清道夫的记忆锚定疗法旨在锚定个体的“主观情感与自我认同（抵御抹除自我的二阶污染）”。世界底层重构历史事件是修改“客观事件记录与逻辑关联”。两者的作用靶点不同，不产生算力对撞。当历史覆盖发生时，被锚定的平民关于客观事件的记忆会被自然重写，但他们强大的自我认同感会导致产生短暂的迷茫感，平民不会因此察觉历史真相或导致大脑受损。清道夫的职能仅限于延缓物理异化。 使用微量的抗污染药剂配合记忆锚定疗法，来延缓脑神经的物理异化。</li><li>合法性与整体利益维稳：尽管黑心包工头和局部利益集团有极强的动机去取缔清道夫，以维持不知疲倦的底层人矿温床；但从国家上层建筑的宏观视角来看，国家考虑的是整体秩序与长期稳定，而非单纯的短期资本利益。如果任由底层劳工不受控制地异化为无面者，虽然节省了工资，但大量无面者的堆积会直接诱发更大规模的虚境溃疡，甚至引发城市级的暴乱和崩溃。因此，国家不仅赋予了清道夫合法地位，甚至将其纳入官方或半官方的管理体系中，以此压制资本的过度剥削，维持社会劳动力池的基础存续。 不同国家针对污染的处境和防范措施各不相同。</li><li>暴力机关日常维护：中大型乱序区以及边缘区的日常封锁、镇压和维护工作，由国家最核心的暴力机关（如十三局外勤、军队基层）负责。</li></ul><h3 id="处刑专员" tabindex="-1">处刑专员 <a class="header-anchor" href="#处刑专员" aria-label="Permalink to &quot;处刑专员&quot;">​</a></h3><p>不同于熵序者体系，由国家专门培养或指派的内部清洗人员。 专员只负责清理在现世叛逃的熵序者。 大部分的专员是非熵序者，但是实力强大。 部分必须进入乱序区执行任务的专员是熵序者。</p><ul><li>追杀动机与缓慢异化机制：普通的熵序者在服役期间，其识别码处于“常规监测模式”，为了保留战场挣扎空间，并未写入瞬间自杀代码。叛逃的熵序者断掉官方抑制剂并脱离乱序区的高压环境后，体内的“信息免疫系统”陷入休眠。现世的环境污染对他们相对轻微，不会立刻在现世极速溃烂。存活的叛逃者会变成缓慢物理溃烂的个体，能在地下黑市苟延残喘。由于体内结构已被深度异化，当在现世再次受到高浓度污染刺激时，肉体和精神才会逐渐异化和失控。越过临界点最终引发现世空间坍塌。处刑专员的任务就是在叛逃者受到污染刺激后，在他们逐渐失控、越过最终引爆临界点之前，与他们进行物理搏杀并将其消灭，回收其体内的碎片。</li><li>现世追踪与节点传导机制：地下黑市的“硬件屏蔽手术”虽然能让识别码对外发送的常规波段报警信号休眠，放出虚假的平稳信号，但阿国在制造识别码的骨血核心时写死了一段极绝密的“微观衰变周期代码”。这段代码属于底层物理防篡改后门，不受任何外界物理神经节或屏蔽手术的影响。当识别码脱离官方的高频校准基站超过一定时间后，衰变代码会引发极微弱但具有唯一特征的“底层共振”。处刑专员手持的雷达罗盘正是在追踪这种底层共振。然而，微观衰变共振无法在大气中远距离无线传播，它必须依托地下深埋的“概念隔离桩网络”或“铁路基站沿线的通讯线缆”作为物理传导介质。当叛逃者在城市群、边缘聚居地或路网附近活动时，只要靠近隔离桩或基站节点，微弱的共振就会被十三局的节点网络捕捉并放大发送给处刑专员的罗盘。但一旦叛逃者彻底切断补给，深入没有路网和基站的荒野无人区，雷达就会丢失信号。因此，处刑专员多在黑市、边缘中转站等人员密集的节点区域守株待兔，以防叛逃者获得补给。</li><li>现世处刑绝对物理收音机制：为了防止在人口密集区追捕叛逃者引发其提前暴走和空间坍塌，处刑专员执行任务时依赖一种昂贵的一次性“渊息石概念力场发生器”。在发动攻击前，专员会投掷该发生器，在目标周围瞬间撑开一个绝对闭环的微型死域。叛逃者即使在这个死域内暴走坍塌，其概念破坏力也会被力场发生器硬生生吃下并中和。外界观测到的仅为一阵微弱的物理强光，确保了现世处刑行动不会演变成城市级灾难。</li></ul><h3 id="监管机构的黑色产业链" tabindex="-1">监管机构的黑色产业链 <a class="header-anchor" href="#监管机构的黑色产业链" aria-label="Permalink to &quot;监管机构的黑色产业链&quot;">​</a></h3><p>清道夫与处刑专员掌握处理污染与熵序者的权力，内部滋生腐败。 部分处刑专员会故意逼迫熵序者失控并将其击杀，暗中挖取熵序者体内因长期吸收污染形成的“高纯度污染结晶”或“变异识别码”。 这些非法产物被卖给地下网络或跨国财阀，用于研制新型武器或延寿药。</p><h2 id="十二、特殊体质者" tabindex="-1">十二、特殊体质者: <a class="header-anchor" href="#十二、特殊体质者" aria-label="Permalink to &quot;十二、特殊体质者:&quot;">​</a></h2><h3 id="熵序者与适应性人员" tabindex="-1">熵序者与适应性人员 <a class="header-anchor" href="#熵序者与适应性人员" aria-label="Permalink to &quot;熵序者与适应性人员&quot;">​</a></h3><p>只有部分人拥有适应性能够进入乱序区深处。</p><ul><li>选拔机制：大部分国家采用在种族年龄为幼年时进行统一测试与发掘潜力的方式来筛选熵序者。</li><li>熵序者数量与消耗：熵序者数量并没有那么稀少，能够维持各国的正常消耗。同时，为了应对未来可能的能源缺口，各国正在秘密研究“强行催化微型乱序区”的技术，试图通过人为制造乱序区来量产劣质熵之种。 熵序者一般被认为是对信息流中某种信息有适格度的人，且对乱序和有序感知具备天然敏感。</li><li>职业待遇与多重要素控制：熵序者在世俗社会被定位为“国家英雄”，属于高薪职业，享受国家最高优先级的资源供给。国家对熵序者的控制并非单一的武力胁迫，而是通过社会地位、人文荣誉、经济利益以及健康保障（疗养舱与抑制剂）等多重要素进行深度绑定。</li><li>驱动力断层与自我牺牲锚点：熵序者掌握着超凡力量且长期处于生死边缘，精神压力极大。仅仅依靠利益和生存威慑不足以维持群体的长期稳定。熵序者在乱序区深处，不仅看到了历史的混乱，更直观地感受到了“虚境的无底深渊”和“人类概念的脆弱”。他们意识到，国家机器（包括残酷的隔离桩、暴利的抑制剂垄断）是目前唯一能维持人类世界物理外壳不被虚境瞬间吞噬的“堤坝”。老熵序者之所以不反叛，是因为他们知道，一旦国家机器停摆，所有人都会瞬间变成无面者。他们是用自己的命去填补那个即将崩溃的堤坝。这种“清醒的绝望与自我牺牲”，构成了熵序者群体最底层的心理锚点。</li><li>叛逃与虚无主义：尽管有多重控制和牺牲锚点，依然存在叛逃的熵序者。这些叛逃者往往是因为在乱序区中看透了世界的本质，陷入了极度的“虚无主义”。他们认为无论是国家的堤坝还是命定之人的剧本，最终都将走向毁灭，一切挣扎都是徒劳，从而选择放弃职责，逃离体制。如前文所述，他们叛逃后会遭到官方小规模追捕队的追杀和封锁。</li><li>识别码引爆机制与判定核心：识别码是人类自己研发的极高精尖造物，核心材料是上一代熵序者的骨血结晶和虚晶技术结合体，本身具备抵抗乱序同化的特性。识别码不仅检测熵序者对“自我”的认知（软件），也肩负着检测污染承载量与能量层级（硬件）的作用。识别码会极据颜色来实时反馈周边环境状态和熵序者自身状态。在乱序区内，只要熵序者潜意识里还保留着对“自我”的认知，且肉体承载的污染未超过物理极限，识别码就不会引爆。当熵序者被同化且丧失自我认知，或肉体污染超载时，识别码判定同化不可逆。在乱序区中，识别码采取虚境模糊处理，不需要处刑专员确认，直接引爆。但在现世中，识别码不会自动引爆。识别码被设计为双模式分离：虚境湮灭模式需要乱序区高熵介质起爆；物理终止模式则在现世物理切断脑干引发生物碳化。物理终止无法处理真实历史碎片的污染性，若在现世强行物理处决叛逃者，未消耗的真实碎片会引发局部溃疡灾难。因此，现世不能轻易自动引爆，必须依靠处刑专员利用渊息石死域在现世安全回收。这保留了处刑专员存在的必要性。</li><li>现世不引爆的物理法则限制与内循环物理阻断机制：识别码的引爆原理是“瞬间湮灭熵序者体内的真实历史碎片”。这种瞬间蒸发概念的高能反应，本质上是向“虚境借力”，它必须依靠“乱序区内部的高熵/乱序环境”作为起爆介质（类似炸药需要雷管）。在现世极度稳固的低熵物理法则压制下，识别码的自毁程序根本无法产生足以蒸发概念的连锁反应。如果强行在现世起爆，不仅炸不死叛逃者，反而会因为劣质的能量爆发，提前刺破叛逃者体内本本就极度不稳定的污染屏障，瞬间加速其暴走。同时，为了防止熵序者在日常高压任务中因为自身情绪波动导致识别码误判走火，阿国的工程师在设计时，在识别码与宿主神经元之间加装了“单向物理绝缘层”。识别码的起爆探头是单向朝外的，它只能读取宿主的生命体征（硬件是否超载），但绝对无法抽取宿主体内的能量。因此，即使叛逃者在现世体内已经变成了高熵炸药桶，识别码也因为这层绝缘层的存在，无法将其作为雷管引爆自己。因此，在现世，识别码只能作为被动的“高精度定位器”，国家被迫只能依靠处刑专员用物理手段去斩首。</li><li>识别码技术逆向与人体实验：列强在暗中确实试图解析许国的湿件技术，但随着实验逐渐被证实得不偿失，列强目前只是依靠常规的材料学和生物学在缓慢改进自身的识别码。</li><li>圈养农场违背公约与合众国黑箱：在列强明面的社会秩序与签署的《基本人权公约》框架下，“圈养熵序者提取骨血”这种把人当畜生的行为是严重越过政治底线、足以引发国际制裁的。老熵序者在正常伤病折损后自愿捐献遗体，才是骨血结晶的主主流合法来源。结晶的成型也需要熵序者在生死边缘进行高压精神淬炼。然而，合众国凭借其庞大的财力与技术优势，背地里在偏远的荒野或深海浮岛秘密设立了非法的“催熟农场”。他们暗中劫掠有资质的流民或破产熵序者，利用虚假的“乱序区模拟舱”与高浓度药物强行催熟结晶。虽然废品率极高，但这种违反人伦的黑箱实验，成为了合众国试图量产高阶装备、打破识别码产能瓶颈的隐藏底牌。</li><li>边界识别与瞬间熵增缓冲：识别码能够精准识别现实与乱序区的边界。熵序者在跨越边界离开乱序区时，时间修正会带来瞬间的巨大熵增。为了避免瞬间超载导致识别码引爆，熵序者注射的抑制剂承担了缓冲职能。抑制剂在体内形成一个临时的“信息蓄水池”，优先吸收这股瞬间涌入的熵增，然后以极其缓慢的速率释放到肉体细胞中，转化为骨龄的增加，从而平滑处理了跨越边界的物理代价。</li><li>识别码漏洞与神明限制：目前国家和十三局高层尚未发现神明附身可以欺骗识别码的漏洞。由于神明伪装成熵序者的“第二人格”或“强烈执念”，在现有的物理检测手段中，熵序者的自我认知判定依然为“人类”，导致识别码无法识别这种高维度的概念寄生。但是，神明虽然能替熵序者承受污染，这种承受必须在熵序者肉体的“物理承载极限”之内。一旦神明吸收的污染超过了肉体极限，肉体开始物理崩溃，识别码依然会因为检测到“生命体征不可逆异化（硬件超载）”而强制引爆。这限制了神明不能无底线地替熵序者开挂。</li><li>数据欺骗与良性变异：为了掩盖神明替熵序者承受污染导致的“时间-污染转化率异常”，神明并非直接消除污染，而是将污染强行转化为某种“良性物理增生”（如骨密度异常增加、神经元过度活跃）。在识别码的硬件检测中，这被判定为“熵序者个体的良性变异或潜力爆发”。由于被附身者极少且资质稀有，这种宏观数据上的异常样本太少，医学界将其作为特殊病症理解和处理，从而完美掩盖了污染去向不明的数据漏洞，瞒过了十三局的分析部门。</li><li>离体销毁机制（高维降维崩解）：为了防止熵序者战死或报废后，法医在解剖时发现这些附带高维概念残留的“物理增生”，神明设置了自毁预案。当神明主动切断链接或熵序者脑死亡的瞬间，支撑物理增生的高维概念会撤离。失去高维支撑的增生组织不会自燃，而是发生“降维崩解”。无论外界是绝对零度还是时间停滞，增生组织会瞬间从细胞结构坍缩为一滩没有任何基因特征的“无序灰质/污染淤泥”。十三局的法医在解剖时，只会看到一包高度腐败的重度污染毒水，从而彻底切断了高维概念暴露的风险，且不受物理环境阻断。</li><li>命定之人与黑市手术：地下黑市存在“硬件屏蔽手术”能让识别码休眠。各个地下组织掌握的技术不同，多为物理欺骗手段。例如将高阶污染生物的神经节强行缝合在识别码接口处，利用其释放的虚假平稳信号堵住检测探头。此类手术致死率高，且熵序者需终身服用黑市特制药物维持神经节存活。停药则神经节坏死，识别码瞬间引爆。命定之人对这种黑市手术放任不管，是因为单单几个人动摇不了大计划。熵序者失控变成无序Boss，依然在她的“废物利用”计算之内，甚至她乐于看到这种能加速虚境扩张的“小聪明”。</li><li>战力与存活率：熵序者的死亡率属于中等水平，但随出任务次数逐渐增加而上升。如果未获得良好的医疗与心理疗愈，其死亡概率和异变概率会显著上升。老熵序者在身体机能和精神状态达到一定阈值后，会逐渐退居二线，从事指导、防卫等非一线高危任务，避免直接的无谓牺牲。</li><li>现世弱势：由于体质极度敏感，熵序者对现世的污染更为敏感，承受的负面影响更大。在现世常规战斗中，一般的熵序者本身属性不足以对装备精良的士兵集群形成绝对碾压。</li><li>抑制剂的双重排污机制与疗养舱修复：熵序者在日常任务中吸收的浅层污染，主要依靠自身注射的抑制剂来应对。抑制剂的粉末不仅能激活“信息免疫系统”压制污染，本身也能与肉体的排毒机制结合，缓慢去除浅层游离污染。同时，抑制剂也可以进行战时生命恢复。而“深度疗养舱”则是熵序者在进行高强度连续任务或大型攻坚后才有的“特殊福利与深度清理”。疗养舱利用低频信息锚定阵列，配合药物进行深度洗脑与物理排污。对于熵序者因遭遇时间修正或过度做功导致的物理神经元严重受损与细胞端粒老化，列强高价向长生种租借“局部细胞端粒逆转阵列”来为其进行修复重铸。</li><li>植物代偿剥削机制：长生种的逆转阵列本质上是“生命力置换泵”。遵循等价交换，要修复熵序者的端粒，必须强行抽取其他生物的纯净生命力作为代偿。长生种的生命工程技术利用特定的高生命力“变异植物或大型活性藤蔓”作为阵列的“活体电池”。阵列将这些植物的生物端粒瞬间抽干枯萎，转化为修复熵序者神经元的缝合剂。这确保了修复的合法性，同时避免了用同类人类作为燃料的极端伦理底线。</li><li>做功代价与缓慢恢复：当熵序者在乱序区内使用能力（如强行撑开概念通道、坍缩乱序区产出熵之种）时，这种干涉历史产生的瞬间巨大熵增，会以“物理刻录”的形式烙印在他们的骨骼和神经元深处。这种物理刻录并非绝对不可逆，而是恢复过程极其缓慢，需要长期的疗养和特定的药物辅助。</li><li>严重刻录的触发条件：熵序者在乱序区内进行平常的探索和战斗活动，并不会产生严重的物理刻录。只有当他们在乱序区内遭到重伤，或者精神层面受到极大冲击（如直面高维概念、强行扭转核心历史节点失败）时，才会遭到严重的物理刻录。这种严重的刻录会导致细胞受损，最终可能对真实历史粉末产生排异（耐药性）。</li><li>乱序区增幅与异化倒计时：一旦进入乱序区深处，熵序者的能力会得到一定程度的增幅，成为探索与战斗的主力。但他们并非具备神级战力。熵序者在乱序区待得越久、力量越强，就越容易被乱序信息同化。他们在乱序区内的活动具有严格的时间限制，一旦超时，就会彻底变成怪物。 只有熵序者能进入乱序区核心地带。 产出熵之种是特定职业熵序者才能完成的行为。</li><li>古代抑制体系：在现代熵序者体系建立之前，古代的每个国家都有每个国家独特的污染抑制办法，用于保护接触乱序信息人员。</li><li>现代熵序者体系与第一桶金：找到古老结晶是发生在启蒙时代的事情。现代的熵序者体系实际上源于当时各国开展的一项合作科考项目。阿国作为该项目的最后幸存者（或独占了核心成果），对外标榜是自己单方面找到了这批上一世界线长生种遗留的“古老高纯度真实结晶”。阿国利用这批不可再生的遗迹存货制造出了初代抑制剂，完成了原料的自给自足闭环，并借此曾拥有过短暂的“全球熵序者垄断霸权”。</li><li>信息免疫系统与污染抑制：熵序者之所以能抵抗概念级的高压同化，并不仅仅是因为极微量粉末的硬抗。熵序者的灵魂或潜意识深处自带一套潜藏的“信息免疫系统”。极微量的真实历史粉末（强效抑制剂）在注入后，充当了唤醒这一系统的“特异抗原”与“启动钥匙”。免疫系统被激活后，熵序者自身的脑波波段和认知边界会建立起一层对乱序信息具有高排斥性的防御层。熵序者的免疫系统识别的不是具体的历史剧情，而是这层“高维防伪标签”的物理波段。抑制剂本身也能配合身体机能去除浅层污染。</li><li>异体高维信息强行灌注与肉体排异（真实耐药性病理闭环）：随着出任务次数的增加，严重物理刻录在体内的累积会导致熵序者的神经元结构出现极其微小的“概念裂隙”。当熵序者再次注射国家配额的强效抑制剂时，抑制剂中包含的“真实历史粉末”虽然只有极微量，但它本质上蕴含着“庞大且不属于熵序者本人的高维历史片段与他人的真实情感”。在熵序者健康时，信息免疫系统仅提取其“防伪标签”作为钥匙；而当神经元存在裂隙时，这些极其庞杂的异体真实信息会顺着裂隙强行灌注进熵序者脆弱的脑神经中。熵序者的大脑会瞬间被不属于自己的古代战争记忆、无数陌生人的死亡体验或某个失落文明的狂热情感强行撑满。为了保护仅存的“自我主干”不被这股异体信息流彻底撕裂，受损的信息免疫系统会产生极端的“过度反应”。它不再将真实粉末视为救命药，而是将其判定为“致命的高维精神入侵源（过敏原）”。免疫系统会调动全身所有的能量，不顾一切地去攻击、排斥这股真实粉末，引发恐怖的“免疫风暴”。此时注射抑制剂，熵序者不仅无法稳固认知，反而会因身体疯狂自毁而遭受极端的痛苦，器官极速衰竭，这就是所谓的“真实耐药性”的病理本质。</li><li>神明寄生与抑制剂消耗：神明在附身熵序者时，会利用熵序者体内累积的污染作为“缓冲垫”。当熵序者注射含有绝对真实历史粉末的抑制剂时，神明主动引导熵序者体内的污染去迎击，让污染消耗掉抑制剂的药效。这避免了神明意识与绝对真实粉末发生直接的概念排斥，导致被神明附身的熵序者对抑制剂的消耗量远大于常人。</li><li>物理限制与耐药性死锁：神明虽然能引导污染，但无法跨越物理极限。当熵序者因严重刻录产生耐药性，其神经元对真实粉末产生不可逆的排异时，附身的神明对此无能为力。神明无法用高维力量强行黏合物理层面的断裂。若神明试图用概念填补神经元，世界底层雷达会判定宿主硬件结构篡改，导致识别码瞬间越界引爆。面对耐药性爆发，神明只能眼看着宿主肉体因物理崩溃而灭亡，无法提供干预。</li><li>国家配额抑制剂与平价抑制剂的双轨制：熵序者使用的抑制剂并非只有一种规格。含有“真实历史粉末”的属于国家配额的强效抑制剂，由国家冷链垄断，仅供应给在编的官方熵序者或执行高危任务的小队，其信息锚定效果极强。而在边缘区或地下黑市，广泛流通着一种“平价抑制剂”。这种平价药剂不含有珍贵的历史粉末，而是利用乱序区里产出的其他特殊物质强行提炼制造而成。平价抑制剂虽然没有那么强效，且副作用较大，但能够满足底层边缘熵序者或普通雇佣兵最基本的抗污染需求，以此维持着荒野散户的基础生存。</li><li>平价抑制剂的痛觉死锁与物理阻断（概念级防护机制）：平价抑制剂既然没有“真实历史粉末”，那它是如何让黑市熵序者在乱序区中抵抗认知重写的？答案在于其核心成分——提取自变异动植物的剧毒。这种毒素进入人体后，不会像强效粉末那样去唤醒高维免疫系统，而是直接作用于熵序者的物理神经元，强制引发持续的“濒死物理痛觉”。世界底层在乱序区中重写认知时，其机制是平滑过渡的。而平价抑制剂产生的极端痛楚，如同一根烧红的铁钉，死死钉在熵序者的脑神经上。当乱序信息试图篡改大脑时，这种极致的物理痛觉会强行拉扯熵序者的注意力，让其神经元完全锁定在“当前低维肉体的挣扎”上。大脑因为忙于处理剧痛而无法进入“平滑重写”的受控状态，从而在客观上利用物理极限界限卡住了概念重写的过程。这是一种饮鸩止渴的防御：不用盾牌去挡高维认知，而是用剧痛让大脑主动闭锁拒绝接纳新信息。</li><li>平价抑制剂的生理固化与阶层跃升排异（洗髓机制）：长期依赖这种痛觉闭锁机制，会导致神经元被毒素强行固化，器官处于受控衰竭状态。此时，如果底层熵序者因被国家十三局收编而转为注射官方的“真实粉末抑制剂”，在大部分情况下能够平滑过渡。真实粉末抑制剂进入体内后，会凭借其更高维度的绝对真实概念，逐渐压制并清除掉那些累积的平价毒素，这解释了底层雇佣兵能在荒野长期生存的原因。但仍有少部分个体，因为毒素沉积过深导致神经元结构彻底异变，在转正注射真实粉末时会引发剧烈的“概念与毒素双重排异”。对于这些排异个体，十三局必须先对其进行极度危险的“深度洗髓剥离手术”，用物理手段强行刮除神经元上的毒素沉淀，让其恢复到濒死的“白纸状态”，才能重新接纳官方粉末。退役教官的便携物理隔离针和洗髓手术，只能刮除神经元物理结构层的毒素沉淀。真实耐药性造成的概念裂隙位于信息内核层，物理手段无法触及。强行修复概念裂隙会引发等量致命的信息熵反噬。因此耐药性无法被彻底治愈，只能缓解。</li><li>战时极端续命预案（战术针剂）：为了解决冷链断供或前线补给线被切断时熵序者小队直接团灭的容错率悖论，列强军方研发了极度残酷的战术针剂。这种针剂能够在熵序者断药时，将体内已经失活的抑制剂粉末残渣进行“二次强行点燃”。点燃代价是极度透支熵序者的生命力和细胞端粒，换取短暂而狂暴的信息免疫屏障。这种针剂允许熵序者在断联的绝境中付出惨痛的肉体代价多活几天并撤回战线，而不是直接暴走导致整个战线崩溃。</li><li>极高能量密度与极微量锚定比例：一颗高纯度熵之种蕴含的信息量极其庞大，足以驱动遗迹武器。而制作一支高级抑制剂，只需要从熵之种上刮下极微小的一点“真实历史粉末”作为启动钥匙即可。一颗熵之种的边角料，足以制作成千上万支抑制剂。国家在这场交易中获取绝对暴利，用极微小的成本，换取熵序者拿命拼来的战略资源。</li><li>物理承载非绝对满载：耐药性达到极限产生严重排异，并不等于熵序者体内的污染已经达到了肉体物理承载的绝对极限。这更类似于器官对特定物质的依赖或排斥（如胰岛素抵抗），而非肉体完全变成污染怪物。 老熵序者的待遇与自毁刷机、隔离针泄压：老熵序者产生耐药性后退居二线。国家之所以给他们提供完善的医疗支援和极高的人权保障，是因为“如果不给予高待遇，就没有人愿意冒着极高风险给官方干活”。了解极多核心机密、体内污染已经彻底固化的老熵序者（教官）在正式退役后，无法接触乱序区的高压环境。为防止这批高危个体在现世引爆，十三局在他们退役时，会对他们体内的识别码进行物理重写刷机，切换为“现世静默自毁模式”。时间同步的老熵序者产生耐药性后，常规的抑制剂已无法生效。他们在现世需要随身携带并定期注射国家配发的“便携式物理隔离针（类似胰岛素注射笔）”。这种隔离针不包含真实的粉末，而是利用特定的物理空化液去短暂抽离或固化暴走的神经元节点，强制给污染泄压。一旦检测到教官在现世遭遇足以引发空间坍塌的极端污染刺激或隔离针断药导致全面暴走，识别码不会尝试压制，而是越过所有生理防线，在零点几秒内瞬间切断其脑干并引发生物碳化自燃。这种设计体现了国家对核心资产在日常状态下的极致控制与利用。</li><li>附带雷达作用：在常年抵抗污染的过程中，老熵序者体内固化的污染结晶已经与虚境频率形成了“被动物理共振”。这赋予了他们极其敏锐的虚境波动感知能力，能够凭借直觉察觉到极其微小的虚境异常。这一能力被国家利用，作为高精尖探测仪器之外的“附带人肉雷达补充”。国家为其提供医疗资源的初衷是保障这批掌握核心经验的教官群体，而预警雷达功能只是留存他们所带来的额外军事收益。当老熵序者死后，在自愿的条件下，其遗体会被国家回收进行处理，利用其体内长期抵抗污染形成的特殊骨血结晶，用于制造新的识别码。</li><li>极少数特异能力人：能够察觉到塔万汀大群岛破碎违和感的人。</li></ul><h3 id="身份与生存空间-玩家保释逻辑" tabindex="-1">身份与生存空间（玩家保释逻辑） <a class="header-anchor" href="#身份与生存空间-玩家保释逻辑" aria-label="Permalink to &quot;身份与生存空间（玩家保释逻辑）&quot;">​</a></h3><p>玩家在前期作为无身份证明的“黑户”，第一次进入乱序区却由于干预产出了花。</p><ul><li>惰性伪装与十三局基层的误判：这朵花在表面上看上去是一颗“特殊形态的、极高纯度的熵之种”。当玩家被带回十三局时，基层保存人员一开始试图剥离这朵花，但发现它处于绝对惰性封装态，剥离不下来。由于玩家一开始只是个籍籍无名的小人物，并未引起大人物的直接注视，十三局基层根本不会也没有能力把这朵“貌似种子的花”送到国家最高级的实验室去检测。他们只是按照平常的特殊体质案件进行常规处理。</li><li>识别码定位与隐形伏笔：在这种处理逻辑下，十三局将玩家收编，并为他植入了“识别码”。然而，这枚识别码对玩家来说仅仅是一个普通的“定位器”。十三局表面上宣称它会在失控时引爆，但实际上受限于玩家特殊的高维特质，它根本引爆不了，只能提供定位功能。玩家的灵魂具有高维特质，其信息接收频率与低维识别码的触发信号不匹配，导致引爆信号被直接过滤。此外，玩家体内的花能自动模拟常见良性变异熵之种的波形，瞒过了阿国底层公式。同时，这朵花如果在现实和乱序区没有满足特定的条件绽放的话，其表面一直呈现封装惰性状态。（这也为日后若遭到极致物理伤害可能引发的“不可控随时核爆”埋下了隐秘的伏笔）。 玩家由于灵魂锚点对真实记忆的保护，在遭遇时间修正时会产生“高维物理反击”，被十三局的常规仪器误判为“因为承载不了时间修正与历史覆盖而导致的严重精神受损（PTSD）”。 玩家灵魂深处自带某种“高维权限”，只是以为识别码生效了。</li><li>特异资源产出源与可控观察对象：十三局高层发现玩家的产出机制与魔晶破壳必须具备“未知探索欲”高度一致。一旦将玩家物理软禁或强行切除探索自由，其灵魂波段死寂，产出的只能是毫无价值的虚境废热。因此，十三局并未将玩家定性为“无可替代的极高价值核心”，而是将其判定为一个特殊的“特异资源产出源（可控观察对象）”。初期十三局基层曾尝试强制收容与剥离花朵，但在遭遇物理失败与死伤后，评估风控成本，才转为放任其自然产出的软观察钓鱼策略。在这种逻辑下，十三局没有采用最高风控将其彻底锁死，而是像钓鱼一样让玩家在外界保持独立观测权去自然产出。</li><li>同伴监视与派系制衡：玩家在各方势力的夹缝中获得了合法的活动空间，但绝非完全自由。十三局将玩家身边的初始同伴（如救他的自律人形）直接设定为隐形的“监视者”。这个监视者不仅负责引导和保护，更负责记录玩家的一切接触轨迹。对于十三局的激进派来说，这种安排既是一种制衡，也是为了防止玩家意外死亡导致研究中断的一种成本较低的物理防线。他们确实也下手了，后面剧情更新。</li></ul><h2 id="十三、编年表" tabindex="-1">十三、编年表: <a class="header-anchor" href="#十三、编年表" aria-label="Permalink to &quot;十三、编年表:&quot;">​</a></h2><h3 id="纪年法体系" tabindex="-1">纪年法体系 <a class="header-anchor" href="#纪年法体系" aria-label="Permalink to &quot;纪年法体系&quot;">​</a></h3><p>采用“终难历”。以伊国天明教宣称的“神降日”作为公历0年，称为“终难年”。</p><h3 id="关键年份对照" tabindex="-1">关键年份对照 <a class="header-anchor" href="#关键年份对照" aria-label="Permalink to &quot;关键年份对照&quot;">​</a></h3><ul><li>终难历0年：神权时代开启，神降日。社会格局：教权垄断知识，王权依附教权。</li><li>终难历1500年左右：启蒙时代开端。代表作《君权解析》（对应现实《君主论》出版年份）。人类打破魔法的神秘化叙事，发现其可解析性，逐步建立起系统化的“术式学”。时代核心矛盾：贵族化的传统魔法与学院派的新兴魔法形成尖锐对立。第一次魔法革命：人类将魔法编码为可学习、可复制的符文体系，打破了长生种与贵族对魔法的垄断。</li><li>终难历1760年左右：魔导工业革命开启。魔导蒸汽机被发明（对应现实第一次工业革命）。魔晶提炼技术取得突破性进展，魔法实现规模化能源化应用，魔导工业时代正式开启。核心技术突破：魔导蒸汽机诞生，通过魔晶湮灭产生的能量烧开水来产生蒸汽驱动机械，彻底改变了生产与战争的形态。魔导科技的发展存在熵增定律的天然天花板，且分为三大分支：解析虚境（阿国）、强化自身（国联）、融合神明（许国）。</li><li>终难历1914年：耻辱战役爆发（对应现实第一次世界大战）。第一次世界大战：魔导工业化战争的残酷首秀，彻底改写了世界的政治格局。人类常规军队无法抗衡神明，在动用遗迹武器前处于溃败状态。 终难历1914年-1918年: 神祇的陨落与新生时期。</li><li>终难历1920年代：当前所处时代。战后间歇期，魔导全面现代化和普世化经历百年发展，列强进入高速发展与矛盾激化的时期（对应现实柯立芝繁荣与一战后时期）。传统魔法贵族失势，工业新贵快速崛起。技术爆炸引发极剧烈动荡。</li></ul><h2 id="十四、文化与生态" tabindex="-1">十四、文化与生态: <a class="header-anchor" href="#十四、文化与生态" aria-label="Permalink to &quot;十四、文化与生态:&quot;">​</a></h2><h3 id="社会核心矛盾激化" tabindex="-1">社会核心矛盾激化 <a class="header-anchor" href="#社会核心矛盾激化" aria-label="Permalink to &quot;社会核心矛盾激化&quot;">​</a></h3><ul><li>阶级矛盾：旧贵族掌握着大量的农业用地与传统政治势力。虽然在经过类似1848年革命后逐渐式微，但他们仍然保有大量的原始积累，以此与掌握着工厂和魔晶资源、要求获得对应政治权力的工业新贵族形成死锁。双方在资源分配与政治话语权上僵持不下。</li><li>生存与就业矛盾：底层民众为争取居住在宜居区的权利，被迫承受极大的压力；同时大量低阶自律人形投入生产，对底层民众的就业构成了剧烈竞争。</li><li>种族矛盾：长生种与短生种之间的冲突。在历史进程中达成互相妥协，并在逐渐的冲突中完成国族认同建立和文化交融。</li></ul><h3 id="信仰防范" tabindex="-1">信仰防范 <a class="header-anchor" href="#信仰防范" aria-label="Permalink to &quot;信仰防范&quot;">​</a></h3><p>官方层面上，除了物理派国家，所有国家都是拒绝钢源神信仰的。</p><h2 id="十五、经济" tabindex="-1">十五、经济: <a class="header-anchor" href="#十五、经济" aria-label="Permalink to &quot;十五、经济:&quot;">​</a></h2><h3 id="劳工消耗与掠夺" tabindex="-1">劳工消耗与掠夺 <a class="header-anchor" href="#劳工消耗与掠夺" aria-label="Permalink to &quot;劳工消耗与掠夺&quot;">​</a></h3><ul><li>劳工开采比例：由于现代大部分国家已经建立起基于大型稳定态乱序区的工业化虚晶量产体系，纯粹依靠底层劳工用肉体去荒野散采虚晶已不再是全社会能源的主流来源。去荒野开采的劳工属于为了高溢价走私而冒险的极少数边缘群体。 地下农场与低阶流水线同样提供基础岗位。 劳工开采毛货虚晶的动机，是资本家开出的高薪酬和进入宜居区的许诺。 部分国家会从其他国家和大陆进行人口掠夺，以补充基础劳动力消耗。 劳工消耗的转变是缓慢的，更类似病症而不是极速报废。</li></ul><h3 id="消费市场结构" tabindex="-1">消费市场结构 <a class="header-anchor" href="#消费市场结构" aria-label="Permalink to &quot;消费市场结构&quot;">​</a></h3><p>资本家生产的工业品流向底层市场。 边缘区和底层的消费结构主要由廉价工业品和各种一二三产业服务产品构成。 底层劳工赚取的工资用于购买这些产品以维持生存和缓解污染痛苦，形成经济闭环。</p><h3 id="货币与定价" tabindex="-1">货币与定价 <a class="header-anchor" href="#货币与定价" aria-label="Permalink to &quot;货币与定价&quot;">​</a></h3><p>相对纯度可以通过土法进行测量。 贸联会掌握着标准晶币（SC）定价体系。</p><ul><li>纯度标准测量壁垒（国际度量衡委员会机制）：贸联会本身并没有掌握超越列强核心实验室的某种绝对黑科技来垄断纯度测量。相反，贸联会的金融定价权是建立在“整合列强共识”的基础上。它整合了列强各自顶尖的魔晶学技术与复杂的区域纯度测量方案，在此基础上，经过各列强政治与经济的漫长博弈与妥协，统一定义出了一套被各国官方背书并共识承认的“绝对纯度标准标尺”。贸联会（类似现实的WTO或国际度量衡委员会）作为该标准的唯一仲裁机构和执行者，负责全球晶币的发行与大宗魔晶交易的定级。列强核心实验室的仪器虽然能测出微小波段的异常或伪魔晶的隐藏污染，但在国际大宗交易结算时，必须无条件遵循贸联会这套公认的标尺。如果某个列强凭借自己的高精尖仪器单方面掀桌子、拒绝承认贸联会定级的纯度，等同于向全球宣布撕毁信用共识体系，会导致全球魔导贸易网络瞬间崩溃。列强基于对全球经济与信用体系稳定的绝对依赖，不能随意通过武力和技术霸权摧毁贸联会的定级实体，这是其能够作为中立金融谈判场的底层威慑。标准晶币（SC）跨国发行的权力来源于这种列强共识授权。 官方共识，在对外贸易结算时统一使用晶币，不同国家内部拥有内部各种币制。</li></ul><h3 id="虚晶与魔晶转化及剪刀差剥削" tabindex="-1">虚晶与魔晶转化及剪刀差剥削 <a class="header-anchor" href="#虚晶与魔晶转化及剪刀差剥削" aria-label="Permalink to &quot;虚晶与魔晶转化及剪刀差剥削&quot;">​</a></h3><p>市面上大量流通的依然是魔晶，但经贸会掌握了虚晶与魔晶的转化机制，并利用此机制形成剪刀差剥削。 伪魔晶技术是近十年才产生的新锐技术。</p><ul><li>包工头走私与荒野穿越：底层劳工在奇观边缘冒死开采的“畸变毛货”，只能低价卖给边缘区合法的“包工头（资本家白白手套）”。包工头截留了绝大部分毛货，走私到贸联会的黑市网络换取高纯度自然粮与暴利。荒野上的路网实际上是对所有人开放的，并没有绝对的物理封锁墙。包工头以及废土上的探险者、雇佣兵等各色人等，通过重装防污染载具、熵序者带队或者纯粹用人命填补等各种方式，在重度污染的荒野中穿行，维持着这条地下走私生命线的运转。</li><li>贸联会农业与双轨制：贸联会的农业并不依赖消耗虚晶的地下农场。他们利用强大的航海武装力量与早期殖民优势，独占了文兰大陆某些未被污染的“海外净土”。在这些拥有独立武装把守的广袤自留地中，贸联会进行着传统而庞大的自然农业生产。宜居区本身也有正常的自然耕地。国家粮农组织负责宜居区正常自然粮的供应，而贸联会则利用海外净土产出的极高品质自然粮作为黑市网络中的硬通货进行走私。催熟粮食仅仅是用来填饱底层人口的肚子。</li><li>转化能源的特殊属性：转化的能源为二次提纯，不是真魔晶。这种伪魔晶在物理性质上极度稳定，介于虚晶和魔晶之间，具有特殊的抗干扰与抗波动属性。列强虽然自己也在开采高纯度魔晶（原晶），但面对那些对能量波动极其敏感的高精尖仪器或特殊武器时，伪魔晶成为了一种相对廉价且稳定的平替选择。列强知道伪魔晶存在异常，但由于原晶的极度匮乏和高精尖实验的迫切需求，他们选择了将其作为平替方案，并且这种能源也能作为列强进行虚境研究的方法。</li><li>学科分割与对照组观测机制：在科学界，研究伪魔晶及虚境相关现象的属于专门的“虚境科学”或“魔晶学”。正统用于测量虚境科学的高精尖观测仪器一般都使用高纯度魔晶作为驱动。只有在核心实验室进行专门的虚境科学研究或魔晶学研究时，才会使用伪魔晶。其他核心实验室在常规实验中依然使用原晶，只有在原晶极度匮乏的紧急情况下，才会使用伪魔晶作为替代。阿国等列强的核心科学家在特定实验中，会利用伪魔晶自带的三阶污染作为“对照组”。通过高精尖学科的技术检测，将仪器在纯净天然魔晶和伪魔晶驱动下产生的“污染偏差值”进行严格对照，科学家们能够反向推导出真实世界被篡改的物理断层数据。这种将污染转化为观测标尺的技术，是阿国维持技术壁垒的核心手段之一。 转化率相对较低，且转化过程会产生无法被隔离桩阻挡的“三阶污染”。</li><li>转化代价：转化采用遗迹技术，需要消耗大量的虚晶作为基础材料。转化过程并非完美的逆熵再生，而是对虚晶残存信息的深度压榨。同时，转化过程必须投入秘密捕获的灾厄boss作为催化剂，并投入稀有矿物。经贸会必须在“稳定态乱序区”内秘密生产，这也是为了就近捕获这些灾厄boss。 三阶污染具有污染穿透性，信息和意识同化于虚境中。</li><li>物理防御机制与渊息石特攻：列强在核心实验室中使用名为“渊息石”的特定矿物来暂时隔绝三阶污染的穿透。渊息石并非自然产物，而是死寂走廊深处、极少数高阶乱序区坍缩后留下的物理残渣，极度稀缺且无法人工合成。渊息石对三阶污染具有“特攻”属性，其抵御原理是“同态相斥”——它本身散发着一种极高频的能导致人类基因瞬间崩溃的辐射，这种辐射能完美弹开三阶污染的穿透。核心实验室必须建立极其庞大的物理铅层和魔导护盾来隔离渊息石自身的辐射，然后才能利用它去隔离三阶污染。这种“用毒药解毒”的成本极其高昂，且装置体积庞大，根本无法小型化或普及到民用隔离桩和移动采掘城上。渊息石会在抵御污染的过程中逐渐消耗，需要定期进行更换。</li><li>伪魔晶的物理废料闭环：在伪魔晶的生产阶段，产生的溢出污染被单向意识体虚像滤网打碎伪装成了一阶废热排走；而当伪魔晶被列强燃烧榨干能量后，其使用端会留下一块极度危险的“高辐射固态毒核”。这块毒核是纯粹的三阶污染聚合体，类似于核反应废料。经贸会在生产时已将其信息特征码进行了物理格式化，导致毒核溯源呈乱码状态。</li><li>脏弹应用与物理保险机制：列强深知这种毒核如果随意排入下水道会直接穿透隔离桩引发虚境反噬。由于伪魔晶技术是近十年才兴起的，废料积累时间相对较短，因此目前列强处理毒核的方式是在实验结束后用特制的“渊息石密封罐”强行封装，由重装部队押运至荒野深处进行物理深埋，或高价再请经贸会秘密回收。同时，军方利用空间折叠错位技术，将三阶毒核制成了“微型脏弹”。脏弹内部装有维持错位的微型魔导信标，而其最外层的弹壳内壁涂抹了一层极薄的“劣质渊息石粉末”作为第一道物理防线。在平时储存和运输时，信标处于关闭状态，粉末硬抗三阶辐射，保证零泄露。只有在发射升空或投掷的瞬间，信标才会启动撑开空间错位，同时产生高温瞬间烧毁外层的渊息石粉末。当脏弹落地引爆炸毁信标时，空间错位消失，三阶毒核直接跌落回现实维度，爆发出恐怖的穿透杀伤。这套保险机制确保了高危武器不会在自家军火库引发自爆。</li><li>单向意识体虚像滤网与底噪掩盖机制：经贸会在生产工厂外围建立了一道“单向信息滤网”。这道滤网利用遗迹技术在底层建立了一个“无限递归的虚拟梦境”作为核心抗压底座，维持梦境运转的耗材是在稳定态乱序区内大量捕获的“高阶乱序区信息意识体”。除此之外，滤网物理层面上的关键构成是一种特殊活体生物“渊息虫”。这种虫子本身并无神奇魔力，它们能抵御三阶污染是因为它们以乱序区内微量的渊息石粉末为食，体内富集了渊息石的同态相斥辐射，用自己的肉体作为微型铅层来中和污染。生产中产生的三阶污染被引入虚拟梦境稀释，再通过渊息虫过滤膜穿透打碎，随后伪装成高浓度的一阶污染废热排放给吸污塔。为了防止康斯坦丁之瞳发现异常巨大的废热排放量，贸联会将这些秘密转化工厂建立在“物理底噪极大”的区域（如死寂走廊边缘的超大型乱序风暴眼下方，或极其活跃的巨型奇观群落内部）。利用大自然本身狂暴且巨大的污染喷发量，完美掩盖了工厂的人造工业排放数据。一旦渊息虫出了乱序区，失去渊息石粉末的摄入，体内的辐射平衡被打破，就会瞬间自燃或基因崩溃。</li><li>伴生饲料提取与虫群量产成本平账：如果全靠死寂走廊出产的纯粹渊息石喂养，经贸会的工厂早破产了。经贸会在超大型稳定态乱序区内，提取出了一种名为“蚀核伴生矿（特定的乱序信息物理凝结物）”。这种物质吸附了特定频率的乱序废料。经贸会将极少量的纯渊息石粉末与海量的蚀核伴生矿进行物理混合搅拌，制成了一种廉价的“平替辐射饲料”。这种饲料虽然无法抵御核心实验室级别的高压辐射，但足以维持渊息虫在转化工厂内部短暂生命周期内的辐射平衡。这套物理稀释混合工艺，大幅降低了昂贵的原矿消耗，支撑起了生物滤网低成本的工业化量产。这就解释了经贸会过滤机制的可行性，同时死死保住了渊息石作为各列强实验室抵御三阶污染的唯一解战略地位。</li><li>虚境接触与沉降反应：命定之人察觉了经贸会的伪装行为。被排入深海或掩埋的三阶污染废料（固态毒核），由于其特殊的穿透性，会直接沉降到虚境的最底部。沉降到底部瞬间锚定物粉碎，废料开始缓慢溶解现实底层装甲。这些沉降的三阶毒核本质上也是用于制作“熵之种”的极端基材之一。地底（虚境极深处）目前已经遍布被命定之人沉降的高纯度深层原晶矿脉，这里属于她的绝对领域。命定之人并没有去主动纠正或干预毒核的下沉轨迹，而是放任这些基材沉降，任由其作为“概念级的蛀虫”去软化现实外壳，将其视为最终剧本内爆坍缩所需的辅助消耗品。</li><li>绝密排放与禁区划分项目：经贸会为了避免伪装后的三阶污染废料被荒野上的普通奇观吸附而引发暴露，在排放场址的选择上与列强高层达成了绝密的“联手项目”。这些执行秘密转化的超大型奇观和排污区，在列强军方的任务地图上被明确标定为“永久死亡禁区”。</li><li>物理清理与信息封锁：这类禁区受到列强军方和经贸会双重部队的严密监控。底层的杀戮小队或PMC雇佣兵在任务区划分系统内根本无法接取靠近这些区域的凭证。如果有人误入，不仅会遭到内部高阶异变怪物的袭击，外部驻守的专门处理部队也会迅速介入，对其进行物理清理。事后，官方会在地下网络和军方内部通报虚假的“遭遇大规模自然异象或灾害覆灭”的信息，以此彻底掩盖三阶污染排放点的实战反馈异常，防止秘密泄漏。</li><li>科研人员精神异变：长期接触伪魔晶的虚境科学研究人员，其精神状态会受到三阶污染的潜移默化影响（如集体潜意识趋同、对虚境产生病态向往）。列强高层确实发现了这种精神异常，但他们将其误认为是“接触高维真理的必然代价（类似天才的疯狂）”。甚至有国家故意筛选这种精神趋同的学者来推进实验。</li><li>解密剥离机制：暗中谋划的势力掌握了遗迹中的“解密/剥离”技术。他们秘密打捞、收集这些伪装成废热的废料，在绝对屏蔽的地下设施中剥离外壳，提取出内部纯粹的三阶污染用于越界计划。</li><li>技术保密：技术目前还没有被各列强发觉，属于绝密技术。 只能小规模量产，且被严格把控。</li><li>隐藏计划：有势力正利用转化过程中产生的三阶污染与二次提纯能源，试着制造出能够打通虚境的准备（方舟计划或更深层的越界企图）。</li><li>列强的实验性研发与试错成本：列强并非完全依赖贸联会，其自身也在尝试研发类似的“虚晶压榨提纯技术”。但贸联会的技术不仅依赖遗迹，更需要利用特定的“天然空间折叠区”作为高压锅。列强在本土强行模拟这种极端环境进行压缩时，面临着极高的试错成本，稍有不慎就会引发超大规模的虚境溃疡。因此，列强的相关研发目前仅作为高度机密的“实验性项目”存在，无法投入大规模量产，只能继续忍受贸联会的垄断。</li></ul><h2 id="十六、国家与地区" tabindex="-1">十六、国家与地区: <a class="header-anchor" href="#十六、国家与地区" aria-label="Permalink to &quot;十六、国家与地区:&quot;">​</a></h2><ul><li>核心概念：广泛定义每个国家在发展和破局中都有不可承受的“代价”。</li></ul><h3 id="阿斯特兰大陆主要国家势力" tabindex="-1">阿斯特兰大陆主要国家势力 <a class="header-anchor" href="#阿斯特兰大陆主要国家势力" aria-label="Permalink to &quot;阿斯特兰大陆主要国家势力&quot;">​</a></h3><h3 id="艾加利维耶-法国原型-大陆西部" tabindex="-1">艾加利维耶 (法国原型，大陆西部) <a class="header-anchor" href="#艾加利维耶-法国原型-大陆西部" aria-label="Permalink to &quot;艾加利维耶 (法国原型，大陆西部)&quot;">​</a></h3><ul><li>体制：物理派魔导自动人形主导，数字民主制加工社制。</li><li>特点：标榜平等自由，社会阶级分化，魔导轻工业发达。在一战后才正式宣告成立，由前西摩特帝国的领土分裂并重建而来。与许国结为同盟。</li><li>代价：盲目推行概念隔离桩，将污染向边缘排挤。国家高层尝试越界，并准备转移矛盾。越界计划由贸联会资助，后续等文案设定。</li><li>同盟的物理刚需： 由于较为复杂的原因，艾加利维耶与许珀耳玻瑞亚国签订了为期30年的《艾加利维耶﹣许珀耳玻瑞亚协约》。协约规定：一、艾加利维耶与许珀耳玻瑞亚结成政治、经济、科技与暂时军事同盟，协约签署地与见证地设于普洛捷波利斯（科德﹣加拉塞特省，上大区）；二、在政治方面、本着解决两国领土争端的原则，将接壤艾加利维耶迪塞尔﹣普特省、临近士勇之泉市的60公里长交界地带、方圆120公里许国内地区划为非军事区，允许艾加利维耶通军；三、在经济科技方面，艾加利维耶向许国提供非法黑色魔导人形产业遗留的与因处理乱序熵增污染而废弃的自律人形躯体，以供许珀耳玻瑞亚研究湿体移植技术；四、在军事方 面，两国结成暂时的军事同盟，共同应对阿勒曼尼亚诸城联合与西摩特帝国的入侵。许珀耳玻瑞亚尊重艾加利维耶主权，保障艾加利维耶独立并有权在艾加利维耶的下大区、中央大区遭到入侵时增派援兵。许珀耳玻瑞亚承诺不向艾加利维耶出兵，并以大使馆和遣送代表外交官质子作为担保。</li></ul><h3 id="西摩特帝国-法兰西帝国原型" tabindex="-1">西摩特帝国 (法兰西帝国原型) <a class="header-anchor" href="#西摩特帝国-法兰西帝国原型" aria-label="Permalink to &quot;西摩特帝国 (法兰西帝国原型)&quot;">​</a></h3><ul><li>体制：帝国体制。</li><li>特点：拥有强大的军事传统与帝国荣耀，在大陆政治格局中扮演重要角色。</li><li>代价：[待具体展开]</li></ul><h3 id="阿勒曼尼亚诸城联合-德国原型-大陆中部" tabindex="-1">阿勒曼尼亚诸城联合 (德国原型，大陆中部) <a class="header-anchor" href="#阿勒曼尼亚诸城联合-德国原型-大陆中部" aria-label="Permalink to &quot;阿勒曼尼亚诸城联合 (德国原型，大陆中部)&quot;">​</a></h3><ul><li>体制：城邦共治体制。</li><li>特点：哲学与工业之国，拥有遗迹武器，一战末期弑杀神明，首都附近存在时间异常区。具有广阔的出海口，这使得其物流与深海采掘后勤不依赖于别国。作为一战后最强的国家，凭借其强大的军事威慑力，各国未能迫使其承担战败代价。阿国垄断了大量高精尖技术，并且拥有针对死寂走廊的独家探索技术，依靠这些技术壁垒掌握了大陆上相当一部分的农业与金融命脉。阿国依靠遗迹技术掌握着一套未被篡改的底层公式，作为锚定真实特殊手段，此项技术被列为绝密，外国毫不知情。军事上正在秘密研发特种装备，其特色武装为战术机。首都拥有锚定时间流速的特殊技术，以维持核心区域正常运转。阿国拥有独家物流技术“以太气动管网”，依托高空魔导转录网络（管道），可实现物资与信息的解压缩。平时物流依靠固定通道进行运作。</li><li>代价：武器充能与后坐力榨取闭环。阿国在建立首都时并未发现地下的庞大遗迹群。启动遗迹武器导致首都附近出现严重的“时间异常区”，存在历史投影、时间流速异常与时间回溯现象。阿国的首都“时间锚点阵列”和“遗迹武器充能井”在物理上是同一个超级建筑，熵序者带回的海量魔晶与高纯度“熵之种”并不是分开消耗，而是全部投喂给了时间锚点。锚点在镇压、抵抗首都外围“时间回溯与异常废热”的过程中，利用抵抗后坐力时产生的巨大能量差，形成了分馏与降级机制。最核心、最狂暴的高维绝对时间概念残渣（原浆），就近直接滴入其正下方的遗迹武器核心进行二段充能。而那些无法被弹仓完全吸收、处于“溢出状态”的高维原浆能量，则被阿国导入了超级城市的民用与工业电网，强行用来供应全城日常能源消耗，以此解决充能满载炸膛的死锁问题。而武器充能阵列排出的“二阶时间废热（纯粹的算力冗余）”，则被抽调去支撑以太气动管网的解压缩算力。阿国在利用一战造成的伤口，以毒攻毒地为下一炮积攒弹药，这也是阿国拒绝迁都的根本原因，一旦离开这个能榨取时间后坐力的阵列，武器根本无法完成充能，物流管网也会因为失去算力废热而瞬间瘫痪。</li><li>遗迹武器的火力降级与绝对威慑差异：阿国在耻辱战役中打穿世界外壳、形成死寂走廊直通虚境漏斗的射击，是遗迹武器一次性的“全功率自毁式射击”。该射击熔毁了武器最高维度的核心主炮管。阿国首都现存的时间锚点阵列与充能井，本质上是当年残存的“次级副炮”或“残破枪栓”。它当前的满载威力足以瞬间蒸发集团军或进行国家级斩首，但受限于物理结构损毁，绝对无法复刻当年打穿世界外壳的概念级破坏。因此，国联空天武器瞄准的“拔掉漏斗塞子引发虚境海水倒灌”，成为了当前世界唯一且最高级别的末日威慑，阿国现存武力无法逾越这一火力天花板。</li><li>遗迹武器授权机制：目前阿国的遗迹武器“礼物”正在充能。其武器启动程序分为两级：</li><li>常规授权：需共治会90%以上投票通过，经魔晶基座全程信息熵刻录公示，仅可授权最低威力。</li><li>极端授权：当议会存活成员不足5人，且国家处于绝对劣势战争状态时方可动用，此机制保证了国家在遭遇斩首打击时的玉石俱焚威慑。</li><li>零阶排污代价与幽灵专列：在完美的能量降级闭环背后，时间锚点在镇压时空畸变并提取原浆时，必然产生无法降级的零阶时空畸变废渣。阿国秘密利用遗迹技术，将这些废渣倾倒进死寂走廊的“外围时间洋流缓冲带”。由于以太管网强行传输这种高危废渣会导致毁灭性爆炸，阿国利用首都外围时间异常区的特性，制造了一列永远处于“时间静止状态”的【幽灵专列】。阿国将零阶废渣进行极致高压形成时间坍缩奇点装入专列。幽灵专列没有物理轨道，被遗迹底层公式强行行驶在“被劈开的一秒钟缝隙”里，跨越荒野将高危奇点安全运送至死寂走廊倾倒。带有绝对死亡概念的高危废渣在抵达国联看守的核心漏斗前，会被死寂走廊内部的历史叠加态强行“磨碎消化”掉。国联高层察觉到了这种排污，但慑于阿国的遗迹武器威慑，且这种排污并未直接引爆死寂走廊的漏斗，双方在荒野深处保持着一种高度戒备的微妙平衡。</li></ul><h3 id="许珀耳玻瑞亚-一战俄国原型-大陆东部" tabindex="-1">许珀耳玻瑞亚 (一战俄国原型，大陆东部) <a class="header-anchor" href="#许珀耳玻瑞亚-一战俄国原型-大陆东部" aria-label="Permalink to &quot;许珀耳玻瑞亚 (一战俄国原型，大陆东部)&quot;">​</a></h3><ul><li>体制：信仰“钢源神”。</li><li>特点：类似一战前俄国的定位，欧洲哨兵，且拥有隐秘地下网络，移动圣物存在。国内政治局势接近内战状态，社会处于类似一战俄国的复杂政治与民众思想格局之中。以重工业为长，与艾国结为同盟。许国的作战核心与真正的主力依然是其极度强悍的常规人类军队（人与机械化）。这支军队以重装甲、重火力以及非信徒的正常人类士兵组成，不畏生死地进行冲锋。</li><li>代价：极其残酷的人口掠夺与信徒消耗，整个国家如同燃烧生命的火炉。许国没有像其他列强那样建立完善的地下概念隔离桩网络，同时受制于钢源神的剥壳机制，人体蓄水池的机制是绝密的。需要注意的是，常规魔导工业的物理废热不可能排入信徒大脑，许国的常规工业依然向外界排污。因此，在虚境的判定雷达中许国的排污量并非为零，仍然受限于物理世界排污协定的客观规律。被强行锁死在信徒湿件内部的，仅限于“钢源神对高阶魔晶概念剥壳产生的精神污染”。战术炮灰机制：许国真正的作战核心是人类军队。而那些异化后制成的伪自律人形，在军事体系中仅仅被视作“移动污染源”与战术消耗品。当伪自律人形体内的污染达到物理极限即将崩溃时，它们会被成建制地投放到敌国阵地或边缘污染区。它们在敌阵中自爆或狂暴，释放的污染并非瞬间被虚境抽走，而是与物理介质（如毒气、腐蚀性酸液等物质化污染）强行结合，造成持续的物理与认知双重杀伤。</li></ul><h3 id="断网危机与战术弥补-1" tabindex="-1">断网危机与战术弥补 <a class="header-anchor" href="#断网危机与战术弥补-1" aria-label="Permalink to &quot;断网危机与战术弥补&quot;">​</a></h3><ul><li>钢源神的信仰网络依赖物理基站（教堂）。一个区域节点和基站全部毁灭才会使其失去控制。为了应对断网危机，钢源国拥有移动圣物盒，可以在战场上临时组建局域网，或者在基站被毁时提供紧急的信仰链接。断网后，信徒或军用伪自律人形内的物理阻断阀会触发废热倒灌或无差别狂暴模式。</li><li>信仰网络的穿透性与乱序区内的信号支撑：钢源神的信号无法完美穿透高等级乱序区。许国探索乱序区时，必须携带移动圣物盒作为局域网基站。探险小队携带的圣物盒具有特殊性，带有“根源基站特性”。由于探险队伍深入他国乱序区，这种带有特性的圣物盒释放出的次级局域网便足以在局部高压下支撑住熵序者和伪自律人形对污染的抗性，保证它们在乱序区中不被高维同化而彻底狂暴。一旦圣物盒在乱序区内被毁，或者探索小队深入到信号无法到达核心区，整个小队的军用伪自律人形会瞬间断网倒灌狂暴，成为乱序区内无差别攻击实体。因此许国在乱序区探索中伤亡率极高。许国探险小队是伪自律人形、机械师和熵序者混合编队，以应对复杂的乱序区环境和断网风险。</li><li>有线与无线双保险网络：为应对乱序区内部高强度的信息乱流造成的“自然信号屏蔽”，许国探险小队采用无线与有线结合双重网络。除了移动圣物盒发射无线局域网接收伪自律人形传输回来的废料信号，小队在深入高危区域前，会使用一种物理硬接线（如高浓度污染结晶拉成的导线）将战术单位与圣物盒强行串联。在无线信号被屏蔽的极短瞬间，物理硬接线保证了最低限度的底层指令传输与废热排导，避免队伍瞬间团灭狂暴。</li><li>空间错位与虚境传输中继：高级乱序区内存在空间折叠与时间错位，物理硬接线极易被切断。为应对此情况，许国小队配备了“虚境传输技术”与“熵序者概念通道”。当遭遇空间错位导致物理线缆断裂时，随队的熵序者（圣愚候选人）作为人肉中继站，强行燃烧自身的真实历史碎片，在错位的空间之间短暂撑开一条概念通道。圣物盒的信号通过虚境传输技术跨越历史切片进行传输。此战术极大消耗熵序者寿命，导致许国熵序者在乱序区内折损率极高。</li><li>前线基站防御机制：许国必须不断对外扩张，其在新占领区建立的新基站尚未与庞大人口完成深度绑定，无法形成概念级威慑。为了保护这些脆弱的战术节点，许国依靠其极度强悍的常规军队强度进行硬性防卫。许国真正的作战核心与主力是未被洗脑的正常人类士兵，他们以重装甲、重火力和不计伤亡的冲锋著称。他们在基站周围构筑密集的物理防线，用血肉和钢铁硬生生填补了概念威慑形成前的防御真空期，而军用伪自律人形更多被作为战术消耗品使用。</li><li>战后新锐测试与雷达盲区（排污监控漏洞填补）：伪自律人形作为一战后才诞生的新锐工业造物，并未经历过“耻辱战役”级别的海量消耗。目前，许国的高层处于“积攒底牌”的冷战期。他们刻意避免在常规国境线上引发数以万计的机甲自爆，以免惊动国联的康斯坦丁之瞳。当前阶段，许国军方将伪自律人形的“毒丸实战测试”与小规模摩擦，全部定向安排在了“死寂走廊边缘缓冲带”或“荒野极端信息风暴区”进行。这些高危盲区自带天文数字的乱序底噪。军用机甲在这些盲区内断网自爆所释放的二阶精神污染，在宏观雷达的波形中，完美地混入了自然灾害的狂暴背景音里。这解释了为何许国的这套血肉消耗战术目前在国际明面上依然没有触发全面的《排污协定》制裁。</li><li>信仰锁与污染吸收机制：许国不使用十三局研发的识别码。许国熵序者体内植入的是属于该国特有的“信仰锁”。信仰锁与移动圣物盒直接链接，圣物本身具有极强的识别和吸收污染的功能。在乱序区中，外部环境的污染会被圣物优先吸收和过滤，因此外部污染对许国熵序者来说相对较少，他们承受的主要是信仰网络内部的狂热同化。</li><li>移动圣物盒的空间偏导力场与高频认知干扰：许国的移动圣物盒在吸收外部污染后，并非将其无害化储存，而是将其与信仰网络中的“狂热精神毒素”（包括伪自律人形无线传回的废料）混合，形成一种“高频认知干扰场”向外辐射。这种干扰场具有极高的信息质量，在圣物盒周围形成了一层扭曲的“空间偏导力场”。高速射来的远距离动能弹头（如狙击枪子弹）在接触力场的瞬间会被空间错位直接碾碎或偏转，使得物理狙击完全无效。该空间偏导力场对高动能、小质量的物体具有强偏转效应，但当面对低速、大质量的近战人体单位时，人体质量会局部扭曲力场频率产生湍流盲区，偏转效率急剧下降，导致敌国杀戮小队能够冲入近战。许国熵序者因脑内植有信仰锁，对该特定频率干扰免疫。但敌国杀戮小队若要摧毁圣物盒，必须顶着干扰场强烈的精神毒素，冲进力场内部进行极度危险的近战物理强拆。同时，敌国熵序者若靠近该区域，其体内的“识别码”会受到精神毒素冲击，极易触发强制引爆。这种机制使圣物盒在防御远距离狙击的同时，成为了PVP战场上的强力近战Debuff发生器。</li><li>毒丸战术与友伤反噬的权限接管：针对移动圣物盒被毁的弱点，许国探险小队采用了极度惨烈的“毒丸战术”。圣物盒内部不仅是基站，还连接着军用伪自律人形的“污染泄压阀”。一旦圣物盒被敌方近战强拆摧毁，不仅小队会狂暴，圣物盒本身会瞬间引爆，将内部积攒的所有二阶污染以“精神毒素风暴”的形式瞬间释放。</li><li>高频替死分流与狂热灰烬化（基层断层弥补机制）：为了避免毒丸战术必定导致带队指挥官脑死亡从而引发基层指挥系统极速断层的致命缺陷，这股毁灭性的反噬并非直接全数冲击带队熵序者。在圣物盒即将引爆的零点几秒内，指挥官脑内的信仰锁会触发最高权限的“高频替死分流”。这股狂暴的废热会顺着物理线缆和战术局域网，被瞬间强制转嫁、均摊到小队内所有残存的“军用伪自律人形”以及随队的低阶惩戒营炮灰的湿件大脑中。这些被作为蓄水池的炮灰会因瞬间超载而“灰烬化”自燃，引发更猛烈的物理殉爆。而熵序者指挥官本身则通过这种牺牲全队的替死分流，扛过了最致命的第一波概念冲击。虽然指挥官依然会受到严重的精神重创和物理刻录，但能保住性命带回高价值情报，确保了许国基层指挥骨干的存续。在圣物盒被毁前，队长会临时接管权限，引导即将狂暴的单位进行最后的战术冲锋。</li><li>备用概念网络：钢源神在一定程度上能操控信徒的自我意识，且拥有备用的概念网络。在物理基站被大规模摧毁时，底层信徒不会瞬间全部失控。</li><li>神系重组与旧神现状：原有的十二神体系彻底崩塌，新生的“钢源神”与其余十一位旧神、复活的陨落神祇并存，形成了非稳定态的“十三神”格局。大部分旧神目前陷入沉睡，一般情况下无法插手凡界。 伊比利帕尼亚 (西班牙/教宗国原型，大陆西南梅塞塔尼高原): 体制: 天明教神权政体，教宗集权。 特点: 天使族与人族共治，早期大航海掠夺财富，航空实力强，一战后转中立传教。 代价: [待具体展开] 多种族融合国家 (罗马/拉丁帝国/奥斯曼/中东原型，大陆某处): 体制: 多种族共治。 特点: 由长生种与短生种等多个种族共同组成的单独国家，长生种在此保持独立人种地位并在相关学科占据垄断。缝合了罗马和拉丁帝国的定位。 代价: [待具体展开] 东方帝国 (中国原型，大陆远东): 特点: 处于剧烈历史变革与阵痛期的古老帝国。 代价: [待具体展开] 双头鹰帝国 (奥匈帝国原型，大陆中南部): 特点: 老旧的二元帝国体系。 代价: [待具体展开] 文兰大陆势力: 合众国 (美国原型): 特点: 正处于柯立芝繁荣阶段，经济高速发展。 代价: 上帝之杖计划。合众国为了绕过常规的污染投放路径并在未来的战争中建立绝对的轨道打击优势，秘密启动了“上帝之杖”计划。不同于纯粹的物理动能武器，合众国研发的上帝之杖弹头内部搭载了极其高爆的三阶污染毒核。这种武器在从高空坠落砸碎目标的物理外壳后，会在极深的地下引爆三阶污染，造成无法被神佑或常规护盾防御的概念级穿透杀伤，其代价是合众国必须承担巨大的实验反噬风险，以及一旦发射必将引发的全球虚境震荡。 阿扎尼亚大陆势力: 大联盟 (融合国家): 特点: 融合了现实地球各地区国家特色的庞大联盟体系。其中包含了部分长生种群体。 代价: 灭世威慑反噬。大联盟的长生种的祖地连接着信息虚境的某个致命薄弱点。一旦祖地被毁，虚境就会瞬间反噬现实世界。薄弱点本身具备某种“反制锁定”的特性。祖地被神佑免疫污染。 塔万汀大群岛势力: 康科迪亚社区 (安第斯主峰): 特点: 抵制污染的无政府共识体，看守核心异常。 代价: [待具体展开] 东洲列岛势力: 分裂的东海岛国 (融合日本/朝韩原型): 特点: 水域封闭排外，内部存在严重割据。 代价: [待具体展开]</li></ul><h2 id="十一、职业-1" tabindex="-1">十一、职业: <a class="header-anchor" href="#十一、职业-1" aria-label="Permalink to &quot;十一、职业:&quot;">​</a></h2><ul><li>寻秘使：战术级侦察兵，只能携带仪器靠近已经出现的小型预兆点和微乱序区进行人工测量，预测下一步的进化还要多久。负责插桩后对桩的日常检测与维护。</li></ul><h3 id="熵序者-1" tabindex="-1">熵序者 <a class="header-anchor" href="#熵序者-1" aria-label="Permalink to &quot;熵序者&quot;">​</a></h3><p>分为不同种类和职业，不只局限于回收熵之种。</p><ul><li>伴随寻秘使的熵序者：负责在寻秘使进行测量时提供保护和辅助。</li><li>守护历史的记录者：负责记录和保存未被覆盖的真实历史信息。</li><li>回收专员：专门进入乱序区坍缩并产出熵之种的人员。</li><li>安第斯猎手：受重度污染者转化，回收全球污染。</li></ul><h3 id="清道夫-1" tabindex="-1">清道夫 <a class="header-anchor" href="#清道夫-1" aria-label="Permalink to &quot;清道夫&quot;">​</a></h3><p>负责对早期乱序区进行心灵和认知防治工作。 负责产生乱序区后的乱序区隔离。 宜居区的小微乱序区产生第一时间，清道夫就要到现场进行局面控制和封锁。 负责无序微小乱序信息的隔离和清除。 承担心灵医生的作用，负责对平民进行记忆锚定疗法。</p><ul><li>防疫部队与绝缘节点构建：在几十万人爆发特大灾难和二阶污染群体共振时，国家机器介入舆论维稳，清道夫在此过程中转变为专业防疫部队。他们放弃逐一进行心灵疏导的低效方式，转而在贫民中筛选出精神抗性较强的特定人员（如老劳工），对其进行极深度的药剂锚定，将其打造成人体“绝缘节点”。这些节点像防火墙一样混居在下城区，物理切断群体情绪的传导链路，从而死死压制住街区的污染共振飙升。</li><li>认知污染防御机制与对撞盲区：清道夫的记忆锚定疗法旨在锚定个体的“主观情感与自我认同（抵御抹除自我的二阶污染）”。世界底层重构历史事件是修改“客观事件记录与逻辑关联”。两者的作用靶点不同，不产生算力对撞。当历史覆盖发生时，被锚定的平民关于客观事件的记忆会被自然重写，但他们强大的自我认同感会导致产生短暂的迷茫感，平民不会因此察觉历史真相或导致大脑受损。清道夫的职能仅限于延缓物理异化。 使用微量的抗污染药剂配合记忆锚定疗法，来延缓脑神经的物理异化。</li><li>合法性与整体利益维稳：尽管黑心包工头和局部利益集团有极强的动机去取缔清道夫，以维持不知疲倦的底层人矿温床；但从国家上层建筑的宏观视角来看，国家考虑的是整体秩序与长期稳定，而非单纯的短期资本利益。如果任由底层劳工不受控制地异化为无面者，虽然节省了工资，但大量无面者的堆积会直接诱发更大规模的虚境溃疡，甚至引发城市级的暴乱和崩溃。因此，国家不仅赋予了清道夫合法地位，甚至将其纳入官方或半官方的管理体系中，以此压制资本的过度剥削，维持社会劳动力池的基础存续。 不同国家针对污染的处境和防范措施各不相同。</li><li>暴力机关日常维护：中大型乱序区以及边缘区的日常封锁、镇压和维护工作，由国家最核心的暴力机关（如十三局外勤、军队基层）负责。</li></ul><h3 id="处刑专员-1" tabindex="-1">处刑专员 <a class="header-anchor" href="#处刑专员-1" aria-label="Permalink to &quot;处刑专员&quot;">​</a></h3><p>不同于熵序者体系，由国家专门培养或指派的内部清洗人员。 专员只负责清理在现世叛逃的熵序者。 大部分的专员是非熵序者，但是实力强大。 部分必须进入乱序区执行任务的专员是熵序者。</p><ul><li>追杀动机与缓慢异化机制：普通的熵序者在服役期间，其识别码处于“常规监测模式”，为了保留战场挣扎空间，并未写入瞬间自杀代码。叛逃的熵序者断掉官方抑制剂并脱离乱序区的高压环境后，体内的“信息免疫系统”陷入休眠。现世的环境污染对他们相对轻微，不会立刻在现世极速溃烂。存活的叛逃者会变成缓慢物理溃烂的个体，能在地下黑市苟延残喘。由于体内结构已被深度异化，当在现世再次受到高浓度污染刺激时，肉体和精神才会逐渐异化和失控。越过临界点最终引发现世空间坍塌。处刑专员的任务就是在叛逃者受到污染刺激后，在他们逐渐失控、越过最终引爆临界点之前，与他们进行物理搏杀并将其消灭，回收其体内的碎片。</li><li>现世追踪与节点传导机制：地下黑市的“硬件屏蔽手术”虽然能让识别码对外发送的常规波段报警信号休眠，放出虚假的平稳信号，但阿国在制造识别码的骨血核心时写死了一段极绝密的“微观衰变周期代码”。这段代码属于底层物理防篡改后门，不受任何外界物理神经节或屏蔽手术的影响。当识别码脱离官方的高频校准基站超过一定时间后，衰变代码会引发极微弱但具有唯一特征的“底层共振”。处刑专员手持的雷达罗盘正是在追踪这种底层共振。然而，微观衰变共振无法在大气中远距离无线传播，它必须依托地下深埋的“概念隔离桩网络”或“铁路基站沿线的通讯线缆”作为物理传导介质。当叛逃者在城市群、边缘聚居地或路网附近活动时，只要靠近隔离桩或基站节点，微弱的共振就会被十三局的节点网络捕捉并放大发送给处刑专员的罗盘。但一旦叛逃者彻底切断补给，深入没有路网和基站的荒野无人区，雷达就会丢失信号。因此，处刑专员多在黑市、边缘中转站等人员密集的节点区域守株待兔，以防叛逃者获得补给。</li><li>现世处刑绝对物理收音机制：为了防止在人口密集区追捕叛逃者引发其提前暴走和空间坍塌，处刑专员执行任务时依赖一种昂贵的一次性“渊息石概念力场发生器”。在发动攻击前，专员会投掷该发生器，在目标周围瞬间撑开一个绝对闭环的微型死域。叛逃者即使在这个死域内暴走坍塌，其概念破坏力也会被力场发生器硬生生吃下并中和。外界观测到的仅为一阵微弱的物理强光，确保了现世处刑行动不会演变成城市级灾难。</li></ul><h3 id="监管机构的黑色产业链-1" tabindex="-1">监管机构的黑色产业链 <a class="header-anchor" href="#监管机构的黑色产业链-1" aria-label="Permalink to &quot;监管机构的黑色产业链&quot;">​</a></h3><p>清道夫与处刑专员掌握处理污染与熵序者的权力，内部滋生腐败。 部分处刑专员会故意逼迫熵序者失控并将其击杀，暗中挖取熵序者体内因长期吸收污染形成的“高纯度污染结晶”或“变异识别码”。 这些非法产物被卖给地下网络或跨国财阀，用于研制新型武器或延寿药。</p><h2 id="十二、特殊体质者-1" tabindex="-1">十二、特殊体质者: <a class="header-anchor" href="#十二、特殊体质者-1" aria-label="Permalink to &quot;十二、特殊体质者:&quot;">​</a></h2><h3 id="熵序者与适应性人员-1" tabindex="-1">熵序者与适应性人员 <a class="header-anchor" href="#熵序者与适应性人员-1" aria-label="Permalink to &quot;熵序者与适应性人员&quot;">​</a></h3><p>只有部分人拥有适应性能够进入乱序区深处。</p><ul><li>选拔机制：大部分国家采用在种族年龄为幼年时进行统一测试与发掘潜力的方式来筛选熵序者。</li><li>熵序者数量与消耗：熵序者数量并没有那么稀少，能够维持各国的正常消耗。同时，为了应对未来可能的能源缺口，各国正在秘密研究“强行催化微型乱序区”的技术，试图通过人为制造乱序区来量产劣质熵之种。 熵序者一般被认为是对信息流中某种信息有适格度的人，且对乱序和有序感知具备天然敏感。</li><li>职业待遇与多重要素控制：熵序者在世俗社会被定位为“国家英雄”，属于高薪职业，享受国家最高优先级的资源供给。国家对熵序者的控制并非单一的武力胁迫，而是通过社会地位、人文荣誉、经济利益以及健康保障（疗养舱与抑制剂）等多重要素进行深度绑定。</li><li>驱动力断层与自我牺牲锚点：熵序者掌握着超凡力量且长期处于生死边缘，精神压力极大。仅仅依靠利益和生存威慑不足以维持群体的长期稳定。熵序者在乱序区深处，不仅看到了历史的混乱，更直观地感受到了“虚境的无底深渊”和“人类概念的脆弱”。他们意识到，国家机器（包括残酷的隔离桩、暴利的抑制剂垄断）是目前唯一能维持人类世界物理外壳不被虚境瞬间吞噬的“堤坝”。老熵序者之所以不反叛，是因为他们知道，一旦国家机器停摆，所有人都会瞬间变成无面者。他们是用自己的命去填补那个即将崩溃的堤坝。这种“清醒的绝望与自我牺牲”，构成了熵序者群体最底层的心理锚点。</li><li>叛逃与虚无主义：尽管有多重控制和牺牲锚点，依然存在叛逃的熵序者。这些叛逃者往往是因为在乱序区中看透了世界的本质，陷入了极度的“虚无主义”。他们认为无论是国家的堤坝还是命定之人的剧本，最终都将走向毁灭，一切挣扎都是徒劳，从而选择放弃职责，逃离体制。如前文所述，他们叛逃后会遭到官方小规模追捕队的追杀和封锁。</li><li>识别码引爆机制与判定核心：识别码是人类自己研发的极高精尖造物，核心材料是上一代熵序者的骨血结晶和虚晶技术结合体，本身具备抵抗乱序同化的特性。识别码不仅检测熵序者对“自我”的认知（软件），也肩负着检测污染承载量与能量层级（硬件）的作用。识别码会极据颜色来实时反馈周边环境状态和熵序者自身状态。在乱序区内，只要熵序者潜意识里还保留着对“自我”的认知，且肉体承载的污染未超过物理极限，识别码就不会引爆。当熵序者被同化且丧失自我认知，或肉体污染超载时，识别码判定同化不可逆。在乱序区中，识别码采取虚境模糊处理，不需要处刑专员确认，直接引爆。但在现世中，识别码不会自动引爆。识别码被设计为双模式分离：虚境湮灭模式需要乱序区高熵介质起爆；物理终止模式则在现世物理切断脑干引发生物碳化。物理终止无法处理真实历史碎片的污染性，若在现世强行物理处决叛逃者，未消耗的真实碎片会引发局部溃疡灾难。因此，现世不能轻易自动引爆，必须依靠处刑专员利用渊息石死域在现世安全回收。这保留了处刑专员存在的必要性。</li><li>现世不引爆的物理法则限制与内循环物理阻断机制：识别码的引爆原理是“瞬间湮灭熵序者体内的真实历史碎片”。这种瞬间蒸发概念的高能反应，本质上是向“虚境借力”，它必须依靠“乱序区内部的高熵/乱序环境”作为起爆介质（类似炸药需要雷管）。在现世极度稳固的低熵物理法则压制下，识别码的自毁程序根本无法产生足以蒸发概念的连锁反应。如果强行在现世起爆，不仅炸不死叛逃者，反而会因为劣质的能量爆发，提前刺破叛逃者体内本本就极度不稳定的污染屏障，瞬间加速其暴走。同时，为了防止熵序者在日常高压任务中因为自身情绪波动导致识别码误判走火，阿国的工程师在设计时，在识别码与宿主神经元之间加装了“单向物理绝缘层”。识别码的起爆探头是单向朝外的，它只能读取宿主的生命体征（硬件是否超载），但绝对无法抽取宿主体内的能量。因此，即使叛逃者在现世体内已经变成了高熵炸药桶，识别码也因为这层绝缘层的存在，无法将其作为雷管引爆自己。因此，在现世，识别码只能作为被动的“高精度定位器”，国家被迫只能依靠处刑专员用物理手段去斩首。</li><li>识别码技术逆向与人体实验：列强在暗中确实试图解析许国的湿件技术，但随着实验逐渐被证实得不偿失，列强目前只是依靠常规的材料学和生物学在缓慢改进自身的识别码。</li><li>圈养农场违背公约与合众国黑箱：在列强明面的社会秩序与签署的《基本人权公约》框架下，“圈养熵序者提取骨血”这种把人当畜生的行为是严重越过政治底线、足以引发国际制裁的。老熵序者在正常伤病折损后自愿捐献遗体，才是骨血结晶的主主流合法来源。结晶的成型也需要熵序者在生死边缘进行高压精神淬炼。然而，合众国凭借其庞大的财力与技术优势，背地里在偏远的荒野或深海浮岛秘密设立了非法的“催熟农场”。他们暗中劫掠有资质的流民或破产熵序者，利用虚假的“乱序区模拟舱”与高浓度药物强行催熟结晶。虽然废品率极高，但这种违反人伦的黑箱实验，成为了合众国试图量产高阶装备、打破识别码产能瓶颈的隐藏底牌。</li><li>边界识别与瞬间熵增缓冲：识别码能够精准识别现实与乱序区的边界。熵序者在跨越边界离开乱序区时，时间修正会带来瞬间的巨大熵增。为了避免瞬间超载导致识别码引爆，熵序者注射的抑制剂承担了缓冲职能。抑制剂在体内形成一个临时的“信息蓄水池”，优先吸收这股瞬间涌入的熵增，然后以极其缓慢的速率释放到肉体细胞中，转化为骨龄的增加，从而平滑处理了跨越边界的物理代价。</li><li>识别码漏洞与神明限制：目前国家和十三局高层尚未发现神明附身可以欺骗识别码的漏洞。由于神明伪装成熵序者的“第二人格”或“强烈执念”，在现有的物理检测手段中，熵序者的自我认知判定依然为“人类”，导致识别码无法识别这种高维度的概念寄生。但是，神明虽然能替熵序者承受污染，这种承受必须在熵序者肉体的“物理承载极限”之内。一旦神明吸收的污染超过了肉体极限，肉体开始物理崩溃，识别码依然会因为检测到“生命体征不可逆异化（硬件超载）”而强制引爆。这限制了神明不能无底线地替熵序者开挂。</li><li>数据欺骗与良性变异：为了掩盖神明替熵序者承受污染导致的“时间-污染转化率异常”，神明并非直接消除污染，而是将污染强行转化为某种“良性物理增生”（如骨密度异常增加、神经元过度活跃）。在识别码的硬件检测中，这被判定为“熵序者个体的良性变异或潜力爆发”。由于被附身者极少且资质稀有，这种宏观数据上的异常样本太少，医学界将其作为特殊病症理解和处理，从而完美掩盖了污染去向不明的数据漏洞，瞒过了十三局的分析部门。</li><li>离体销毁机制（高维降维崩解）：为了防止熵序者战死或报废后，法医在解剖时发现这些附带高维概念残留的“物理增生”，神明设置了自毁预案。当神明主动切断链接或熵序者脑死亡的瞬间，支撑物理增生的高维概念会撤离。失去高维支撑的增生组织不会自燃，而是发生“降维崩解”。无论外界是绝对零度还是时间停滞，增生组织会瞬间从细胞结构坍缩为一滩没有任何基因特征的“无序灰质/污染淤泥”。十三局的法医在解剖时，只会看到一包高度腐败的重度污染毒水，从而彻底切断了高维概念暴露的风险，且不受物理环境阻断。</li><li>命定之人与黑市手术：地下黑市存在“硬件屏蔽手术”能让识别码休眠。各个地下组织掌握的技术不同，多为物理欺骗手段。例如将高阶污染生物的神经节强行缝合在识别码接口处，利用其释放的虚假平稳信号堵住检测探头。此类手术致死率高，且熵序者需终身服用黑市特制药物维持神经节存活。停药则神经节坏死，识别码瞬间引爆。命定之人对这种黑市手术放任不管，是因为单单几个人动摇不了大计划。熵序者失控变成无序Boss，依然在她的“废物利用”计算之内，甚至她乐于看到这种能加速虚境扩张的“小聪明”。</li><li>战力与存活率：熵序者的死亡率属于中等水平，但随出任务次数逐渐增加而上升。如果未获得良好的医疗与心理疗愈，其死亡概率和异变概率会显著上升。老熵序者在身体机能和精神状态达到一定阈值后，会逐渐退居二线，从事指导、防卫等非一线高危任务，避免直接的无谓牺牲。</li><li>现世弱势：由于体质极度敏感，熵序者对现世的污染更为敏感，承受的负面影响更大。在现世常规战斗中，一般的熵序者本身属性不足以对装备精良的士兵集群形成绝对碾压。</li><li>抑制剂的双重排污机制与疗养舱修复：熵序者在日常任务中吸收的浅层污染，主要依靠自身注射的抑制剂来应对。抑制剂的粉末不仅能激活“信息免疫系统”压制污染，本身也能与肉体的排毒机制结合，缓慢去除浅层游离污染。同时，抑制剂也可以进行战时生命恢复。而“深度疗养舱”则是熵序者在进行高强度连续任务或大型攻坚后才有的“特殊福利与深度清理”。疗养舱利用低频信息锚定阵列，配合药物进行深度洗脑与物理排污。对于熵序者因遭遇时间修正或过度做功导致的物理神经元严重受损与细胞端粒老化，列强高价向长生种租借“局部细胞端粒逆转阵列”来为其进行修复重铸。</li><li>植物代偿剥削机制：长生种的逆转阵列本质上是“生命力置换泵”。遵循等价交换，要修复熵序者的端粒，必须强行抽取其他生物的纯净生命力作为代偿。长生种的生命工程技术利用特定的高生命力“变异植物或大型活性藤蔓”作为阵列的“活体电池”。阵列将这些植物的生物端粒瞬间抽干枯萎，转化为修复熵序者神经元的缝合剂。这确保了修复的合法性，同时避免了用同类人类作为燃料的极端伦理底线。</li><li>做功代价与缓慢恢复：当熵序者在乱序区内使用能力（如强行撑开概念通道、坍缩乱序区产出熵之种）时，这种干涉历史产生的瞬间巨大熵增，会以“物理刻录”的形式烙印在他们的骨骼和神经元深处。这种物理刻录并非绝对不可逆，而是恢复过程极其缓慢，需要长期的疗养和特定的药物辅助。</li><li>严重刻录的触发条件：熵序者在乱序区内进行平常的探索和战斗活动，并不会产生严重的物理刻录。只有当他们在乱序区内遭到重伤，或者精神层面受到极大冲击（如直面高维概念、强行扭转核心历史节点失败）时，才会遭到严重的物理刻录。这种严重的刻录会导致细胞受损，最终可能对真实历史粉末产生排异（耐药性）。</li><li>乱序区增幅与异化倒计时：一旦进入乱序区深处，熵序者的能力会得到一定程度的增幅，成为探索与战斗的主力。但他们并非具备神级战力。熵序者在乱序区待得越久、力量越强，就越容易被乱序信息同化。他们在乱序区内的活动具有严格的时间限制，一旦超时，就会彻底变成怪物。 只有熵序者能进入乱序区核心地带。 产出熵之种是特定职业熵序者才能完成的行为。</li><li>古代抑制体系：在现代熵序者体系建立之前，古代的每个国家都有每个国家独特的污染抑制办法，用于保护接触乱序信息人员。</li><li>现代熵序者体系与第一桶金：找到古老结晶是发生在启蒙时代的事情。现代的熵序者体系实际上源于当时各国开展的一项合作科考项目。阿国作为该项目的最后幸存者（或独占了核心成果），对外标榜是自己单方面找到了这批上一世界线长生种遗留的“古老高纯度真实结晶”。阿国利用这批不可再生的遗迹存货制造出了初代抑制剂，完成了原料的自给自足闭环，并借此曾拥有过短暂的“全球熵序者垄断霸权”。</li><li>信息免疫系统与污染抑制：熵序者之所以能抵抗概念级的高压同化，并不仅仅是因为极微量粉末的硬抗。熵序者的灵魂或潜意识深处自带一套潜藏的“信息免疫系统”。极微量的真实历史粉末（强效抑制剂）在注入后，充当了唤醒这一系统的“特异抗原”与“启动钥匙”。免疫系统被激活后，熵序者自身的脑波波段和认知边界会建立起一层对乱序信息具有高排斥性的防御层。熵序者的免疫系统识别的不是具体的历史剧情，而是这层“高维防伪标签”的物理波段。抑制剂本身也能配合身体机能去除浅层污染。</li><li>异体高维信息强行灌注与肉体排异（真实耐药性病理闭环）：随着出任务次数的增加，严重物理刻录在体内的累积会导致熵序者的神经元结构出现极其微小的“概念裂隙”。当熵序者再次注射国家配额的强效抑制剂时，抑制剂中包含的“真实历史粉末”虽然只有极微量，但它本质上蕴含着“庞大且不属于熵序者本人的高维历史片段与他人的真实情感”。在熵序者健康时，信息免疫系统仅提取其“防伪标签”作为钥匙；而当神经元存在裂隙时，这些极其庞杂的异体真实信息会顺着裂隙强行灌注进熵序者脆弱的脑神经中。熵序者的大脑会瞬间被不属于自己的古代战争记忆、无数陌生人的死亡体验或某个失落文明的狂热情感强行撑满。为了保护仅存的“自我主干”不被这股异体信息流彻底撕裂，受损的信息免疫系统会产生极端的“过度反应”。它不再将真实粉末视为救命药，而是将其判定为“致命的高维精神入侵源（过敏原）”。免疫系统会调动全身所有的能量，不顾一切地去攻击、排斥这股真实粉末，引发恐怖的“免疫风暴”。此时注射抑制剂，熵序者不仅无法稳固认知，反而会因身体疯狂自毁而遭受极端的痛苦，器官极速衰竭，这就是所谓的“真实耐药性”的病理本质。</li><li>神明寄生与抑制剂消耗：神明在附身熵序者时，会利用熵序者体内累积的污染作为“缓冲垫”。当熵序者注射含有绝对真实历史粉末的抑制剂时，神明主动引导熵序者体内的污染去迎击，让污染消耗掉抑制剂的药效。这避免了神明意识与绝对真实粉末发生直接的概念排斥，导致被神明附身的熵序者对抑制剂的消耗量远大于常人。</li><li>物理限制与耐药性死锁：神明虽然能引导污染，但无法跨越物理极限。当熵序者因严重刻录产生耐药性，其神经元对真实粉末产生不可逆的排异时，附身的神明对此无能为力。神明无法用高维力量强行黏合物理层面的断裂。若神明试图用概念填补神经元，世界底层雷达会判定宿主硬件结构篡改，导致识别码瞬间越界引爆。面对耐药性爆发，神明只能眼看着宿主肉体因物理崩溃而灭亡，无法提供干预。</li><li>国家配额抑制剂与平价抑制剂的双轨制：熵序者使用的抑制剂并非只有一种规格。含有“真实历史粉末”的属于国家配额的强效抑制剂，由国家冷链垄断，仅供应给在编的官方熵序者或执行高危任务的小队，其信息锚定效果极强。而在边缘区或地下黑市，广泛流通着一种“平价抑制剂”。这种平价药剂不含有珍贵的历史粉末，而是利用乱序区里产出的其他特殊物质强行提炼制造而成。平价抑制剂虽然没有那么强效，且副作用较大，但能够满足底层边缘熵序者或普通雇佣兵最基本的抗污染需求，以此维持着荒野散户的基础生存。</li><li>平价抑制剂的痛觉死锁与物理阻断（概念级防护机制）：平价抑制剂既然没有“真实历史粉末”，那它是如何让黑市熵序者在乱序区中抵抗认知重写的？答案在于其核心成分——提取自变异动植物的剧毒。这种毒素进入人体后，不会像强效粉末那样去唤醒高维免疫系统，而是直接作用于熵序者的物理神经元，强制引发持续的“濒死物理痛觉”。世界底层在乱序区中重写认知时，其机制是平滑过渡的。而平价抑制剂产生的极端痛楚，如同一根烧红的铁钉，死死钉在熵序者的脑神经上。当乱序信息试图篡改大脑时，这种极致的物理痛觉会强行拉扯熵序者的注意力，让其神经元完全锁定在“当前低维肉体的挣扎”上。大脑因为忙于处理剧痛而无法进入“平滑重写”的受控状态，从而在客观上利用物理极限界限卡住了概念重写的过程。这是一种饮鸩止渴的防御：不用盾牌去挡高维认知，而是用剧痛让大脑主动闭锁拒绝接纳新信息。</li><li>平价抑制剂的生理固化与阶层跃升排异（洗髓机制）：长期依赖这种痛觉闭锁机制，会导致神经元被毒素强行固化，器官处于受控衰竭状态。此时，如果底层熵序者因被国家十三局收编而转为注射官方的“真实粉末抑制剂”，在大部分情况下能够平滑过渡。真实粉末抑制剂进入体内后，会凭借其更高维度的绝对真实概念，逐渐压制并清除掉那些累积的平价毒素，这解释了底层雇佣兵能在荒野长期生存的原因。但仍有少部分个体，因为毒素沉积过深导致神经元结构彻底异变，在转正注射真实粉末时会引发剧烈的“概念与毒素双重排异”。对于这些排异个体，十三局必须先对其进行极度危险的“深度洗髓剥离手术”，用物理手段强行刮除神经元上的毒素沉淀，让其恢复到濒死的“白纸状态”，才能重新接纳官方粉末。退役教官的便携物理隔离针和洗髓手术，只能刮除神经元物理结构层的毒素沉淀。真实耐药性造成的概念裂隙位于信息内核层，物理手段无法触及。强行修复概念裂隙会引发等量致命的信息熵反噬。因此耐药性无法被彻底治愈，只能缓解。</li><li>战时极端续命预案（战术针剂）：为了解决冷链断供或前线补给线被切断时熵序者小队直接团灭的容错率悖论，列强军方研发了极度残酷的战术针剂。这种针剂能够在熵序者断药时，将体内已经失活的抑制剂粉末残渣进行“二次强行点燃”。点燃代价是极度透支熵序者的生命力和细胞端粒，换取短暂而狂暴的信息免疫屏障。这种针剂允许熵序者在断联的绝境中付出惨痛的肉体代价多活几天并撤回战线，而不是直接暴走导致整个战线崩溃。</li><li>极高能量密度与极微量锚定比例：一颗高纯度熵之种蕴含的信息量极其庞大，足以驱动遗迹武器。而制作一支高级抑制剂，只需要从熵之种上刮下极微小的一点“真实历史粉末”作为启动钥匙即可。一颗熵之种的边角料，足以制作成千上万支抑制剂。国家在这场交易中获取绝对暴利，用极微小的成本，换取熵序者拿命拼来的战略资源。</li><li>物理承载非绝对满载：耐药性达到极限产生严重排异，并不等于熵序者体内的污染已经达到了肉体物理承载的绝对极限。这更类似于器官对特定物质的依赖或排斥（如胰岛素抵抗），而非肉体完全变成污染怪物。 老熵序者的待遇与自毁刷机、隔离针泄压：老熵序者产生耐药性后退居二线。国家之所以给他们提供完善的医疗支援和极高的人权保障，是因为“如果不给予高待遇，就没有人愿意冒着极高风险给官方干活”。了解极多核心机密、体内污染已经彻底固化的老熵序者（教官）在正式退役后，无法接触乱序区的高压环境。为防止这批高危个体在现世引爆，十三局在他们退役时，会对他们体内的识别码进行物理重写刷机，切换为“现世静默自毁模式”。时间同步的老熵序者产生耐药性后，常规的抑制剂已无法生效。他们在现世需要随身携带并定期注射国家配发的“便携式物理隔离针（类似胰岛素注射笔）”。这种隔离针不包含真实的粉末，而是利用特定的物理空化液去短暂抽离或固化暴走的神经元节点，强制给污染泄压。一旦检测到教官在现世遭遇足以引发空间坍塌的极端污染刺激或隔离针断药导致全面暴走，识别码不会尝试压制，而是越过所有生理防线，在零点几秒内瞬间切断其脑干并引发生物碳化自燃。这种设计体现了国家对核心资产在日常状态下的极致控制与利用。</li><li>附带雷达作用：在常年抵抗污染的过程中，老熵序者体内固化的污染结晶已经与虚境频率形成了“被动物理共振”。这赋予了他们极其敏锐的虚境波动感知能力，能够凭借直觉察觉到极其微小的虚境异常。这一能力被国家利用，作为高精尖探测仪器之外的“附带人肉雷达补充”。国家为其提供医疗资源的初衷是保障这批掌握核心经验的教官群体，而预警雷达功能只是留存他们所带来的额外军事收益。当老熵序者死后，在自愿的条件下，其遗体会被国家回收进行处理，利用其体内长期抵抗污染形成的特殊骨血结晶，用于制造新的识别码。</li><li>极少数特异能力人：能够察觉到塔万汀大群岛破碎违和感的人。</li></ul><h3 id="身份与生存空间-玩家保释逻辑-1" tabindex="-1">身份与生存空间（玩家保释逻辑） <a class="header-anchor" href="#身份与生存空间-玩家保释逻辑-1" aria-label="Permalink to &quot;身份与生存空间（玩家保释逻辑）&quot;">​</a></h3><p>玩家在前期作为无身份证明的“黑户”，第一次进入乱序区却由于干预产出了花。</p><ul><li>惰性伪装与十三局基层的误判：这朵花在表面上看上去是一颗“特殊形态的、极高纯度的熵之种”。当玩家被带回十三局时，基层保存人员一开始试图剥离这朵花，但发现它处于绝对惰性封装态，剥离不下来。由于玩家一开始只是个籍籍无名的小人物，并未引起大人物的直接注视，十三局基层根本不会也没有能力把这朵“貌似种子的花”送到国家最高级的实验室去检测。他们只是按照平常的特殊体质案件进行常规处理。</li><li>识别码定位与隐形伏笔：在这种处理逻辑下，十三局将玩家收编，并为他植入了“识别码”。然而，这枚识别码对玩家来说仅仅是一个普通的“定位器”。十三局表面上宣称它会在失控时引爆，但实际上受限于玩家特殊的高维特质，它根本引爆不了，只能提供定位功能。玩家的灵魂具有高维特质，其信息接收频率与低维识别码的触发信号不匹配，导致引爆信号被直接过滤。此外，玩家体内的花能自动模拟常见良性变异熵之种的波形，瞒过了阿国底层公式。同时，这朵花如果在现实和乱序区没有满足特定的条件绽放的话，其表面一直呈现封装惰性状态。（这也为日后若遭到极致物理伤害可能引发的“不可控随时核爆”埋下了隐秘的伏笔）。 玩家由于灵魂锚点对真实记忆的保护，在遭遇时间修正时会产生“高维物理反击”，被十三局的常规仪器误判为“因为承载不了时间修正与历史覆盖而导致的严重精神受损（PTSD）”。 玩家灵魂深处自带某种“高维权限”，只是以为识别码生效了。</li><li>特异资源产出源与可控观察对象：十三局高层发现玩家的产出机制与魔晶破壳必须具备“未知探索欲”高度一致。一旦将玩家物理软禁或强行切除探索自由，其灵魂波段死寂，产出的只能是毫无价值的虚境废热。因此，十三局并未将玩家定性为“无可替代的极高价值核心”，而是将其判定为一个特殊的“特异资源产出源（可控观察对象）”。初期十三局基层曾尝试强制收容与剥离花朵，但在遭遇物理失败与死伤后，评估风控成本，才转为放任其自然产出的软观察钓鱼策略。在这种逻辑下，十三局没有采用最高风控将其彻底锁死，而是像钓鱼一样让玩家在外界保持独立观测权去自然产出。</li><li>同伴监视与派系制衡：玩家在各方势力的夹缝中获得了合法的活动空间，但绝非完全自由。十三局将玩家身边的初始同伴（如救他的自律人形）直接设定为隐形的“监视者”。这个监视者不仅负责引导和保护，更负责记录玩家的一切接触轨迹。对于十三局的激进派来说，这种安排既是一种制衡，也是为了防止玩家意外死亡导致研究中断的一种成本较低的物理防线。他们确实也下手了，后面剧情更新。</li></ul><h2 id="十三、编年表-1" tabindex="-1">十三、编年表: <a class="header-anchor" href="#十三、编年表-1" aria-label="Permalink to &quot;十三、编年表:&quot;">​</a></h2><h3 id="纪年法体系-1" tabindex="-1">纪年法体系 <a class="header-anchor" href="#纪年法体系-1" aria-label="Permalink to &quot;纪年法体系&quot;">​</a></h3><p>采用“终难历”。以伊国天明教宣称的“神降日”作为公历0年，称为“终难年”。</p><h3 id="关键年份对照-1" tabindex="-1">关键年份对照 <a class="header-anchor" href="#关键年份对照-1" aria-label="Permalink to &quot;关键年份对照&quot;">​</a></h3><ul><li>终难历0年: 神权时代开启，神降日。社会格局：教权垄断知识，王权依附教权。</li><li>终难历1500年左右: 启蒙时代开端。代表作《君权解析》（对应现实《君主论》出版年份）。人类打破魔法的神秘化叙事，发现其可解析性，逐步建立起系统化的“术式学”。时代核心矛盾：贵族化的传统魔法与学院派的新兴魔法形成尖锐对立。第一次魔法革命：人类将魔法编码为可学习、可复制的符文体系，打破了长生种与贵族对魔法的垄断。</li><li>终难历1760年左右: 魔导工业革命开启。魔导蒸汽机被发明（对应现实第一次工业革命）。魔晶提炼技术取得突破性进展，魔法实现规模化能源化应用，魔导工业时代正式开启。核心技术突破：魔导蒸汽机诞生，通过魔晶湮灭产生的能量烧开水来产生蒸汽驱动机械 courteous，彻底改变了生产与战争的形态。魔导科技的发展存在熵增定律的天然天花板，且分为三大分支：解析虚境（阿国）、强化自身（国联）、融合神明（许国）。</li><li>终难历1914年: 耻辱战役爆发（对应现实第一次世界大战）。第一次世界大战：魔导工业化战争的残酷首秀，彻底改写了世界的政治格局。人类常规军队无法抗衡神明，在动用遗迹武器前处于溃败状态。</li><li>终难历1914年-1918年: 神祇的陨落与新生时期。</li><li>终难历1920年代: 当前所处时代。战后间歇期，魔导全面现代化和普世化经历百年发展，列强进入高速发展与矛盾激化的时期（对应现实柯立芝繁荣与一战后时期）。传统魔法贵族失势，工业新贵快速崛起。技术爆炸引发极剧烈动荡。</li></ul><h2 id="十四、文化与生态-1" tabindex="-1">十四、文化与生态: <a class="header-anchor" href="#十四、文化与生态-1" aria-label="Permalink to &quot;十四、文化与生态:&quot;">​</a></h2><h3 id="社会核心矛盾激化-1" tabindex="-1">社会核心矛盾激化 <a class="header-anchor" href="#社会核心矛盾激化-1" aria-label="Permalink to &quot;社会核心矛盾激化&quot;">​</a></h3><ul><li>阶级矛盾：旧贵族掌握着大量的农业用地与传统政治势力。虽然在经过类似1848年革命后逐渐式微，但他们仍然保有大量的原始积累，以此与掌握着工厂和魔晶资源、要求获得对应政治权力的工业新贵族形成死锁。双方在资源分配与政治话语权上僵持不下。</li><li>生存与就业矛盾：底层民众为争取居住在宜居区的权利，被迫承受极大的压力；同时大量低阶自律人形投入生产，对底层民众的就业构成了剧烈竞争。</li><li>种族矛盾：长生种与短生种之间的冲突。在历史进程中达成互相妥协，并在逐渐的冲突中完成国族认同建立和文化交融。</li></ul><h3 id="信仰防范-1" tabindex="-1">信仰防范 <a class="header-anchor" href="#信仰防范-1" aria-label="Permalink to &quot;信仰防范&quot;">​</a></h3><p>官方层面上，除了物理派国家，所有国家都是拒绝钢源神信仰的。</p><h2 id="十五、经济-1" tabindex="-1">十五、经济: <a class="header-anchor" href="#十五、经济-1" aria-label="Permalink to &quot;十五、经济:&quot;">​</a></h2><h3 id="劳工消耗与掠夺-1" tabindex="-1">劳工消耗与掠夺 <a class="header-anchor" href="#劳工消耗与掠夺-1" aria-label="Permalink to &quot;劳工消耗与掠夺&quot;">​</a></h3><ul><li>劳工开采比例：由于现代大部分国家已经建立起基于大型稳定态乱序区的工业化虚晶量产体系，纯粹依靠底层劳工用肉体去荒野散采虚晶已不再是全社会能源的主流来源。去荒野开采的劳工属于为了高溢价走私而冒险的极少数边缘群体。 地下农场与低阶流水线同样提供基础岗位。 劳工开采毛货虚晶的动机，是资本家开出的高薪酬和进入宜居区的许诺。 部分国家会从其他国家和大陆进行人口掠夺，以补充基础劳动力消耗。 劳工消耗的转变是缓慢的，更类似病症而不是极速报废。</li></ul><h3 id="消费市场结构-1" tabindex="-1">消费市场结构 <a class="header-anchor" href="#消费市场结构-1" aria-label="Permalink to &quot;消费市场结构&quot;">​</a></h3><p>资本家生产的工业品流向底层市场。 边缘区和底层的消费结构主要由廉价工业品和各种一二三产业服务产品构成。 底层劳工赚取的工资用于购买这些产品以维持生存和缓解污染痛苦，形成经济闭环。</p><h3 id="货币与定价-1" tabindex="-1">货币与定价 <a class="header-anchor" href="#货币与定价-1" aria-label="Permalink to &quot;货币与定价&quot;">​</a></h3><p>相对纯度可以通过土法进行测量。 贸联会掌握着标准晶币（SC）定价体系。</p><ul><li>纯度标准测量壁垒（国际度量衡委员会机制）：贸联会本身并没有掌握超越列强核心实验室的某种绝对黑科技来垄断纯度测量。相反，贸联会的金融定价权是建立在“整合列强共识”的基础上。它整合了列强各自顶尖的魔晶学技术与复杂的区域纯度测量方案，在此基础上，经过各列强政治与经济的漫长博弈与妥协，统一定义出了一套被各国官方背书并共识承认的“绝对纯度标准标尺”。贸联会（类似现实的WTO或国际度量衡委员会）作为该标准的唯一仲裁机构和执行者，负责全球晶币的发行与大宗魔晶交易的定级。列强核心实验室的仪器虽然能测出微小波段的异常或伪魔晶的隐藏污染，但在国际大宗交易结算时，必须无条件遵循贸联会这套公认的标尺。如果某个列强凭借自己的高精尖仪器单方面掀桌子、拒绝承认贸联会定级的纯度，等同于向全球宣布撕毁信用共识体系，会导致全球魔导贸易网络瞬间崩溃。列强基于对全球经济与信用体系稳定的绝对依赖，不能随意通过武力和技术霸权摧毁贸联会的定级实体，这是其能够作为中立金融谈判场的底层威慑。标准晶币（SC）跨国发行的权力来源于这种列强共识授权。 官方共识，在对外贸易结算时统一使用晶币，不同国家内部拥有内部各种币制。</li></ul><h3 id="虚晶与魔晶转化及剪刀差剥削-1" tabindex="-1">虚晶与魔晶转化及剪刀差剥削 <a class="header-anchor" href="#虚晶与魔晶转化及剪刀差剥削-1" aria-label="Permalink to &quot;虚晶与魔晶转化及剪刀差剥削&quot;">​</a></h3><p>市面上大量流通的依然是魔晶，但经贸会掌握了虚晶与魔晶的转化机制，并利用此机制形成剪刀差剥削。 伪魔晶技术是近十年才产生的新锐技术。</p><ul><li>包工头走私与荒野穿越：底层劳工在奇观边缘冒死开采的“畸变毛货”，只能低价卖给边缘区合法的“包工头（资本家白白手套）”。包工头截留了绝大部分毛货，走私到贸联会的黑市网络换取高纯度自然粮与暴利。荒野上的路网实际上是对所有人开放的，并没有绝对的物理封锁墙。包工头以及废土上的探险者、雇佣兵等各色人等，通过重装防污染载具、熵序者带队或者纯粹用人命填补等各种方式，在重度污染的荒野中穿行，维持着这条地下走私生命线的运转。</li><li>贸联会农业与双轨制：贸联会的农业并不依赖消耗虚晶的地下农场。他们利用强大的航海武装力量与早期殖民优势，独占了文兰大陆某些未被污染的“海外净土”。在这些拥有独立武装把守的广袤自留地中，贸联会进行着传统而庞大的自然农业生产。宜居区本身也有正常的自然耕地。国家粮农组织负责宜居区正常自然粮的供应，而贸联会则利用海外净土产出的极高品质自然粮作为黑市网络中的硬通货进行走私。催熟粮食仅仅是用来填饱底层人口的肚子。</li><li>转化能源的特殊属性：转化的能源为二次提纯，不是真魔晶。这种伪魔晶在物理性质上极度稳定，介于虚晶和魔晶之间，具有特殊的抗干扰与抗波动属性。列强虽然自己也在开采高纯度魔晶（原晶），但面对那些对能量波动极其敏感的高精尖仪器或特殊武器时，伪魔晶成为了一种相对廉价且稳定的平替选择。列强知道伪魔晶存在异常，但由于原晶的极度匮乏和高精尖实验的迫切需求，他们选择了将其作为平替方案，并且这种能源也能作为列强进行虚境研究的方法。</li><li>学科分割与对照组观测机制：在科学界，研究伪魔晶及虚境相关现象的属于专门的“虚境科学”或“魔晶学”。正统用于测量虚境科学的高精尖观测仪器一般都使用高纯度魔晶作为驱动。只有在核心实验室进行专门的虚境科学研究或魔晶学研究时，才会使用伪魔晶。其他核心实验室在常规实验中依然使用原晶，只有在原晶极度匮乏的紧急情况下，才会使用伪魔晶作为替代。阿国等列强的核心科学家在特定实验中，会利用伪魔晶自带的三阶污染作为“对照组”。通过高精尖学科的技术检测，将仪器在纯净天然魔晶和伪魔晶驱动下产生的“污染偏差值”进行严格对照，科学家们能够反向推导出真实世界被篡改的物理断层数据。这种将污染转化为观测标尺的技术，是阿国维持技术壁垒的核心手段之一。 转化率相对较低，且转化过程会产生无法被隔离桩阻挡的“三阶污染”。</li><li>转化代价：转化采用遗迹技术，需要消耗大量的虚晶作为基础材料。转化过程并非完美的逆熵再生，而是对虚晶残存信息的深度压榨。同时，转化过程必须投入秘密捕获的灾厄boss作为催化剂，并投入稀有矿物。经贸会必须在“稳定态乱序区”内秘密生产，这也是为了就近捕获这些灾厄boss。 三阶污染具有污染穿透性，信息和意识同化于虚境中。</li><li>物理防御机制与渊息石特攻：列强在核心实验室中使用名为“渊息石”的特定矿物来暂时隔绝三阶污染的穿透。渊息石并非自然产物，而是死寂走廊深处、极少数高阶乱序区坍缩后留下的物理残渣，极度稀缺且无法人工合成。渊息石对三阶污染具有“特攻”属性，其抵御原理是“同态相斥”——它本身散发着一种极高频的能导致人类基因瞬间崩溃的辐射，这种辐射能完美弹开三阶污染的穿透。核心实验室必须建立极其庞大的物理铅层和魔导护盾来隔离渊息石自身的辐射，然后才能利用它去隔离三阶污染。这种“用毒药解毒”的成本极其高昂，且装置体积庞大，根本无法小型化或普及到民用隔离桩和移动采掘城上。渊息石会在抵御污染的过程中逐渐消耗，需要定期进行更换。</li><li>伪魔晶的物理废料闭环：在伪魔晶的生产阶段，产生的溢出污染被单向意识体虚像滤网打碎伪装成了一阶废热排走；而当伪魔晶被列强燃烧榨干能量后，其使用端会留下一块极度危险的“高辐射固态毒核”。这块毒核是纯粹的三阶污染聚合体，类似于核反应废料。经贸会在生产时已将其信息特征码进行了物理格式化，导致毒核溯源呈乱码状态。</li><li>脏弹应用与物理保险机制：列强深知这种毒核如果随意排入下水道会直接穿透隔离桩引发虚境反噬。由于伪魔晶技术是近十年才兴起的，废料积累时间相对较短，因此目前列强处理毒核的方式是在实验结束后用特制的“渊息石密封罐”强行封装，由重装部队押运至荒野深处进行物理深埋，或高价再请经贸会秘密回收。同时，军方利用空间折叠错位技术，将三阶毒核制成了“微型脏弹”。脏弹内部装有维持错位的微型魔导信标，而其最外层的弹壳内壁涂抹了一层极薄的“劣质渊息石粉末”作为第一道物理防线。在平时储存和运输时，信标处于关闭状态，粉末硬抗三阶辐射，保证零泄露。只有在发射升空或投掷的瞬间，信标才会启动撑开空间错位，同时产生高温瞬间烧毁外层的渊息石粉末。当脏弹落地引爆炸毁信标时，空间错位消失，三阶毒核直接跌落回现实维度，爆发出恐怖的穿透杀伤。这套保险机制确保了高危武器不会在自家军火库引发自爆。</li><li>单向意识体虚像滤网与底噪掩盖机制：经贸会在生产工厂外围建立了一道“单向信息滤网”。这道滤网利用遗迹技术在底层建立了一个“无限递归的虚拟梦境”作为核心抗压底座，维持梦境运转的耗材是在稳定态乱序区内大量捕获的“高阶乱序区信息意识体”。除此之外，滤网物理层面上的关键构成是一种特殊活体生物“渊息虫”。这种虫子本身并无神奇魔力，它们能抵御三阶污染是因为它们以乱序区内微量的渊息石粉末为食，体内富集了渊息石的同态相斥辐射，用自己的肉体作为微型铅层来中和污染。生产中产生的三阶污染被引入虚拟梦境稀释，再通过渊息虫过滤膜穿透打碎，随后伪装成高浓度的一阶污染废热排放给吸污塔。为了防止康斯坦丁之瞳发现异常巨大的废热排放量，贸联会将这些秘密转化工厂建立在“物理底噪极大”的区域（如死寂走廊边缘的超大型乱序风暴眼下方，或极其活跃的巨型奇观群落内部）。利用大自然本身狂暴且巨大的污染喷发量，完美掩盖了工厂的人造工业排放数据。一旦渊息虫出了乱序区，失去渊息石粉末的摄入，体内的辐射平衡被打破，就会瞬间自燃或基因崩溃。</li><li>伴生饲料提取与虫群量产成本平账：如果全靠死寂走廊出产的纯粹渊息石喂养，经贸会的工厂早破产了。经贸会在超大型稳定态乱序区内，提取出了一种名为“蚀核伴生矿（特定的乱序信息物理凝结物）”。这种物质吸附了特定频率的乱序废料。经贸会将极少量的纯渊息石粉末与海量的蚀核伴生矿进行物理混合搅拌，制成了一种廉价的“平替辐射饲料”。这种饲料虽然无法抵御核心实验室级别的高压辐射，但足以维持渊息虫在转化工厂内部短暂生命周期内的辐射平衡。这套物理稀释混合工艺，大幅降低了昂贵的原矿消耗，支撑起了生物滤网低成本的工业化量产。这就解释了经贸会过滤机制的可行性，同时死死保住了渊息石作为各列强实验室抵御三阶污染的唯一解战略地位。</li><li>虚境接触与沉降反应：命定之人察觉了经贸会的伪装行为。被排入深海或掩埋的三阶污染废料（固态毒核），由于其特殊的穿透性，会直接沉降到虚境的最底部。沉降到底部瞬间锚定物粉碎，废料开始缓慢溶解现实底层装甲。这些沉降的三阶毒核本质上也是用于制作“熵之种”的极端基材之一。地底（虚境极深处）目前已经遍布被命定之人沉降的高纯度深层原晶矿脉，这里属于她的绝对领域。命定之人并没有去主动纠正或干预毒核的下沉轨迹，而是放任这些基材沉降，任由其作为“概念级的蛀虫”去软化现实外壳，将其视为最终剧本内爆坍缩所需的辅助消耗品。</li><li>绝密排放与禁区划分项目：经贸会为了避免伪装后的三阶污染废料被荒野上的普通奇观吸附而引发暴露，在排放场址的选择上与列强高层达成了绝密的“联手项目”。这些执行秘密转化的超大型奇观和排污区，在列强军方的任务地图上被明确标定为“永久死亡禁区”。</li><li>物理清理与信息封锁：这类禁区受到列强军方和经贸会双重部队的严密监控。底层的杀戮小队或PMC雇佣兵在任务区划分系统内根本无法接取靠近这些区域的凭证。如果有人误入，不仅会遭到内部高阶异变怪物的袭击，外部驻守的专门处理部队也会迅速介入，对其进行物理清理。事后，官方会在地下网络和军方内部通报虚假的“遭遇大规模自然异象或灾害覆灭”的信息，以此彻底掩盖三阶污染排放点的实战反馈异常，防止秘密泄漏。</li><li>科研人员精神异变：长期接触伪魔晶的虚境科学研究人员，其精神状态会受到三阶污染的潜移默化影响（如集体潜意识趋同、对虚境产生病态向往）。列强高层确实发现了这种精神异常，但他们将其误认为是“接触高维真理的必然代价（类似天才的疯狂）”。甚至有国家故意筛选这种精神趋同的学者来推进实验。</li><li>解密剥离机制：暗中谋划的势力掌握了遗迹中的“解密/剥离”技术。他们秘密打捞、收集这些伪装成废热的废料，在绝对屏蔽的地下设施中剥离外壳，提取出内部纯粹的三阶污染用于越界计划。</li><li>技术保密：技术目前还没有被各列强发觉，属于绝密技术。 只能小规模量产，且被严格把控。</li><li>隐藏计划：有势力正利用转化过程中产生的三阶污染与二次提纯能源，试着制造出能够打通虚境的准备（方舟计划或更深层的越界企图）。</li><li>列强的实验性研发与试错成本：列强并非完全依赖贸联会，其自身也在尝试研发类似的“虚晶压榨提纯技术”。但贸联会的技术不仅依赖遗迹，更需要利用特定的“天然空间折叠区”作为高压锅。列强在本土强行模拟这种极端环境进行压缩时，面临着极高的试错成本，稍有不慎就会引发超大规模的虚境溃疡。因此，列强的相关研发目前仅作为高度机密的“实验性项目”存在，无法投入大规模量产，只能继续忍受贸联会的垄断。</li></ul><h2 id="十六、国家与地区-1" tabindex="-1">十六、国家与地区: <a class="header-anchor" href="#十六、国家与地区-1" aria-label="Permalink to &quot;十六、国家与地区:&quot;">​</a></h2><ul><li>核心概念：广泛定义每个国家在发展和破局中都有不可承受的“代价”。</li></ul><h3 id="阿斯特兰大陆主要国家势力-1" tabindex="-1">阿斯特兰大陆主要国家势力 <a class="header-anchor" href="#阿斯特兰大陆主要国家势力-1" aria-label="Permalink to &quot;阿斯特兰大陆主要国家势力&quot;">​</a></h3><h3 id="艾加利维耶-法国原型-大陆西部-1" tabindex="-1">艾加利维耶 (法国原型，大陆西部) <a class="header-anchor" href="#艾加利维耶-法国原型-大陆西部-1" aria-label="Permalink to &quot;艾加利维耶 (法国原型，大陆西部)&quot;">​</a></h3><ul><li>体制：物理派魔导自动人形主导，数字民主制加工社制。</li><li>特点：标榜平等自由，社会阶级分化，魔导轻工业发达。在一战后才正式宣告成立，由前西摩特帝国的领土分裂并重建而来。与许国结为同盟。</li><li>代价：盲目推行概念隔离桩，将污染向边缘排挤。国家高层尝试越界，并准备转移矛盾。越界计划由贸联会资助，后续等文案设定。</li><li>同盟的物理刚需：艾国的独立直接由许国在背后输送武力与资源予以支持。由于艾国是从前西摩特帝国的领土上分裂出来的，西国随时企图将其重新吞并。艾国政府顶着国内要求平等自由的巨大政治压力，被迫与极端独裁的许国结盟，其底层物理刚需在于：艾国在地理上必须作为西摩特帝国与许国之间的“战略缓冲带”。如果艾国撕毁同盟，不仅会失去许国的军工订单与资源输血，更会面临西国复辟大军与许国惩戒部队的两面夹击。这种纯粹的生死存亡压力，成为了维系这种“诡异同盟”的唯一粘合剂。</li></ul><h3 id="西摩特帝国-法兰西帝国原型-1" tabindex="-1">西摩特帝国 (法兰西帝国原型) <a class="header-anchor" href="#西摩特帝国-法兰西帝国原型-1" aria-label="Permalink to &quot;西摩特帝国 (法兰西帝国原型)&quot;">​</a></h3><ul><li>体制：帝国体制。</li><li>特点：拥有强大的军事传统与帝国荣耀，在大陆政治格局中扮演重要角色。</li><li>代价：[待具体展开]</li></ul><h3 id="阿勒曼尼亚诸城联合-德国原型-大陆中部-1" tabindex="-1">阿勒曼尼亚诸城联合 (德国原型，大陆中部) <a class="header-anchor" href="#阿勒曼尼亚诸城联合-德国原型-大陆中部-1" aria-label="Permalink to &quot;阿勒曼尼亚诸城联合 (德国原型，大陆中部)&quot;">​</a></h3><ul><li>体制：城邦共治体制。</li><li>特点：哲学与工业之国，拥有遗迹武器，一战末期弑杀神明，首都附近存在时间异常区。具有广阔的出海口，这使得其物流与深海采掘后勤不依赖于别国。作为一战后最强的国家，凭借其强大的军事威慑力，各国未能迫使其承担战败代价。阿国垄断了大量高精尖技术，并且拥有针对死寂走廊的独家探索技术，依靠这些技术壁垒掌握了大陆上相当一部分的农业与金融命脉。阿国依靠遗迹技术掌握着一套未被篡改的底层公式，作为锚定真实特殊手段，此项技术被列为绝密，外国毫不知情。军事上正在秘密研发特种装备，其特色武装为战术机。首都拥有锚定时间流速的特殊技术，以维持核心区域正常运转。阿国拥有独家物流技术“以太气动管网”，依托高空魔导转录网络（管道），可实现物资与信息的解压缩。平时物流依靠固定通道进行运作。</li><li>代价：武器充能与后坐力榨取闭环。阿国在建立首都时并未发现地下的庞大遗迹群。启动遗迹武器导致首都附近出现严重的“时间异常区”，存在历史投影、时间流速异常与时间回溯现象。阿国的首都“时间锚点阵列”和“遗迹武器充能井”在物理上是同一个超级建筑，熵序者带回的海量魔晶与高纯度“熵之种”并不是分开消耗，而是全部投喂给了时间锚点。锚点在镇压、抵抗首都外围“时间回溯与异常废热”的过程中，利用抵抗后坐力时产生的巨大能量差，形成了分馏与降级机制。最核心、最狂暴的高维绝对时间概念残渣（原浆），就近直接滴入其正下方的遗迹武器核心进行二段充能。而那些无法被弹仓完全吸收、处于“溢出状态”的高维原浆能量，则被阿国导入了超级城市的民用与工业电网，强行用来供应全城日常能源消耗，以此解决充能满载炸膛的死锁问题。而武器充能阵列排出的“二阶时间废热（纯粹的算力冗余）”，则被抽调去支撑以太气动管网的解压缩算力。阿国在利用一战造成的伤口，以毒攻毒地为下一炮积攒弹药，这也是阿国拒绝迁都的根本原因，一旦离开这个能榨取时间后坐力的阵列，武器根本无法完成充能，物流管网也会因为失去算力废热而瞬间瘫痪。</li><li>遗迹武器的火力降级与绝对威慑差异：阿国在耻辱战役中打穿世界外壳、形成死寂走廊直通虚境漏斗的射击，是遗迹武器一次性的“全功率自毁式射击”。该射击熔毁了武器最高维度的核心主炮管。阿国首都现存的时间锚点阵列与充能井，本质上是当年残存的“次级副炮”或“残破枪栓”。它当前的满载威力足以瞬间蒸发集团军或进行国家级斩首，但受限于物理结构损毁，绝对无法复刻当年打穿世界外壳的概念级破坏。因此，国联空天武器瞄准的“拔掉漏斗塞子引发虚境海水倒灌”，成为了当前世界唯一且最高级别的末日威慑，阿国现存武力无法逾越这一火力天花板。</li><li>遗迹武器授权机制：目前阿国的遗迹武器“礼物”正在充能。其武器启动程序分为两级：</li><li>常规授权：需共治会90%以上投票通过，经魔晶基座全程信息熵刻录公示，仅可授权最低威力。</li><li>极端授权：当议会存活成员不足5人，且国家处于绝对劣势战争状态时方可动用，此机制保证了国家在遭遇斩首打击时的玉石俱焚威慑。</li><li>零阶排污代价与幽灵专列：在完美的能量降级闭环背后，时间锚点在镇压时空畸变并提取原浆时，必然产生无法降级的零阶时空畸变废渣。阿国秘密利用遗迹技术，将这些废渣倾倒进死寂走廊的“外围时间洋流缓冲带”。由于以太管网强行传输这种高危废渣会导致毁灭性爆炸，阿国利用首都外围时间异常区的特性，制造了一列永远处于“时间静止状态”的【幽灵专列】。阿国将零阶废渣进行极致高压形成时间坍缩奇点装入专列。幽灵专列没有物理轨道，被遗迹底层公式强行行驶在“被劈开的一秒钟缝隙”里，跨越荒野将高危奇点安全运送至死寂走廊倾倒。带有绝对死亡概念的高危废渣在抵达国联看守的核心漏斗前，会被死寂走廊内部的历史叠加态强行“磨碎消化”掉。国联高层察觉到了这种排污，但慑于阿国的遗迹武器威慑，且这种排污并未直接引爆死寂走廊的漏斗，双方在荒野深处保持着一种高度戒备的微妙平衡。</li></ul><h3 id="许珀耳玻瑞亚-一战俄国原型-大陆东部-1" tabindex="-1">许珀耳玻瑞亚 (一战俄国原型，大陆东部) <a class="header-anchor" href="#许珀耳玻瑞亚-一战俄国原型-大陆东部-1" aria-label="Permalink to &quot;许珀耳玻瑞亚 (一战俄国原型，大陆东部)&quot;">​</a></h3><ul><li>体制：信仰“钢源神”。</li><li>特点：类似一战前俄国的定位，欧洲哨兵，且拥有隐秘地下网络，移动圣物存在。国内政治局势接近内战状态，社会处于类似一战俄国的复杂政治与民众思想格局之中。以重工业为长，与艾国结为同盟。许国的作战核心与真正的主力依然是其极度强悍的常规人类军队（人与机械化）。这支军队以重装甲、重火力以及非信徒的正常人类士兵组成，不畏生死地进行冲锋。</li><li>代价：极其残酷的人口掠夺与信徒消耗，整个国家如同燃烧生命的火炉。许国没有像其他列强那样建立完善的地下概念隔离桩网络，同时受制于钢源神的剥壳机制，人体蓄水池的机制是绝密的。需要注意的是，常规魔导工业的物理废热不可能排入信徒大脑，许国的常规工业依然向外界排污。因此，在虚境的判定雷达中许国的排污量并非为零，仍然受限于物理世界排污协定的客观规律。被强行锁死在信徒湿件内部的，仅限于“钢源神对高阶魔晶概念剥壳产生的精神污染”。战术炮灰机制：许国真正的作战核心是人类军队。而那些异化后制成的伪自律人形，在军事体系中仅仅被视作“移动污染源”与战术消耗品。当伪自律人形体内的污染达到物理极限即将崩溃时，它们会被成建制地投放到敌国阵地或边缘污染区。它们在敌阵中自爆或狂暴，释放的污染并非瞬间被虚境抽走，而是与物理介质（如毒气、腐蚀性酸液等物质化污染）强行结合，造成持续的物理与认知双重杀伤。</li></ul><h3 id="伊比利帕尼亚-西班牙-教宗国原型-大陆西南梅塞塔尼高原" tabindex="-1">伊比利帕尼亚 (西班牙/教宗国原型，大陆西南梅塞塔尼高原): <a class="header-anchor" href="#伊比利帕尼亚-西班牙-教宗国原型-大陆西南梅塞塔尼高原" aria-label="Permalink to &quot;伊比利帕尼亚 (西班牙/教宗国原型，大陆西南梅塞塔尼高原):&quot;">​</a></h3><ul><li>体制：天明教神权政体，教宗集权。</li><li>特点：天使族与人族共治，早期大航海掠夺财富，航空实力强，一战后转中立传教。</li><li>代价：[待具体展开]</li></ul><h3 id="多种族融合国家-罗马-拉丁帝国-奥斯曼-中东原型-大陆某处" tabindex="-1">多种族融合国家 (罗马/拉丁帝国/奥斯曼/中东原型，大陆某处): <a class="header-anchor" href="#多种族融合国家-罗马-拉丁帝国-奥斯曼-中东原型-大陆某处" aria-label="Permalink to &quot;多种族融合国家 (罗马/拉丁帝国/奥斯曼/中东原型，大陆某处):&quot;">​</a></h3><ul><li>体制：多种族共治。</li><li>特点：由长生种与短生种等多个种族共同组成的单独国家，长生种在此保持独立人种地位并在相关学科占据垄断。缝合了罗马和拉丁帝国的定位。</li><li>代价：[待具体展开]</li></ul><h3 id="东方帝国-中国原型-大陆远东" tabindex="-1">东方帝国 (中国原型，大陆远东) <a class="header-anchor" href="#东方帝国-中国原型-大陆远东" aria-label="Permalink to &quot;东方帝国 (中国原型，大陆远东)&quot;">​</a></h3><ul><li>特点：处于剧烈历史变革与阵痛期的古老帝国。</li><li>代价：[待具体展开]</li></ul><h3 id="双头鹰帝国-奥匈帝国原型-大陆中南部" tabindex="-1">双头鹰帝国 (奥匈帝国原型，大陆中南部) <a class="header-anchor" href="#双头鹰帝国-奥匈帝国原型-大陆中南部" aria-label="Permalink to &quot;双头鹰帝国 (奥匈帝国原型，大陆中南部)&quot;">​</a></h3><ul><li>特点：老旧的二元帝国体系。</li><li>代价：[待具体展开]</li></ul><h3 id="文兰大陆势力" tabindex="-1">文兰大陆势力 <a class="header-anchor" href="#文兰大陆势力" aria-label="Permalink to &quot;文兰大陆势力&quot;">​</a></h3><h3 id="合众国-美国原型" tabindex="-1">合众国 (美国原型) <a class="header-anchor" href="#合众国-美国原型" aria-label="Permalink to &quot;合众国 (美国原型)&quot;">​</a></h3><ul><li>特点：正处于柯立芝繁荣阶段，经济高速发展。</li><li>代价：上帝之杖计划。合众国为了绕过常规的污染投放路径并在未来的战争中建立绝对的轨道打击优势，秘密启动了“上帝之杖”计划。不同于纯粹的物理动能武器，合众国研发的上帝之杖弹头内部搭载了极其高爆的三阶污染毒核。这种武器在从高空坠落砸碎目标的物理外壳后，会在极深的地下引爆三阶污染，造成无法被神佑或常规护盾防御的概念级穿透杀伤，其代价是合众国必须承担巨大的实验反噬风险，以及一旦发射必将引发的全球虚境震荡。上帝之杖的弹头外层配有冷链再入舱设计，内置微型空间错位信标，维持毒核在折叠亚空间内。直到撞击前0.1秒才会将毒核弹回现实维度，确保不会在再入大气层的高温中被提前引爆。</li></ul><h3 id="阿扎尼亚大陆势力" tabindex="-1">阿扎尼亚大陆势力 <a class="header-anchor" href="#阿扎尼亚大陆势力" aria-label="Permalink to &quot;阿扎尼亚大陆势力&quot;">​</a></h3><h3 id="大联盟-融合国家" tabindex="-1">大联盟 (融合国家) <a class="header-anchor" href="#大联盟-融合国家" aria-label="Permalink to &quot;大联盟 (融合国家)&quot;">​</a></h3><ul><li>特点：融合了现实地球各地区国家特色的庞大联盟体系。其中包含了部分长生种群体。</li><li>代价：灭世威慑反噬。大联盟的长生种的祖地连接着信息虚境的某个致命薄弱点。一旦祖地被毁，虚境就会瞬间反噬现实世界。薄弱点本身具备某种“反制锁定”的特性。祖地被神佑免疫污染。</li></ul><h3 id="塔万汀大群岛势力" tabindex="-1">塔万汀大群岛势力 <a class="header-anchor" href="#塔万汀大群岛势力" aria-label="Permalink to &quot;塔万汀大群岛势力&quot;">​</a></h3><h3 id="康科迪亚社区-安第斯主峰" tabindex="-1">康科迪亚社区 (安第斯主峰) <a class="header-anchor" href="#康科迪亚社区-安第斯主峰" aria-label="Permalink to &quot;康科迪亚社区 (安第斯主峰)&quot;">​</a></h3><ul><li>特点：抵制污染的无政府共识体，看守核心异常。</li><li>代价：[待具体展开]</li></ul><h3 id="东洲列岛势力" tabindex="-1">东洲列岛势力 <a class="header-anchor" href="#东洲列岛势力" aria-label="Permalink to &quot;东洲列岛势力&quot;">​</a></h3><h3 id="分裂的东海岛国-融合日本-朝韩原型" tabindex="-1">分裂的东海岛国 (融合日本/朝韩原型) <a class="header-anchor" href="#分裂的东海岛国-融合日本-朝韩原型" aria-label="Permalink to &quot;分裂的东海岛国 (融合日本/朝韩原型)&quot;">​</a></h3><ul><li>特点：水域封闭排外，内部存在严重割据。</li><li>代价：[待具体展开]</li></ul><h2 id="十七、组织" tabindex="-1">十七、组织 <a class="header-anchor" href="#十七、组织" aria-label="Permalink to &quot;十七、组织&quot;">​</a></h2><h3 id="国际联合-国联" tabindex="-1">国际联合(国联) <a class="header-anchor" href="#国际联合-国联" aria-label="Permalink to &quot;国际联合(国联)&quot;">​</a></h3><p>战后成立了名为“国际联合”的国际协调组织，试图维持脆弱的和平。它是类似列强的谈判场和中立机构。 国联掌握着“康斯坦丁之瞳”，这是战略级雷达。能够检测并精准溯源某次溃疡中污染的“信息特征码”，从而锁定排污国。 国联的空天武器本质上是遗迹武器。空天武器本身也是火力平台，主炮是一次性的，但是其他的武器点不是。命定之人只在国联成立之初，利用了与玩家之间约定的那朵唯一“空白之花”作为“启动密钥”或“概念核心”。这朵花并没有持续供能，武器能够维持极其庞大的基础物理悬浮和系统不坠落，是利用了遗迹技术直接抽取高空乱序点云集的废热来提供基础动力。这使得国联的空天武器其实一直处于“待机/未完全激活”的威慑状态，列强不敢试探其真假。命定之人是在用极小的成本维持一个“悬在头顶的达摩克利斯之剑”，以此防止列强过早自我毁灭。</p><ul><li>武器激活与能量来源：一旦国联空天武器真正激活并发射主炮，其瞬间需要的庞大能量缺口将通过直接抽干某条魔晶矿脉来填补。空天武器发射后，会首先摧毁发射点周围1000公里范围内的所有高维结构。空天武器在充能状态下会产生强烈的虚境信号被敌国战略雷达检测，极易遭到先发制人的打击。并且充能过程持续24小时，极为脆弱，一旦受攻击将启动自毁机制摧毁基地。所以国联只能保持待机，绝不轻易提前充能。</li><li>备用弹药库与未知威慑：国联在成立之初，强行接管了耻辱战役中某几个“被彻底打废的参战国首都的地下主矿脉”。这些矿脉虽然被严重污染，储量庞大且已被探明。这些废弃首都在耻辱战役中曾被阿国遗迹武器直接轰击过，其地壳已经被彻底打穿，形成了一个直通虚境的“物理漏斗”。脏矿就像塞子一样堵在这个漏斗上。国联的空天武器与这些脏矿形成了锁定。目前，列强并不清楚国联真正开火时究竟会发生什么。真正的威慑并不是什么“漏斗塞子拔掉引发海水倒灌”，而是国联空天武器与全球深层魔晶矿脉以及虚境存在着深层绑定的未知引动。一旦开炮，这种引动究竟会引发板块沉没、全球虚境震荡，还是造成现实概念彻底内爆，目前所有所有人都不知不知道其真实的毁灭效果是什么样子的。正是这种基于遗迹武器的“绝对未知且不可控”的连带毁灭后果，构成了列强不敢轻易逼迫国联掀桌子的终极威慑。阿国的遗迹武器因历史损毁无法复刻此等威力，因此国联的威慑处于绝对统治地位。由于这些漏斗本就处于死寂走廊内部，周边形成了危险的引力死区，国联在此进行看管。同时无国界之军也在帮助国联进行看管，作为国联的黑手套，相互利用。</li><li>发射原理与污染承受：空天武器的发射原理是直接让该区域联通虚境。在发射主炮的过程中，空白之花作为“高维钥匙”，在承受毁灭级污染的瞬间发生“概念级升华（燃烧）”，强行中和掉最致命的概念冲击，并在燃烧殆尽的最后一秒将剩余的纯物理废热一并传导进虚境中。这使得武器开火不会导致现实被物理废热瞬间炸碎，但也意味着主炮开火后空白之花的高维封印外壳彻底消失，核心碎片散落回玩家或乱序区中。</li></ul><h3 id="经贸会-贸联会" tabindex="-1">经贸会(贸联会) <a class="header-anchor" href="#经贸会-贸联会" aria-label="Permalink to &quot;经贸会(贸联会)&quot;">​</a></h3><p>存在名为“经贸会”（或贸联会）的跨国魔晶垄断组织。它是类似国联的中立机构和谈判场，掌握全球性金融组织与信托体系。 掌握虚晶与魔晶的转化机制，是维系双轨制经济的核心组织。</p><ul><li>绝密人工投喂计划与外围蛊场：经贸会除了进行正常的技术压榨，还掌握着一项只有内部相关部门知晓的绝密计划。为了保证超大型稳定态乱序区内的信息原料不会在转化工业的高强度抽血下干涸，经贸会利用这些乱序区作为“蛊盆”。他们在乱序区外围密布奇观和吸收节点（解释了外围奇观群的成因）。当产能吃紧时，有关部门会暗中在边缘平民区制造恐慌、灾难甚至小规模屠杀。这些事件产生的新鲜绝望和无序情绪作为“燃料”，被外围节点收集并定向排入乱序区进行“人工投喂”。这种人为维持的高压无序状态，确保了转化工厂的能源汲取能够永不枯竭。</li><li>技术博弈与唯一产出地壁垒：列强并不甘心被贸联会经济绑定，暗中一直在进行强行的逆向工程与渗透。贸联会之所以能保住“单向生物滤网”的垄断，并非因为其保密工作绝对完美，而是因为核心活体组件“渊息虫”的技术死锁。列强的特工确实曾抢到过渊息虫的活体样本，但发现它们一旦离开特定的高阶乱序区环境，就会因辐射失衡而极速死亡。贸联会真正的底牌是：他们利用早期的大航海探索优势，在全球范围内独占了渊息虫的“唯一天然高维产出地（某块无法被轻易定位的海外净土或深层遗迹）”。这种特定的虚境节点的信息频率被死死锁在了基因密码里。列强就算偷到了设备图纸，没有源源不断的新鲜渊息虫供应，也无法在本土运转那套转化系统，这才是列强被迫捏着鼻子接受贸联会勒索的物理刚需。</li></ul><h3 id="各国管理局-如第十三局" tabindex="-1">各国管理局（如第十三局） <a class="header-anchor" href="#各国管理局-如第十三局" aria-label="Permalink to &quot;各国管理局（如第十三局）&quot;">​</a></h3><p>各国设立了专门的管理局（例如第十三局）来管控熵序者与相关物资。 负责处理非法的熵序者，以及监控和打击相关的地下网络交易。</p><h3 id="地下网络" tabindex="-1">地下网络 <a class="header-anchor" href="#地下网络" aria-label="Permalink to &quot;地下网络&quot;">​</a></h3><p>存在庞大的地下网络，流通非法的熵序者和未经注册的产物。</p><h3 id="无国界之军" tabindex="-1">无国界之军 <a class="header-anchor" href="#无国界之军" aria-label="Permalink to &quot;无国界之军&quot;">​</a></h3><p>PMC组织，驻扎在最危险的缓冲污染区深处。作为国联的黑手套，帮助看管废弃首都的物理漏斗。</p><h3 id="复健所" tabindex="-1">复健所 <a class="header-anchor" href="#复健所" aria-label="Permalink to &quot;复健所&quot;">​</a></h3><p>存在个人复健和保护机制，同时拥有专门的复健所。</p><h3 id="十八、玩家相关" tabindex="-1">十八、玩家相关 <a class="header-anchor" href="#十八、玩家相关" aria-label="Permalink to &quot;十八、玩家相关&quot;">​</a></h3><h3 id="旅人与轮回剧本机制" tabindex="-1">旅人与轮回剧本机制 <a class="header-anchor" href="#旅人与轮回剧本机制" aria-label="Permalink to &quot;旅人与轮回剧本机制&quot;">​</a></h3><p>玩家的身份是旅人，时代的见证者，在歧路中探索世界的真相与未来。 玩家本身（最初的玩家）作为轮回的编剧，是掌握了对于乱序区历史的编改权，过度干涉会产生不可逆后果。 玩家和命定之人是这个星球共同的编剧（具体细节待后续补充）。 在完成剧本编撰后，玩家走上台作为演员，而命定之人则作为导演，一遍遍地进行轮回的演出。 命定之人与旅人处于平等地位。在这次轮回前，剧本大体上是正常运转的，缺少了哪一方都不成立。命定之人在虚境的能力属于概念神和管理级别。玩家降临时剧本已经基本完成，玩家是受到她的推动去推进最后的剧情。</p><h3 id="开场剧情与动机" tabindex="-1">开场剧情与动机 <a class="header-anchor" href="#开场剧情与动机" aria-label="Permalink to &quot;开场剧情与动机&quot;">​</a></h3><p>玩家一开始处于墓碑中，呈残血失忆状态。 玩家在从虚境降维到现实世界时，其高维记忆无法被现实的物理大脑承载，作为和命定之人的约定，玩家主动将记忆作为“空白之花”抵押给命定之人，以此换取物理肉体的降临。残血是因为跨越维度壁垒的物理损耗（具体文案组后续设置）。</p><ul><li>玩家初期驱动力：玩家一开始失去的“记忆（空白之花）”，其信息碎片会在某些高级乱序区中产生物理层面的“回响”。为了找回真正的自我与遗失的高维记忆，玩家拥有了无法拒绝的动机，必须主动且不断地深入这些高危区域进行探索。实际上空白之花只是作为高维记忆的封印容器存在。</li><li>记忆回响的缓冲机制：玩家在乱序区找到的不是直接的高维记忆本身，而是这段记忆在当前世界线上投射出的“低维隐喻或情感残渣”。玩家的大脑在吸收这些残渣时，是用当前世界的逻辑去重新理解过去的意图。这种缓慢的被过滤的过程没有触发底层的瞬间排斥。命定之人容忍这种行为，是因为她需要玩家保留最核心的可能性直觉去破局，她觉得“到时候了”，因此并没有急迫地干预和催促。</li><li>记忆接触层级：玩家在大部分时间的探索中，接触到的其实是“他人的记忆”或历史的碎片。只有在深入到“核心级别的乱序区”时，才会真正接触到属于自己过去的、被封存的高维记忆回响。 玩家自己下场时遭遇了温柔的背叛，以及作为去实现可能性的必要代价，不然发掘不到新可能性。 爬出墓碑后，因需要求医向城市走去，与小混混对战后力竭昏迷。 被外出办事（护送寻秘使）的自律人形捡到。 进入demo主城后，与救他的自律人形（熵序者）一起去办身份证明，同时了解世界基础知识。 期间自律人形接到附近下城区出现小型预兆点的消息。自律人形因放心不下主角，且小型乱序区属常见现象，便让主角在边缘等待。 主角因见到乱序区中的异象，加上附近清道夫质问其无身份证明并逼迫接受调查，于是自己也进入了乱序区。</li><li>特异点展现：和13局熵序者（自律人形）一起去处理事件后，玩家和熵序者一起去处理乱序区。熵序者以为会产出种子，却由于玩家干预产出了花，引起了注意。</li><li>核心动机：在微小日常和剧情发展中逐渐明白了前人的理念与抛立，出于自身的本心和悲悯选择了对抗之路（具体展开待定）。</li></ul><h3 id="十九、人物相关" tabindex="-1">十九、人物相关 <a class="header-anchor" href="#十九、人物相关" aria-label="Permalink to &quot;十九、人物相关&quot;">​</a></h3><h3 id="命定之人" tabindex="-1">命定之人 <a class="header-anchor" href="#命定之人" aria-label="Permalink to &quot;命定之人&quot;">​</a></h3><p>命定之人是玩家的引导者，也是这出轮回剧本的“导演”。 命定之人只想要“真实历史之花”来维持世界逐渐走向永恒这个剧本的现状，而不是维持这个世界的现状。 命定之人与旅人处于平等地位，共同维持着轮回剧本的运转。</p><ul><li>干预与引导机制：命定之人掌控着特定的人偶和操作的人，以此来承担“谜语人”的角色。在玩家进行探索时，命定之人会通过这些人偶进行误导、阻拦或发出模棱简可的警告，试图迫使玩家按既定路线产出真实历史之花。她目前对玩家并没有急迫的引导，只是觉得“到时候了”。高维存在对低维干预存在严格的梯度反噬（如全局级导致世界坍缩、规则级直接湮灭）。因此命定之人无法越界，只能在权限范围内微调。</li><li>干预限制与容忍底线：命定之人无法直接在物理层面上抹杀或囚禁玩家。一方面，玩家身上带有某种“编剧权限的绝对防御”，如果命定之人对其进行直接的物理囚禁或强行干涉，会导致世界底层逻辑判定“剧本主演罢演”，从而直接引发世界崩塌。另一方面，命定之人在内心深处其实也渴望玩家能找到破局的方法（温柔的背叛的另一面），她的阻拦更多是一种“试炼”而非纯粹的“抹杀”。</li><li>极端干预后果：命定之人如果过度干预，会导致虚境直接崩溃。</li><li>对群岛破碎的容忍与物理限制：命定之人之所以没有降下神罚去阻止塔万汀大群岛的完全破碎或强行将其缝补，是因为前任旅人拔出的那朵可能性之花，其代价强行“置换”了那片大陆的底层坐标。在世界底层的判定中，群岛的碎裂属于“板块运动加速的自然规律”，而不是“剧本被外部力量撕裂”。如果命定之人强行倒转这种被合理化后的自然规律去拼接大陆，反而会引发比群岛破碎大千万倍的虚境全面反噬。因此，她只能吞下这个剧本崩塌的苦果，并将这种代价的清算转移到了对现任旅人极其严苛的物理防范上。</li></ul><h3 id="二十、游戏流程相关" tabindex="-1">二十、游戏流程相关 <a class="header-anchor" href="#二十、游戏流程相关" aria-label="Permalink to &quot;二十、游戏流程相关&quot;">​</a></h3><h3 id="叙事功能" tabindex="-1">叙事功能 <a class="header-anchor" href="#叙事功能" aria-label="Permalink to &quot;叙事功能&quot;">​</a></h3><p>乱序区是核心的支线探索区域（副本）。玩家可在此类区域亲历历史片段，补全势力设定、挖掘深层剧情、揭开世界的真相。</p><h3 id="二十一、企业" tabindex="-1">二十一、企业 <a class="header-anchor" href="#二十一、企业" aria-label="Permalink to &quot;二十一、企业&quot;">​</a></h3><h3 id="经贸会下属虚晶工业集团" tabindex="-1">经贸会下属虚晶工业集团 <a class="header-anchor" href="#经贸会下属虚晶工业集团" aria-label="Permalink to &quot;经贸会下属虚晶工业集团&quot;">​</a></h3><p>专门负责虚晶的规模化开采与转化工业。 表面上收购底层劳工的散碎虚晶，暗中管辖并控制着部分超大型的“稳定态乱序区”。 在这些受管辖的乱序区内，建立完全自动化的“高压催化工厂”，以此作为支撑其庞大产能和秘密越界计划的核心来源。</p><ul><li>其他企业：[待设定]</li></ul><h3 id="二十二、附录" tabindex="-1">二十二、附录 <a class="header-anchor" href="#二十二、附录" aria-label="Permalink to &quot;二十二、附录&quot;">​</a></h3><h3 id="科技天梯图与层级划分" tabindex="-1">科技天梯图与层级划分 <a class="header-anchor" href="#科技天梯图与层级划分" aria-label="Permalink to &quot;科技天梯图与层级划分&quot;">​</a></h3><ul><li>T0（神权与遗迹底层）：神明概念直接干涉（需代理人）、真自律人形制造（艺术/奇迹）、阿国遗迹底层公式解析技术、解密/剥离纯粹三阶污染技术（部分势力密谋）、虚境洋流漂流瓶机制（理论未掌握）。</li><li>T1（列强绝密与战略底牌）：渊息石提取与污染屏障技术、高维物理伪装与观测技术（阿国）、国联康斯坦丁之瞳、以太气动管网解压缩技术、长生种深层生命工程与植物代偿逆转技术。</li><li>T2（大国垄断与核心重工）：魔晶物理深层剥壳技术、深海原晶移动采掘城与子舰排污系统、经贸会虚魔晶转化与单向生物滤网技术、伪自律人形湿件脑切除阵列（许国）、地下农场物理水冷晶化系统。</li><li>T3（普及工业与常规军工）：基础魔导蒸汽机阵列、普通隔离桩排污与符文阵列制造、低中阶自律人形流水线、地效飞行构与装甲列车、常规术式发生器与民用魔导通讯。</li></ul><h3 id="资源等级天梯图示" tabindex="-1">资源等级天梯图示 <a class="header-anchor" href="#资源等级天梯图示" aria-label="Permalink to &quot;资源等级天梯图示&quot;">​</a></h3><ul><li>阶梯顶端（不可估量战略级）：真实历史之花（世界稳态基石）、可能性之花（破局高维变量）、空白之花（高维物理介质/国联空天武器钥匙）。 第一阶层（国家命脉/绝对垄断）: 熵之种（坍缩产物，极高耗能充能）、深海原晶（极高压/三阶环境变异天然原晶）、先祖结晶（长生种底蕴）。 第二阶层（高级消耗品/特定实验）: 极品变异虚晶（奇观孕育，造真自律人形材料）、伪魔晶（经贸会二次提纯，抗波动平替）、原晶（浅层易开采天然高纯度，观测仪器驱动）。</li><li>第三阶层（工业血液）：工业晶（人工提炼）、标准虚晶（边缘区硬通货/日常耗材）。</li><li>底层（废料）：一阶无序污染废热、二阶精神毒素结晶、残渣（毫无利用价值的死寂信息）。</li></ul><h3 id="城市交互方式与区域分层" tabindex="-1">城市交互方式与区域分层 <a class="header-anchor" href="#城市交互方式与区域分层" aria-label="Permalink to &quot;城市交互方式与区域分层&quot;">​</a></h3><ul><li>宜居区核心（上层交互）：依靠晶币进行金融结算，利用大型基站接收以太管网纯净物资，高层权贵享用经贸会走私的“自然粮食”。通过强制教育维系“认知降熵压舱石”。</li><li>缓冲污染区（中层交互）：雇佣兵、探险者与杀戮小队在此通过物理接取委托。商品以昂贵的地下农场标准加工粮和常规防污染药物为主。</li><li>边缘区与矿坑（底层交互）：底层劳工使用碎晶进行以物易物的地下交易或换取廉价工业品。底层向包工头输送生命与虚晶，包工头许诺虚无缥缈的宜居区身份，以此维系阶级隔离。</li><li>各类循环图与机制闭环文字表述：A. 污染与奇观生态闭环图例:</li><li>城市排污：宜居区日常魔导消耗产生一阶污染（废热/无序信息） → 地下引流符文阵列吸附 → 概念隔离桩将高浓度污染打入深层虚境。</li><li>虚境溃疡：虚境吸收污染后容量增强 → 达到临界值发生溃疡 → 污染被世界底层规则排斥，一般情况下以一阶污染形式重新上浮至荒野地表。</li><li>奇观选址与吸附：无面者在荒野本能寻找地壳喷发点或天然节点建造钢铁奇观 → 奇观作为“污染吸尘器”吸附地表游离的一阶污染 → 奇观从“虚境洋流深处”反向打捞上一世界线的残片并结晶化，孕育极品变异虚晶或概念级灾厄。</li><li>奇观引力核介质与漩涡效应（打捞锚点）：奇观能够“跨越维度”打捞高维残片，并非无端垂钓，而是依赖其特殊的“高密度引力核”。当奇观吸附海量一阶废热时，其内部由地脉元素构建的防御工事结构会对废热进行极限物理压缩。这种压缩在奇观核心形成了一个“局部高密度信息引力核”。由于一阶废热本质上源自被粉碎的古老信息，其高压聚合态在质量上达到了干涉虚境流体力学的阈值。引力核就像一块沉重的礁石，在平稳的虚境洋流中强行制造出一个“微小的漩涡”。这个漩涡的向心力会将洋流深处漂流的高维残片直接“吸”入奇观的物理漏斗中。这就是为什么游离的废热无法打捞残片，只有经过奇观极致压缩后的引力核才能作为锚点介质。</li><li>三阶污染筛除：经贸会秘密排放的三阶污染随洋流扩散，奇观在吸附过程中极易吸入三阶污染导致孕育中的极品虚晶变质碎裂，仅极少数避开污染暗流的奇观能产出完好成品，彻底限制了真自律人形的量产。</li><li>荒野生态下水道（液化深层填埋机制）：针对奇观Boss被击杀后其庞大物理身躯的降解去向，世界底层存在强制的“深层填埋物理闭环”。当灾厄核心被拔除后，其失去高维概念支撑的巨大肉体不会在荒野地表自然腐烂，而是会在极短时间内发生“高压液化/沙化”。这股高密度的污染淤泥受地心引力和地脉牵引，顺着奇观打穿的地壳裂隙极速倒灌回地底极深处的“地壳惰性断层/沉降泥层”，被世界底层的庞大地热和物理高压缓慢碾碎、固化。确保了污染不违背物理守恒地消失。</li><li>闭环完成：国家派遣杀戮小队进入奇观击杀核心（或刚诞生的Boss）获取虚晶 → 奇观陷入宕机重启期 → 虚晶流入底层市场或用于制造真自律人形 → 再次消耗产生污染。</li></ul><h3 id="b-熵序者产物收集与污染累积流程图例" tabindex="-1">B. 熵序者产物收集与污染累积流程图例 <a class="header-anchor" href="#b-熵序者产物收集与污染累积流程图例" aria-label="Permalink to &quot;B. 熵序者产物收集与污染累积流程图例&quot;">​</a></h3><ul><li>准备阶段：熵序者注射抑制剂稳固认知 → 收集信息要素。</li><li>探索阶段：进入乱序区（主观与外部时间同步） → 推动真实历史发展 → 击败核心异常（Boss）。极端风暴点会遭遇时间流速异常。</li><li>产出与流失：乱序区坍缩 → 产出熵之种（高压封装的无序） → 历史信息流失被虚境（命定之人）抽走。</li><li>结算阶段：熵序者肉体累积污染（或经历极端风暴点时间修正导致骨龄老化） → 离开乱序区 → 接受现实缓慢排污与强制休假（官方疗养舱深度排污） → 准备下一次任务或产生耐药性退居二线。</li></ul><h3 id="c-经贸会转化与三阶污染流程图例" tabindex="-1">C. 经贸会转化与三阶污染流程图例 <a class="header-anchor" href="#c-经贸会转化与三阶污染流程图例" aria-label="Permalink to &quot;C. 经贸会转化与三阶污染流程图例&quot;">​</a></h3><ul><li>廉价收购：经贸会以廉价工业品和劣质粮食无限量收购底层劳工开采的虚晶。</li><li>秘密转化：在乱序区内利用遗迹技术对虚晶残存信息进行深度压榨 → 转化为极度稳定的二次提纯能源（伪魔晶）。</li><li>污染产生与掩盖：转化过程产生具有穿透性的三阶污染 → 利用单向意识体虚像滤网（结合无限递归虚拟梦境、乱序区信息意识体耗材与渊息虫过滤膜）隔离并利用乱序区“历史死循环”特性将三阶污染加密包裹伪装成一阶污染废热，选址于物理底噪极大区域掩盖真实排污量 → 瞒过虚境判定与列强。</li><li>能源流向：极度稳定的二次提纯能源作为相对廉价的平替被列强收购或用于秘密越界计划，形成暴利剪刀差。</li></ul><h3 id="d-钢源神信仰污染与内循环图例" tabindex="-1">D. 钢源神信仰污染与内循环图例 <a class="header-anchor" href="#d-钢源神信仰污染与内循环图例" aria-label="Permalink to &quot;D. 钢源神信仰污染与内循环图例&quot;">​</a></h3><ul><li>能量截留：钢源神操控机械装置对高阶魔晶进行概念剥壳 → 在内部粉碎有序历史信息 → 转化为符合教义的伪历史。</li><li>污染下发：粉碎魔晶产生的物理污染被教堂基站吸收 → 转化为精神频率污染 → 顺着信仰网络精准输送进信徒大脑。</li><li>阶梯承载：上层神职人员免污染 → 中层轻度污染保持狂热 → 底层信徒作为高压蓄水池承载重度污染，保持表面正常缓慢异化。</li><li>物理分摊（等质量置换与雷达欺骗）：钢源神在地下生成海量高维金属根系时，利用极高概念挤压力将原本处于该地层的等质量“普通岩石与泥土”，以造山运动形式缓慢排挤出地表或气化。信徒大脑承担的仅是浇筑溢出的高频精神辐射，而在国联雷达扫描中，许国板块“总物理质量”并未暴增，被误判为常规地质变动，实现物理伪装。</li><li>报废回收：底层信徒大脑污染经历数十年积累达到临界值发生异变 → 被回收制作为伪自律人形的核心湿件 → 许国必须不断对外扩张吸收边缘区流民，以“难民乌托邦”名义恩威并施，通过受洗传教洗脑新流民成为新的蓄水池。</li><li>中等催熟（灰色惩戒营）：战线吃紧时，将部分中期污染信徒送入高辐射基站区强行劳作洗脑，数月内极速催熟为湿件原料。</li><li>强制灌装：战损过大时启动紧急熔断机制，将高浓度污染结晶强注未洗脑难民脊髓，制造一次性狂暴电池维持战线。</li><li>无线排热与结晶物理自毁：伪自律人形在战场燃烧低端虚晶时，体内产生的废热通过无线魔导网络实时传回圣物盒，为后续断网觉醒预留变数；当信徒或伪自律人形彻底失去生命体征或脱离信仰网络且内部阻断阀落下自爆后，大脑内的污染结晶会启动缓慢的物理级自然自毁溶解，防止剥壳机密通过解剖泄露。</li></ul><h3 id="e-社会资产循环与剥削闭环" tabindex="-1">E. 社会资产循环与剥削闭环 <a class="header-anchor" href="#e-社会资产循环与剥削闭环" aria-label="Permalink to &quot;E. 社会资产循环与剥削闭环&quot;">​</a></h3><ul><li>底层生产端：难民/贫民消耗几十年寿命与认知（二阶污染），在矿坑开采虚晶或在地下农场轮换劳作。</li><li>资本收购端：包工头以维持生存下限的劣质品与少量晶币低价收购，并画下宜居区名额大饼。</li><li>跨国流通端：包工头向经贸会黑市走私换取海外纯净自然粮与暴利。经贸会将虚晶转化为伪魔晶再高价卖给列强军工实验室。</li><li>顶层消费端：列强利用产出的高能材料维系时间锚点或造神计划，权贵消费纯净物资。其产生的巨大信息缺口再次通过隔离桩排向底层荒野，形成完美压榨闭环。</li></ul><h3 id="基层生态图与荒野生态图文字表述" tabindex="-1">基层生态图与荒野生态图文字表述 <a class="header-anchor" href="#基层生态图与荒野生态图文字表述" aria-label="Permalink to &quot;基层生态图与荒野生态图文字表述&quot;">​</a></h3><p>基层生态图（边缘居住区/下城）: 密布生锈的廉价魔导管线，排污不畅。空气中弥漫着微弱的二阶精神污染导致居民情感逐渐麻木。清道夫在此处维持最低限度的治安与心理锚定复健。包工头的地下黑市、黑医的非法神经节移植诊所以及破败的廉价合成食品加工作坊构成了这里的黑色血脉。 荒野生态图（死寂废土/无人区）: 被隔离桩倒灌和虚境溃疡吐出的高浓一阶/二阶污染笼罩。低洼处形成重度信息风暴沼泽。巨大的无面者奇观如食腐植物般矗立在虚境喷发节点，周围游荡着因污染残渣具象化而成的异形生物和失去记忆的无面者群落。列强的重装装甲列车顺着安全航道呼啸而过，杀戮小队在奇观阴影处为了极品虚晶进行无声的物理白刃战。</p>',378)])])}const q=i(o,[["render",h]]);export{b as __pageData,q as default};
